    # ============================================
    # v4.5 (G-17): Go Language Compression Methods
    # ============================================

    def _compress_go_types(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress Go type definitions (structs, interfaces, type aliases, const blocks)."""
        lines = []

        # Structs
        if hasattr(matrix, 'go_structs') and matrix.go_structs:
            lines.append("# Structs")
            for struct in matrix.go_structs:
                if not struct.get('is_exported', False):
                    continue  # Skip unexported types for compactness
                prefix = self._service_prefix(struct, is_monorepo)
                fields = struct.get('fields', [])
                field_strs = []
                for f in fields[:8]:  # Limit to 8 fields
                    embedded = "↑" if f.get('embedded') else ""
                    tag = ""
                    if f.get('tag'):
                        # Extract json tag name if present
                        import re
                        json_match = re.search(r'json:"([^"]*)"', f['tag'])
                        if json_match:
                            tag = f"|json:{json_match.group(1).split(',')[0]}"
                    field_strs.append(f"{embedded}{f['name']}:{f['type']}{tag}")
                if len(fields) > 8:
                    field_strs.append(f"...+{len(fields) - 8}")
                embedded_types = struct.get('embedded_types', [])
                embed_str = f"|embeds:{','.join(embedded_types)}" if embedded_types else ""
                lines.append(f"  {prefix}{struct['name']}({','.join(field_strs)}){embed_str}")

        # Interfaces
        if hasattr(matrix, 'go_interfaces') and matrix.go_interfaces:
            lines.append("# Interfaces")
            # Sort by method count descending — most important interfaces first
            sorted_ifaces = sorted(
                [i for i in matrix.go_interfaces if i.get('is_exported', False)],
                key=lambda x: len(x.get('methods', [])),
                reverse=True
            )
            for iface in sorted_ifaces:
                prefix = self._service_prefix(iface, is_monorepo)
                methods = iface.get('methods', [])
                embedded = iface.get('embedded_interfaces', [])
                embed_str = f"|embeds:{','.join(embedded)}" if embedded else ""

                if len(methods) <= 20:
                    # Small interface: list all method names
                    method_names = [m.get('name', '') for m in methods]
                    lines.append(f"  {prefix}{iface['name']}|methods:{','.join(method_names)}{embed_str}")
                else:
                    # Large interface (like App with 190 methods):
                    # Group methods by prefix pattern for compact representation
                    method_names = [m.get('name', '') for m in methods]
                    grouped = {}
                    ungrouped = []
                    for mn in method_names:
                        # Group On* methods together (hooks), Find* (queries), etc.
                        prefix_match = None
                        for p in ['On', 'Find', 'Save', 'Delete', 'Create', 'Update', 'Set', 'Get', 'Has', 'Is', 'New', 'Can']:
                            if mn.startswith(p) and len(mn) > len(p):
                                prefix_match = p
                                break
                        if prefix_match:
                            if prefix_match not in grouped:
                                grouped[prefix_match] = []
                            grouped[prefix_match].append(mn)
                        else:
                            ungrouped.append(mn)

                    lines.append(f"  {prefix}{iface['name']}|{len(methods)} methods{embed_str}")
                    for grp, names in sorted(grouped.items(), key=lambda x: len(x[1]), reverse=True):
                        lines.append(f"    {grp}*({len(names)}):{','.join(names[:20])}")
                        if len(names) > 20:
                            lines.append(f"      +{','.join(names[20:])}")
                    if ungrouped:
                        lines.append(f"    other:{','.join(ungrouped)}")

        # Type Aliases
        if hasattr(matrix, 'go_type_aliases') and matrix.go_type_aliases:
            lines.append("# Type Aliases")
            for alias in matrix.go_type_aliases:
                if not alias.get('is_exported', False):
                    continue
                lines.append(f"  {alias['name']}={alias.get('underlying_type', '')}")

        # Const Blocks (Go enum equivalents)
        if hasattr(matrix, 'go_const_blocks') and matrix.go_const_blocks:
            lines.append("# Const/Enums")
            for block in matrix.go_const_blocks:
                type_name = block.get('type_name', 'const')
                values = block.get('values', [])
                value_names = [v.get('name', '') for v in values if v.get('name', '')[0:1].isupper()]
                if value_names:
                    iota_str = "|iota" if block.get('uses_iota') else ""
                    lines.append(f"  {type_name}={','.join(value_names)}{iota_str}")

        return lines

    def _compress_go_api(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress Go API endpoints (HTTP routes, gRPC services)."""
        lines = []

        # HTTP Routes (Gin, Echo, Chi, net/http)
        if hasattr(matrix, 'go_routes') and matrix.go_routes:
            # Group by framework
            by_framework = {}
            for route in matrix.go_routes:
                fw = route.get('framework', 'net/http')
                if fw not in by_framework:
                    by_framework[fw] = []
                by_framework[fw].append(route)

            for fw, routes in by_framework.items():
                lines.append(f"# {fw.title()} Routes")
                for route in routes:
                    prefix = self._service_prefix(route, is_monorepo)
                    method = route.get('method', 'ANY')
                    path = route.get('path', '/')
                    handler = route.get('handler', '')
                    lines.append(f"  {prefix}{method}:{path}|{handler}")

        # gRPC Services
        if hasattr(matrix, 'go_grpc_services') and matrix.go_grpc_services:
            lines.append("# gRPC Services")
            for svc in matrix.go_grpc_services:
                prefix = self._service_prefix(svc, is_monorepo)
                interface = svc.get('server_interface', '')
                lines.append(f"  {prefix}{svc['name']}|implements:{interface}")

        return lines

    def _compress_go_functions(self, matrix) -> List[str]:
        """
        Compress Go functions and methods with adaptive limits and importance scoring.

        v4.8: Replaced hard 10×5=50 cap with adaptive scaling.
        - Receivers sorted by method count (most methods = most important type)
        - Adaptive limits: show up to 40 receivers, 15 methods each
        - For types with many methods (>15), emit a compact summary line listing all method names
        - Top-level functions: up to 30 files, 10 per file
        """
        lines = []

        # Methods grouped by receiver type — SORTED by method count (most important first)
        if hasattr(matrix, 'go_methods') and matrix.go_methods:
            methods_by_receiver = {}
            for method in matrix.go_methods:
                if not method.get('is_exported', False):
                    continue
                receiver = method.get('receiver_type', 'unknown')
                if receiver not in methods_by_receiver:
                    methods_by_receiver[receiver] = []
                methods_by_receiver[receiver].append(method)

            # Sort receivers by method count descending — most important types first
            sorted_receivers = sorted(methods_by_receiver.items(), key=lambda x: len(x[1]), reverse=True)

            # Adaptive limit: scale with project size
            total_receivers = len(sorted_receivers)
            max_receivers = min(total_receivers, max(40, total_receivers // 2))

            receiver_count = 0
            for receiver, methods in sorted_receivers:
                if receiver_count >= max_receivers:
                    remaining = total_receivers - receiver_count
                    if remaining > 0:
                        lines.append(f"  # ... and {remaining} more types")
                    break

                method_count = len(methods)
                lines.append(f"  # {receiver} ({method_count} methods)")

                if method_count <= 15:
                    # Show all methods with signatures for small types
                    for m in methods:
                        ptr = "*" if m.get('is_pointer_receiver') else ""
                        params = m.get('params', [])
                        param_strs = [f"{p.get('name', '')}:{p.get('type', '')}" for p in params[:4]]
                        if len(params) > 4:
                            param_strs.append("...")
                        returns = m.get('return_types', [])
                        ret_str = f"->({'|'.join(returns)})" if returns else ""
                        lines.append(f"    ({ptr}{receiver}).{m['name']}({','.join(param_strs)}){ret_str}")
                else:
                    # For large types: show first 10 with signatures, then list remaining names
                    for m in methods[:10]:
                        ptr = "*" if m.get('is_pointer_receiver') else ""
                        params = m.get('params', [])
                        param_strs = [f"{p.get('name', '')}:{p.get('type', '')}" for p in params[:4]]
                        if len(params) > 4:
                            param_strs.append("...")
                        returns = m.get('return_types', [])
                        ret_str = f"->({'|'.join(returns)})" if returns else ""
                        lines.append(f"    ({ptr}{receiver}).{m['name']}({','.join(param_strs)}){ret_str}")
                    # Compact listing of remaining method names
                    remaining_names = [m['name'] for m in methods[10:]]
                    lines.append(f"    +{','.join(remaining_names)}")

                receiver_count += 1

        # Top-level functions (exported only) — with adaptive limits
        if hasattr(matrix, 'go_functions') and matrix.go_functions:
            exported_funcs = [f for f in matrix.go_functions
                              if f.get('is_exported') and not f.get('is_init') and not f.get('is_main')]
            if exported_funcs:
                # Group by file
                funcs_by_file = {}
                for func in exported_funcs:
                    filename = func.get('file', 'unknown').split('/')[-1]
                    if filename not in funcs_by_file:
                        funcs_by_file[filename] = []
                    funcs_by_file[filename].append(func)

                # Sort by function count descending — files with most functions first
                sorted_files = sorted(funcs_by_file.items(), key=lambda x: len(x[1]), reverse=True)

                total_files = len(sorted_files)
                max_files = min(total_files, max(30, total_files // 2))

                file_count = 0
                for filename, funcs in sorted_files:
                    if file_count >= max_files:
                        remaining = total_files - file_count
                        if remaining > 0:
                            lines.append(f"  # ... and {remaining} more files")
                        break

                    lines.append(f"  # {filename}")
                    for func in funcs[:10]:
                        params = func.get('params', [])
                        param_strs = [f"{p.get('name', '')}:{p.get('type', '')}" for p in params[:4]]
                        if len(params) > 4:
                            param_strs.append("...")
                        returns = func.get('return_types', [])
                        ret_str = f"->({'|'.join(returns)})" if returns else ""
                        lines.append(f"    {func['name']}({','.join(param_strs)}){ret_str}")
                    if len(funcs) > 10:
                        remaining_names = [f['name'] for f in funcs[10:]]
                        lines.append(f"    +{','.join(remaining_names)}")
                    file_count += 1

        return lines

    def _compress_go_dependencies(self, matrix) -> List[str]:
        """Compress Go dependencies from go.mod."""
        lines = []

        if not hasattr(matrix, 'go_dependencies') or not matrix.go_dependencies:
            return lines

        deps = matrix.go_dependencies

        # Module name
        module = deps.get('_module', '')
        if module:
            lines.append(f"  module: {module}")

        # Go version
        go_ver = deps.get('_go_version', '')
        if go_ver:
            lines.append(f"  go: {go_ver}")

        # Direct dependencies (skip meta keys starting with _)
        direct_deps = {k: v for k, v in deps.items() if not k.startswith('_')}
        if direct_deps:
            lines.append(f"  # {len(direct_deps)} direct dependencies")
            # Categorize well-known dependencies
            categories = {
                'web': [], 'db': [], 'auth': [], 'grpc': [],
                'cli': [], 'logging': [], 'testing': [], 'other': []
            }
            for dep, ver in sorted(direct_deps.items()):
                dep_lower = dep.lower()
                if any(k in dep_lower for k in ['gin', 'echo', 'chi', 'fiber', 'mux', 'http', 'router', 'cobra']):
                    categories['web'].append(f"{dep}@{ver}")
                elif any(k in dep_lower for k in ['gorm', 'sql', 'pg', 'mysql', 'sqlite', 'mongo', 'redis', 'badger', 'bbolt', 'database']):
                    categories['db'].append(f"{dep}@{ver}")
                elif any(k in dep_lower for k in ['jwt', 'oauth', 'auth', 'bcrypt', 'crypto']):
                    categories['auth'].append(f"{dep}@{ver}")
                elif any(k in dep_lower for k in ['grpc', 'protobuf', 'proto']):
                    categories['grpc'].append(f"{dep}@{ver}")
                elif any(k in dep_lower for k in ['cobra', 'cli', 'flag', 'viper', 'pflag']):
                    categories['cli'].append(f"{dep}@{ver}")
                elif any(k in dep_lower for k in ['log', 'zap', 'zerolog', 'logrus']):
                    categories['logging'].append(f"{dep}@{ver}")
                elif any(k in dep_lower for k in ['test', 'assert', 'mock', 'gomock']):
                    categories['testing'].append(f"{dep}@{ver}")
                else:
                    categories['other'].append(f"{dep}@{ver}")

            for cat, cat_deps in categories.items():
                if cat_deps:
                    lines.append(f"  [{cat}] {' | '.join(cat_deps[:8])}")
                    if len(cat_deps) > 8:
                        lines.append(f"    # ... and {len(cat_deps) - 8} more")

        return lines

        return lines

    # ============================================
    # v5.2: Go Framework Compression Methods
    # ============================================

    def _compress_go_gin(self, matrix) -> List[str]:
        """Compress Gin framework data (routes, middleware, groups, bindings, renders)."""
        lines = []
        routes = getattr(matrix, 'go_gin_routes', [])
        groups = getattr(matrix, 'go_gin_route_groups', [])
        middleware = getattr(matrix, 'go_gin_middleware', [])
        bindings = getattr(matrix, 'go_gin_bindings', [])
        renders = getattr(matrix, 'go_gin_renders', [])
        if not routes and not middleware:
            return lines
        frameworks = getattr(matrix, 'go_gin_detected_frameworks', [])
        if frameworks:
            lines.append(f"# Ecosystem: {', '.join(frameworks[:10])}")
        if routes:
            lines.append(f"## Routes ({len(routes)})")
            for r in routes[:40]:
                f = r.get('file', '').split('/')[-1]
                group = f"|group:{r['group']}" if r.get('group') else ""
                lines.append(f"  {r.get('method', 'ANY')} {r.get('path', '/')}{group}|{r.get('handler', '?')}|{f}")
            if len(routes) > 40:
                lines.append(f"  # ... and {len(routes) - 40} more routes")
        if groups:
            lines.append(f"## Route Groups ({len(groups)})")
            for g in groups[:20]:
                lines.append(f"  {g.get('prefix', '/')}|mw:{','.join(g.get('middleware', [])[:3])}")
        if middleware:
            lines.append(f"## Middleware ({len(middleware)})")
            for m in middleware[:20]:
                scope = f"|scope:{m['scope']}" if m.get('scope') else ""
                lines.append(f"  {m.get('name', '?')}{scope}")
        if bindings:
            lines.append(f"## Bindings ({len(bindings)})")
            for b in bindings[:15]:
                lines.append(f"  {b.get('binding_type', '?')}|{b.get('target_type', '?')}")
        if renders:
            lines.append(f"## Renders ({len(renders)})")
            for r in renders[:15]:
                lines.append(f"  {r.get('render_type', '?')}")
        return lines

