    def _compress_go_grpc(self, matrix) -> List[str]:
        """Compress gRPC-Go data (services, interceptors, options, clients)."""
        lines = []
        impls = getattr(matrix, 'go_grpc_service_impls', [])
        methods = getattr(matrix, 'go_grpc_rpc_methods', [])
        interceptors = getattr(matrix, 'go_grpc_interceptors', [])
        clients = getattr(matrix, 'go_grpc_client_connections', [])
        if not impls and not methods and not interceptors:
            return lines
        frameworks = getattr(matrix, 'go_grpc_detected_frameworks', [])
        if frameworks:
            lines.append(f"# Ecosystem: {', '.join(frameworks[:10])}")
        if impls:
            lines.append(f"## Service Implementations ({len(impls)})")
            for s in impls[:20]:
                f = s.get('file', '').split('/')[-1]
                meths = s.get('methods', [])
                meth_str = f"|methods:{','.join(meths[:5])}" if meths else ""
                lines.append(f"  {s.get('name', '?')}→{s.get('server_interface', '?')}{meth_str}|{f}")
        if methods:
            lines.append(f"## RPC Methods ({len(methods)})")
            for m in methods[:40]:
                f = m.get('file', '').split('/')[-1]
                stream = f"|{m['stream_type']}" if m.get('stream_type') != 'unary' else ""
                lines.append(f"  {m.get('service', '?')}.{m.get('name', '?')}{stream}|{f}")
            if len(methods) > 40:
                lines.append(f"  # ... and {len(methods) - 40} more methods")
        if interceptors:
            lines.append(f"## Interceptors ({len(interceptors)})")
            for i in interceptors[:15]:
                lines.append(f"  {i.get('name', '?')}|{i.get('interceptor_type', '')}")
        if clients:
            lines.append(f"## Client Connections ({len(clients)})")
            for c in clients[:10]:
                secure = "|TLS" if c.get('is_secure') else ""
                lines.append(f"  {c.get('variable_name', '?')}→{c.get('target', '?')}{secure}")
        return lines

    def _compress_go_gorm(self, matrix) -> List[str]:
        """Compress GORM data (models, hooks, scopes, migrations)."""
        lines = []
        models = getattr(matrix, 'go_gorm_models', [])
        hooks = getattr(matrix, 'go_gorm_hooks', [])
        scopes = getattr(matrix, 'go_gorm_scopes', [])
        migrations = getattr(matrix, 'go_gorm_migrations', [])
        if not models and not hooks and not migrations:
            return lines
        version = getattr(matrix, 'go_gorm_version', '')
        driver = getattr(matrix, 'go_gorm_driver', '')
        if version:
            lines.append(f"# GORM {version}")
        if driver:
            lines.append(f"# Driver: {driver}")
        frameworks = getattr(matrix, 'go_gorm_detected_frameworks', [])
        if frameworks:
            lines.append(f"# Ecosystem: {', '.join(frameworks[:10])}")
        if models:
            lines.append(f"## Models ({len(models)})")
            for m in models[:30]:
                f = m.get('file', '').split('/')[-1]
                table = f"|table:{m['table_name']}" if m.get('table_name') else ""
                soft = "|soft_delete" if m.get('has_soft_delete') else ""
                assocs = m.get('associations', [])
                assoc_str = f"|assoc:{','.join(a.get('type','') for a in assocs[:3])}" if assocs else ""
                lines.append(f"  {m.get('name', '?')}{table}{soft}{assoc_str}|{f}")
            if len(models) > 30:
                lines.append(f"  # ... and {len(models) - 30} more models")
        if hooks:
            lines.append(f"## Hooks ({len(hooks)})")
            for h in hooks[:20]:
                lines.append(f"  {h.get('model', '?')}.{h.get('hook_type', '?')}")
        if scopes:
            lines.append(f"## Scopes ({len(scopes)})")
            for s in scopes[:15]:
                lines.append(f"  {s.get('name', '?')}")
        if migrations:
            lines.append(f"## Migrations ({len(migrations)})")
            for mg in migrations[:10]:
                models_list = mg.get('models', [])
                lines.append(f"  {mg.get('migration_type', '?')}|models:{','.join(models_list[:5])}")
        return lines

    def _compress_go_sqlx(self, matrix) -> List[str]:
        """Compress sqlx data (queries, models, connections)."""
        lines = []
        queries = getattr(matrix, 'go_sqlx_queries', [])
        models = getattr(matrix, 'go_sqlx_models', [])
        connections = getattr(matrix, 'go_sqlx_connections', [])
        if not queries and not models:
            return lines
        driver = getattr(matrix, 'go_sqlx_driver', '')
        if driver:
            lines.append(f"# Driver: {driver}")
        frameworks = getattr(matrix, 'go_sqlx_detected_frameworks', [])
        if frameworks:
            lines.append(f"# Ecosystem: {', '.join(frameworks[:10])}")
        if models:
            lines.append(f"## Models ({len(models)})")
            for m in models[:20]:
                f = m.get('file', '').split('/')[-1]
                fields = m.get('fields', [])
                field_str = f"|fields:{len(fields)}" if fields else ""
                lines.append(f"  {m.get('name', '?')}{field_str}|{f}")
        if queries:
            lines.append(f"## Queries ({len(queries)})")
            for q in queries[:30]:
                f = q.get('file', '').split('/')[-1]
                named = "|named" if q.get('has_named_params') else ""
                sql = f"|{q['query'][:60]}" if q.get('query') else ""
                lines.append(f"  {q.get('method', '?')}{named}{sql}|{f}")
            if len(queries) > 30:
                lines.append(f"  # ... and {len(queries) - 30} more queries")
        if connections:
            lines.append(f"## Connections ({len(connections)})")
            for c in connections[:5]:
                lines.append(f"  {c.get('method', '?')}|driver:{c.get('driver', '?')}")
        return lines

    def _compress_go_cobra(self, matrix) -> List[str]:
        """Compress Cobra CLI data (commands, flags, sub-commands)."""
        lines = []
        commands = getattr(matrix, 'go_cobra_commands', [])
        flags = getattr(matrix, 'go_cobra_flags', [])
        sub_cmds = getattr(matrix, 'go_cobra_sub_commands', [])
        viper = getattr(matrix, 'go_cobra_viper_bindings', [])
        if not commands and not flags:
            return lines
        frameworks = getattr(matrix, 'go_cobra_detected_frameworks', [])
        if frameworks:
            lines.append(f"# Ecosystem: {', '.join(frameworks[:10])}")
        if commands:
            lines.append(f"## Commands ({len(commands)})")
            for cmd in commands[:30]:
                f = cmd.get('file', '').split('/')[-1]
                root = "|ROOT" if cmd.get('is_root') else ""
                run_type = "|RunE" if cmd.get('has_run_e') else ("|Run" if cmd.get('has_run') else "")
                short = f"|{cmd['short'][:40]}" if cmd.get('short') else ""
                lines.append(f"  {cmd.get('use', cmd.get('name', '?'))}{root}{run_type}{short}|{f}")
            if len(commands) > 30:
                lines.append(f"  # ... and {len(commands) - 30} more commands")
        if sub_cmds:
            lines.append(f"## Sub-commands ({len(sub_cmds)})")
            for sc in sub_cmds[:20]:
                lines.append(f"  {sc.get('parent', '?')}→{sc.get('child', '?')}")
        if flags:
            lines.append(f"## Flags ({len(flags)})")
            for fl in flags[:30]:
                persistent = "|persistent" if fl.get('is_persistent') else ""
                required = "|required" if fl.get('is_required') else ""
                lines.append(f"  --{fl.get('name', '?')}|{fl.get('flag_type', '?')}{persistent}{required}")
            if len(flags) > 30:
                lines.append(f"  # ... and {len(flags) - 30} more flags")
        if viper:
            lines.append(f"## Viper Bindings ({len(viper)})")
            for v in viper[:10]:
                lines.append(f"  {v.get('flag_name', '?')}→{v.get('config_key', '?')}")
        return lines

    # ============================================
    # v4.12: Java Language Compression Methods
    # ============================================

    def _compress_java_types(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress Java type definitions (classes, interfaces, records, enums, annotation defs)."""
        lines = []

        # Classes
        if hasattr(matrix, 'java_classes') and matrix.java_classes:
            lines.append("# Classes")
            for cls in matrix.java_classes:
                if not cls.get('is_exported', False):
                    continue
                prefix = self._service_prefix(cls, is_monorepo)
                kind = cls.get('kind', 'class')
                kind_marker = ""
                if kind == 'abstract_class':
                    kind_marker = "abstract "
                elif kind == 'sealed_class':
                    kind_marker = "sealed "

                # Fields
                fields = cls.get('fields', [])
                field_strs = []
                for f in fields[:8]:
                    ann_str = ""
                    if f.get('annotations'):
                        ann_str = "@" + ",@".join(f['annotations'][:2])
                        if len(f['annotations']) > 2:
                            ann_str += f"...+{len(f['annotations']) - 2}"
                        ann_str += " "
                    field_strs.append(f"{ann_str}{f['name']}:{f['type']}")
                if len(fields) > 8:
                    field_strs.append(f"...+{len(fields) - 8}")

                # Extends/implements
                ext_str = f"|extends:{cls['extends']}" if cls.get('extends') else ""
                impl = cls.get('implements', [])
                impl_str = f"|impl:{','.join(impl)}" if impl else ""

                # Annotations
                anns = cls.get('annotations', [])
                ann_str = f"|@{',@'.join(anns[:3])}" if anns else ""
                if len(anns) > 3:
                    ann_str += f"...+{len(anns) - 3}"

                # Generics
                generics = cls.get('generic_params', [])
                gen_str = ""
                if generics:
                    gen_parts = []
                    for g in generics:
                        bounds = g.get('bounds', [])
                        if bounds:
                            gen_parts.append(f"{g['name']}:{','.join(bounds)}")
                        else:
                            gen_parts.append(g['name'])
                    gen_str = f"<{','.join(gen_parts)}>"

                lines.append(f"  {prefix}{kind_marker}{cls['name']}{gen_str}({','.join(field_strs)}){ext_str}{impl_str}{ann_str}")

        # Interfaces
        if hasattr(matrix, 'java_interfaces') and matrix.java_interfaces:
            lines.append("# Interfaces")
            sorted_ifaces = sorted(
                [i for i in matrix.java_interfaces if i.get('is_exported', False)],
                key=lambda x: len(x.get('methods', [])),
                reverse=True
            )
            for iface in sorted_ifaces:
                prefix = self._service_prefix(iface, is_monorepo)
                methods = iface.get('methods', [])
                # Methods may be strings or dicts with 'name' key
                method_names = []
                for m in methods:
                    if isinstance(m, dict):
                        method_names.append(m.get('name', ''))
                    else:
                        method_names.append(str(m))
                extends = iface.get('extends', [])
                ext_str = f"|extends:{','.join(extends)}" if extends else ""
                functional = "|@FunctionalInterface" if iface.get('is_functional') else ""
                sealed = "sealed " if iface.get('is_sealed') else ""

                if len(method_names) <= 15:
                    lines.append(f"  {prefix}{sealed}{iface['name']}|methods:{','.join(method_names)}{ext_str}{functional}")
                else:
                    lines.append(f"  {prefix}{sealed}{iface['name']}|{len(method_names)} methods{ext_str}{functional}")
                    lines.append(f"    {','.join(method_names[:20])}")
                    if len(method_names) > 20:
                        lines.append(f"    +{','.join(method_names[20:])}")

        # Records (Java 14+)
        if hasattr(matrix, 'java_records') and matrix.java_records:
            lines.append("# Records")
            for rec in matrix.java_records:
                if not rec.get('is_exported', False):
                    continue
                prefix = self._service_prefix(rec, is_monorepo)
                components = rec.get('components', [])
                comp_strs = [f"{c['name']}:{c['type']}" for c in components]
                impl = rec.get('implements', [])
                impl_str = f"|impl:{','.join(impl)}" if impl else ""
                anns = rec.get('annotations', [])
                ann_str = f"|@{',@'.join(anns[:3])}" if anns else ""
                lines.append(f"  {prefix}record {rec['name']}({','.join(comp_strs)}){impl_str}{ann_str}")

        # Enums
        if hasattr(matrix, 'java_enums') and matrix.java_enums:
            lines.append("# Enums")
            for enum in matrix.java_enums:
                if not enum.get('is_exported', False):
                    continue
                prefix = self._service_prefix(enum, is_monorepo)
                constants = enum.get('constants', [])
                const_names = [c['name'] for c in constants]
                methods = enum.get('methods', [])
                method_str = f"|methods:{','.join(methods)}" if methods else ""

                if len(const_names) <= 15:
                    lines.append(f"  {prefix}{enum['name']}={','.join(const_names)}{method_str}")
                else:
                    lines.append(f"  {prefix}{enum['name']}={','.join(const_names[:15])}...+{len(const_names) - 15}{method_str}")

        # Annotation Definitions
        if hasattr(matrix, 'java_annotation_defs') and matrix.java_annotation_defs:
            lines.append("# Annotation Definitions")
            for ann in matrix.java_annotation_defs:
                prefix = self._service_prefix(ann, is_monorepo)
                elements = ann.get('elements', [])
                retention = ann.get('retention', '')
                target = ann.get('target', [])
                ret_str = f"|{retention}" if retention else ""
                target_str = f"|target:{','.join(target)}" if target else ""
                elem_strs = [f"{e['name']}:{e.get('type', '?')}" for e in elements[:5]] if isinstance(elements, list) else []
                lines.append(f"  {prefix}@interface {ann['name']}({','.join(elem_strs)}){ret_str}{target_str}")

        return lines

    def _compress_java_api(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress Java API endpoints (Spring/JAX-RS/Quarkus/Micronaut, gRPC, messaging)."""
        lines = []

        # HTTP endpoints
        if hasattr(matrix, 'java_endpoints') and matrix.java_endpoints:
            by_framework = {}
            for ep in matrix.java_endpoints:
                fw = ep.get('framework', 'spring')
                if fw not in by_framework:
                    by_framework[fw] = []
                by_framework[fw].append(ep)

            for fw, endpoints in by_framework.items():
                lines.append(f"# {fw.replace('_', ' ').title()} Endpoints")
                for ep in endpoints:
                    prefix = self._service_prefix(ep, is_monorepo)
                    method = ep.get('method', 'ANY')
                    path = ep.get('path', '/')
                    handler = ep.get('handler', '')
                    consumes = ep.get('consumes', '')
                    produces = ep.get('produces', '')
                    media_str = ""
                    if consumes:
                        media_str += f"|consumes:{consumes}"
                    if produces:
                        media_str += f"|produces:{produces}"
                    lines.append(f"  {prefix}{method}:{path}|{handler}{media_str}")

        # gRPC services
        if hasattr(matrix, 'java_grpc_services') and matrix.java_grpc_services:
            lines.append("# gRPC Services")
            for svc in matrix.java_grpc_services:
                prefix = self._service_prefix(svc, is_monorepo)
                base = svc.get('base_class', '')
                methods = svc.get('methods', [])
                method_str = f"|methods:{','.join(methods)}" if methods else ""
                lines.append(f"  {prefix}{svc['name']}|extends:{base}{method_str}")

        # Message listeners
        if hasattr(matrix, 'java_message_listeners') and matrix.java_message_listeners:
            lines.append("# Message Listeners")
            for listener in matrix.java_message_listeners:
                prefix = self._service_prefix(listener, is_monorepo)
                msg_type = listener.get('type', 'kafka')
                topic = listener.get('topic', '')
                handler = listener.get('handler', '')
                lines.append(f"  {prefix}[{msg_type}] {topic}|{handler}")

        return lines

    def _compress_java_functions(self, matrix) -> List[str]:
        """Compress Java methods and constructors with adaptive limits."""
        lines = []

        # Methods grouped by file
        if hasattr(matrix, 'java_methods') and matrix.java_methods:
            exported_methods = [m for m in matrix.java_methods if m.get('is_exported', False)]
            if exported_methods:
                methods_by_file = {}
                for method in exported_methods:
                    filename = method.get('file', 'unknown').split('/')[-1]
                    if filename not in methods_by_file:
                        methods_by_file[filename] = []
                    methods_by_file[filename].append(method)

                sorted_files = sorted(methods_by_file.items(), key=lambda x: len(x[1]), reverse=True)
                total_files = len(sorted_files)
                max_files = min(total_files, max(30, total_files // 2))

                file_count = 0
                for filename, methods in sorted_files:
                    if file_count >= max_files:
                        remaining = total_files - file_count
                        if remaining > 0:
                            lines.append(f"  # ... and {remaining} more files")
                        break

                    lines.append(f"  # {filename}")
                    for m in methods[:12]:
                        params = m.get('params', [])
                        param_strs = []
                        for p in params[:4]:
                            p_anns = p.get('annotations', [])
                            p_ann_str = f"@{'@'.join(p_anns[:1])} " if p_anns else ""
                            param_strs.append(f"{p_ann_str}{p['name']}:{p['type']}")
                        if len(params) > 4:
                            param_strs.append("...")
                        ret = m.get('return_type', 'void')
                        throws = m.get('throws', [])
                        throws_str = f"|throws:{','.join(throws)}" if throws else ""
                        override = "↑" if m.get('is_override') else ""
                        anns = m.get('annotations', [])
                        ann_str = f"@{',@'.join(anns[:2])} " if anns else ""
                        lines.append(f"    {ann_str}{override}{m['name']}({','.join(param_strs)})->{ret}{throws_str}")
                    if len(methods) > 12:
                        remaining_names = [m['name'] for m in methods[12:]]
                        lines.append(f"    +{','.join(remaining_names)}")
                    file_count += 1

        # Constructors
        if hasattr(matrix, 'java_constructors') and matrix.java_constructors:
            exported_ctors = [c for c in matrix.java_constructors if c.get('is_exported', False)]
            if exported_ctors:
                lines.append("  # Constructors")
                for ctor in exported_ctors[:30]:
                    params = ctor.get('params', [])
                    param_strs = []
                    for p in params[:5]:
                        p_anns = p.get('annotations', [])
                        p_ann_str = f"@{'@'.join(p_anns[:1])} " if p_anns else ""
                        param_strs.append(f"{p_ann_str}{p['name']}:{p['type']}")
                    if len(params) > 5:
                        param_strs.append("...")
                    anns = ctor.get('annotations', [])
                    ann_str = f"@{',@'.join(anns[:2])} " if anns else ""
                    lines.append(f"    {ann_str}{ctor['name']}({','.join(param_strs)})")
                if len(exported_ctors) > 30:
                    lines.append(f"    # ... and {len(exported_ctors) - 30} more constructors")

        return lines

    def _compress_java_models(self, matrix) -> List[str]:
        """Compress Java JPA entities and Spring Data repositories."""
        lines = []

        # JPA Entities
        if hasattr(matrix, 'java_entities') and matrix.java_entities:
            lines.append("# JPA Entities")
            for entity in matrix.java_entities:
                table = entity.get('table_name', '')
                table_str = f"|table:{table}" if table else ""

                # Columns
                columns = entity.get('columns', [])
                col_strs = []
                for c in columns[:8]:
                    nullable = "?" if c.get('nullable', True) else "!"
                    unique = "|unique" if c.get('unique') else ""
                    col_strs.append(f"{c['name']}:{c['type']}{nullable}{unique}")
                if len(columns) > 8:
                    col_strs.append(f"...+{len(columns) - 8}")

                # Relationships
                rels = entity.get('relationships', [])
                rel_strs = []
                for r in rels:
                    mapped = f"|mappedBy:{r['mapped_by']}" if r.get('mapped_by') else ""
                    rel_strs.append(f"{r['type']}→{r['target']}{mapped}")

                lines.append(f"  {entity['name']}{table_str}({','.join(col_strs)})")
                if rel_strs:
                    lines.append(f"    rels: {' | '.join(rel_strs)}")

        # Repositories
        if hasattr(matrix, 'java_repositories') and matrix.java_repositories:
            lines.append("# Repositories")
            for repo in matrix.java_repositories:
                entity_type = repo.get('entity_type', '?')
                repo_type = repo.get('repo_type', 'JpaRepository')
                custom = repo.get('custom_methods', [])
                custom_strs = [str(c) if not isinstance(c, str) else c for c in custom]
                custom_str = f"|methods:{','.join(custom_strs[:5])}" if custom_strs else ""
                if len(custom_strs) > 5:
                    custom_str += f"...+{len(custom_strs) - 5}"
                lines.append(f"  {repo['name']}|{repo_type}<{entity_type}>{custom_str}")

        return lines

    def _compress_java_dependencies(self, matrix) -> List[str]:
        """Compress Java dependencies from pom.xml / build.gradle."""
        lines = []

        if not hasattr(matrix, 'java_dependencies') or not matrix.java_dependencies:
            return lines

        deps = matrix.java_dependencies

        # Build system info
        build_system = deps.get('build_system', '')
        if build_system:
            lines.append(f"  build: {build_system}")

        # Project coordinates
        group = deps.get('group_id', '')
        artifact = deps.get('artifact_id', '')
        version = deps.get('version', '')
        if group or artifact:
            lines.append(f"  project: {group}:{artifact}:{version}")

        # Java version
        java_ver = deps.get('java_version', '')
        if java_ver:
            lines.append(f"  java: {java_ver}")

        # Parent (Spring Boot starter etc.)
        parent = deps.get('parent')
        if parent:
            lines.append(f"  parent: {parent.get('group_id', '')}:{parent.get('artifact_id', '')}:{parent.get('version', '')}")

        # Modules (multi-module project)
        modules = deps.get('modules', [])
        if modules:
            lines.append(f"  modules: {','.join(modules)}")

        # Dependencies categorized
        dep_list = deps.get('dependencies', [])
        if dep_list:
            lines.append(f"  # {len(dep_list)} dependencies")
            categories = {
                'spring': [], 'web': [], 'data': [], 'security': [],
                'test': [], 'cloud': [], 'messaging': [], 'logging': [], 'other': []
            }
            for d in dep_list:
                group_id = d.get('group_id', '')
                artifact_id = d.get('artifact_id', '')
                ver = d.get('version', '') or ''
                scope = d.get('scope', '')
                dep_str = f"{group_id}:{artifact_id}"
                if ver:
                    dep_str += f"@{ver}"
                if scope and scope != 'compile':
                    dep_str += f"|{scope}"

                gid_lower = group_id.lower()
                aid_lower = artifact_id.lower()
                if 'springframework' in gid_lower:
                    if 'security' in aid_lower:
                        categories['security'].append(dep_str)
                    elif 'data' in aid_lower or 'jpa' in aid_lower:
                        categories['data'].append(dep_str)
                    elif 'web' in aid_lower:
                        categories['web'].append(dep_str)
                    elif 'cloud' in aid_lower:
                        categories['cloud'].append(dep_str)
                    elif 'kafka' in aid_lower or 'amqp' in aid_lower or 'jms' in aid_lower:
                        categories['messaging'].append(dep_str)
                    else:
                        categories['spring'].append(dep_str)
                elif any(k in gid_lower for k in ['junit', 'mockito', 'assertj', 'testcontainers']):
                    categories['test'].append(dep_str)
                elif any(k in gid_lower for k in ['hibernate', 'mybatis', 'jooq', 'flyway', 'liquibase']):
                    categories['data'].append(dep_str)
                elif any(k in gid_lower for k in ['log4j', 'slf4j', 'logback']):
                    categories['logging'].append(dep_str)
                elif any(k in gid_lower for k in ['quarkus', 'micronaut']):
                    categories['web'].append(dep_str)
                elif any(k in gid_lower for k in ['kafka', 'rabbitmq', 'activemq']):
                    categories['messaging'].append(dep_str)
                else:
                    categories['other'].append(dep_str)

            for cat, cat_deps in categories.items():
                if cat_deps:
                    lines.append(f"  [{cat}] {' | '.join(cat_deps[:8])}")
                    if len(cat_deps) > 8:
                        lines.append(f"    # ... and {len(cat_deps) - 8} more")

        # Detected frameworks
        if hasattr(matrix, 'java_detected_frameworks') and matrix.java_detected_frameworks:
            lines.append(f"  frameworks: {','.join(matrix.java_detected_frameworks)}")

        return lines

    # ================================================================
    # v4.12: Kotlin Language Compression Methods
    # ================================================================

    def _compress_kotlin_types(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress Kotlin type definitions (classes, objects, interfaces, enum classes)."""
        lines = []

        # Classes (data, sealed, abstract, open, inner, value, annotation)
        if hasattr(matrix, 'kotlin_classes') and matrix.kotlin_classes:
            lines.append("# Classes")
            for cls in matrix.kotlin_classes:
                if not cls.get('is_exported', False):
                    continue
                prefix = self._service_prefix(cls, is_monorepo)
                kind = cls.get('kind', 'class')
                kind_marker = ""
                if kind == 'data_class':
                    kind_marker = "data "
                elif kind == 'sealed_class':
                    kind_marker = "sealed "
                elif kind == 'abstract_class':
                    kind_marker = "abstract "
                elif kind == 'value_class':
                    kind_marker = "value "
                elif kind == 'annotation_class':
                    kind_marker = "annotation "
                elif kind == 'inner_class':
                    kind_marker = "inner "

                # Primary constructor
                ctor = cls.get('primary_constructor', [])
                ctor_strs = []
                for p in ctor[:6]:
                    val_var = "val" if p.get('is_val', True) else "var"
                    ctor_strs.append(f"{val_var} {p.get('name', '?')}:{p.get('type', '?')}")
                if len(ctor) > 6:
                    ctor_strs.append(f"...+{len(ctor) - 6}")

                # Properties (from body, not ctor)
                props = cls.get('properties', [])
                prop_strs = []
                for p in props[:4]:
                    mutability = "val" if p.get('is_val', True) else "var"
                    prop_strs.append(f"{mutability} {p['name']}:{p.get('type', '?')}")
                if len(props) > 4:
                    prop_strs.append(f"...+{len(props) - 4}")

                # Extends/implements
                ext_str = f"|extends:{cls['extends']}" if cls.get('extends') else ""
                impl = cls.get('implements', [])
                impl_str = f"|impl:{','.join(impl)}" if impl else ""

                # Annotations
                anns = cls.get('annotations', [])
                ann_str = f"|@{',@'.join(anns[:3])}" if anns else ""
                if len(anns) > 3:
                    ann_str += f"...+{len(anns) - 3}"

                # Generics
                generics = cls.get('generic_params', [])
                gen_str = f"<{','.join(generics)}>" if generics else ""

                # Companion
                companion = cls.get('companion_object')
                comp_str = f"|companion:{companion}" if companion else ""

                all_params = ctor_strs + prop_strs
                lines.append(f"  {prefix}{kind_marker}class {cls['name']}{gen_str}({','.join(all_params)}){ext_str}{impl_str}{ann_str}{comp_str}")

        # Objects (singletons)
        if hasattr(matrix, 'kotlin_objects') and matrix.kotlin_objects:
            lines.append("# Objects")
            for obj in matrix.kotlin_objects:
                prefix = self._service_prefix(obj, is_monorepo)
                kind = obj.get('kind', 'object')
                methods = obj.get('methods', [])
                method_str = f"|methods:{','.join(methods[:8])}" if methods else ""
                if len(methods) > 8:
                    method_str += f"...+{len(methods) - 8}"
                ext_str = f"|extends:{obj['extends']}" if obj.get('extends') else ""
                impl = obj.get('implements', [])
                impl_str = f"|impl:{','.join(impl)}" if impl else ""
                lines.append(f"  {prefix}{kind} {obj['name']}{ext_str}{impl_str}{method_str}")

        # Interfaces
        if hasattr(matrix, 'kotlin_interfaces') and matrix.kotlin_interfaces:
            lines.append("# Interfaces")
            for iface in matrix.kotlin_interfaces:
                if not iface.get('is_exported', False):
                    continue
                prefix = self._service_prefix(iface, is_monorepo)
                methods = iface.get('methods', [])
                extends = iface.get('extends', [])
                ext_str = f"|extends:{','.join(extends)}" if extends else ""
                functional = "|@FunctionalInterface" if iface.get('is_functional') else ""
                sealed = "sealed " if iface.get('is_sealed') else ""
                generics = iface.get('generic_params', [])
                gen_str = f"<{','.join(generics)}>" if generics else ""

                if len(methods) <= 15:
                    lines.append(f"  {prefix}{sealed}interface {iface['name']}{gen_str}|methods:{','.join(methods)}{ext_str}{functional}")
                else:
                    lines.append(f"  {prefix}{sealed}interface {iface['name']}{gen_str}|{len(methods)} methods{ext_str}{functional}")
                    lines.append(f"    {','.join(methods[:20])}")

        # Enum classes
        if hasattr(matrix, 'kotlin_enums') and matrix.kotlin_enums:
            lines.append("# Enum Classes")
            for enum in matrix.kotlin_enums:
                prefix = self._service_prefix(enum, is_monorepo)
                entries = enum.get('entries', [])
                methods = enum.get('methods', [])
                method_str = f"|methods:{','.join(methods)}" if methods else ""

                if len(entries) <= 15:
                    lines.append(f"  {prefix}enum {enum['name']}={','.join(entries)}{method_str}")
                else:
                    lines.append(f"  {prefix}enum {enum['name']}={','.join(entries[:15])}...+{len(entries) - 15}{method_str}")

        # Detected features
        if hasattr(matrix, 'kotlin_features') and matrix.kotlin_features:
            lines.append(f"# Features: {','.join(matrix.kotlin_features)}")

        # Detected frameworks
        if hasattr(matrix, 'kotlin_detected_frameworks') and matrix.kotlin_detected_frameworks:
            lines.append(f"# Frameworks: {','.join(matrix.kotlin_detected_frameworks)}")

        return lines

    def _compress_kotlin_functions(self, matrix) -> List[str]:
        """Compress Kotlin functions with Kotlin-specific modifiers."""
        lines = []

        if not hasattr(matrix, 'kotlin_functions') or not matrix.kotlin_functions:
            return lines

        exported_funcs = [f for f in matrix.kotlin_functions if f.get('is_exported', False)]
        if not exported_funcs:
            return lines

        # Group by file
        funcs_by_file = {}
        for func in exported_funcs:
            filename = func.get('file', 'unknown').split('/')[-1]
            if filename not in funcs_by_file:
                funcs_by_file[filename] = []
            funcs_by_file[filename].append(func)

        sorted_files = sorted(funcs_by_file.items(), key=lambda x: len(x[1]), reverse=True)
        max_files = min(len(sorted_files), 30)

        file_count = 0
        for filename, funcs in sorted_files:
            if file_count >= max_files:
                remaining = len(sorted_files) - file_count
                if remaining > 0:
                    lines.append(f"  # ... and {remaining} more files")
                break

            lines.append(f"  # {filename}")
            for f in funcs[:12]:
                # Build modifier prefix
                modifiers = []
                if f.get('is_suspend'):
                    modifiers.append('suspend')
                if f.get('is_inline'):
                    modifiers.append('inline')
                if f.get('is_infix'):
                    modifiers.append('infix')
                if f.get('is_operator'):
                    modifiers.append('operator')
                mod_str = ' '.join(modifiers) + ' ' if modifiers else ''

                # Extension receiver
                receiver = f.get('receiver_type', '')
                recv_str = f"{receiver}." if receiver else ""

                # Params
                params = f.get('params', [])
                param_strs = []
                for p in params[:4]:
                    p_anns = p.get('annotations', [])
                    p_ann_str = f"@{'@'.join(p_anns[:1])} " if p_anns else ""
                    param_strs.append(f"{p_ann_str}{p['name']}:{p['type']}")
                if len(params) > 4:
                    param_strs.append("...")

                ret = f.get('return_type', '')
                ret_str = f"->{ret}" if ret else ""
                override = "↑" if f.get('is_override') else ""
                anns = f.get('annotations', [])
                ann_str = f"@{',@'.join(anns[:2])} " if anns else ""

                lines.append(f"    {ann_str}{override}{mod_str}{recv_str}{f['name']}({','.join(param_strs)}){ret_str}")
            if len(funcs) > 12:
                remaining_names = [f['name'] for f in funcs[12:]]
                lines.append(f"    +{','.join(remaining_names)}")
            file_count += 1

        return lines

    def _compress_kotlin_api(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress Kotlin API endpoints (Spring/Ktor/Quarkus/Micronaut)."""
        lines = []

        if not hasattr(matrix, 'kotlin_endpoints') or not matrix.kotlin_endpoints:
            return lines

        # Group by framework
        by_framework = {}
        for ep in matrix.kotlin_endpoints:
            fw = ep.get('framework', 'spring')
            if fw not in by_framework:
                by_framework[fw] = []
            by_framework[fw].append(ep)

        for fw, endpoints in by_framework.items():
            lines.append(f"# {fw.replace('_', ' ').title()} Endpoints")
            for ep in endpoints:
                prefix = self._service_prefix(ep, is_monorepo)
                method = ep.get('method', 'ANY')
                path = ep.get('path', '/')
                handler = ep.get('handler', '')
                consumes = ep.get('consumes', '')
                produces = ep.get('produces', '')
                media_str = ""
                if consumes:
                    media_str += f"|consumes:{consumes}"
                if produces:
                    media_str += f"|produces:{produces}"
                lines.append(f"  {prefix}{method}:{path}|{handler}{media_str}")

        return lines

    def _compress_kotlin_models(self, matrix) -> List[str]:
        """Compress Kotlin JPA entities."""
        lines = []

        if not hasattr(matrix, 'kotlin_entities') or not matrix.kotlin_entities:
            return lines

        lines.append("# JPA Entities (Kotlin)")
        for entity in matrix.kotlin_entities:
            table = entity.get('table_name', '')
            table_str = f"|table:{table}" if table else ""

            # Columns
            columns = entity.get('columns', [])
            col_strs = []
            for c in columns[:8]:
                nullable = "?" if c.get('nullable', True) else "!"
                unique = "|unique" if c.get('unique') else ""
                col_strs.append(f"{c['name']}:{c['type']}{nullable}{unique}")
            if len(columns) > 8:
                col_strs.append(f"...+{len(columns) - 8}")

            # Relationships
            rels = entity.get('relationships', [])
            rel_strs = []
            for r in rels:
                mapped = f"|mappedBy:{r['mapped_by']}" if r.get('mapped_by') else ""
                rel_strs.append(f"{r['type']}→{r['target']}{mapped}")

            lines.append(f"  {entity['name']}{table_str}({','.join(col_strs)})")
            if rel_strs:
                lines.append(f"    rels: {' | '.join(rel_strs)}")

        return lines

    def _compress_kotlin_repositories(self, matrix) -> List[str]:
        """Compress Kotlin repository definitions (Spring Data, Micronaut, Panache)."""
        lines = []
        if not hasattr(matrix, 'kotlin_repositories') or not matrix.kotlin_repositories:
            return lines

        for repo in matrix.kotlin_repositories:
            name = repo.get('name', '')
            entity = repo.get('entity_type', '')
            extends = repo.get('extends', '')
            fw = repo.get('framework', '')
            methods = repo.get('custom_methods', [])
            method_str = f"|methods:{','.join(methods[:6])}" if methods else ""
            if len(methods) > 6:
                method_str += f"...+{len(methods) - 6}"
            extends_str = f" : {extends}" if extends else ""
            entity_str = f"<{entity}>" if entity else ""
            fw_str = f"|{fw}" if fw else ""
            lines.append(f"  {name}{entity_str}{extends_str}{fw_str}{method_str}")

        return lines

    def _compress_kotlin_serialization(self, matrix) -> List[str]:
        """Compress Kotlin serialization models, Exposed tables, and DTOs."""
        lines = []

        # kotlinx.serialization @Serializable models
        if hasattr(matrix, 'kotlin_serializables') and matrix.kotlin_serializables:
            lines.append("# @Serializable")
            for ser in matrix.kotlin_serializables:
                name = ser.get('name', '')
                fmt = ser.get('format', '')
                fields = ser.get('fields', [])
                field_strs = [f"{f.get('name', '?')}:{f.get('type', '?')}" for f in fields[:6]]
                if len(fields) > 6:
                    field_strs.append(f"...+{len(fields) - 6}")
                fmt_str = f"|format:{fmt}" if fmt else ""
                lines.append(f"  {name}({','.join(field_strs)}){fmt_str}")

        # Exposed table objects
        if hasattr(matrix, 'kotlin_exposed_tables') and matrix.kotlin_exposed_tables:
            lines.append("# Exposed Tables")
            for table in matrix.kotlin_exposed_tables:
                name = table.get('name', '')
                table_name = table.get('table_name', '')
                columns = table.get('columns', [])
                refs = table.get('references', [])
                col_strs = [f"{c.get('name', '?')}:{c.get('type', '?')}" for c in columns[:6]]
                if len(columns) > 6:
                    col_strs.append(f"...+{len(columns) - 6}")
                ref_str = f"|refs:{','.join(refs)}" if refs else ""
                lines.append(f"  {name}|table:{table_name}({','.join(col_strs)}){ref_str}")

        # DTOs
        if hasattr(matrix, 'kotlin_dtos') and matrix.kotlin_dtos:
            lines.append("# DTOs")
            for dto in matrix.kotlin_dtos:
                name = dto.get('name', '')
                kind = dto.get('kind', '')
                fields = dto.get('fields', [])
                field_strs = [f"{f.get('name', '?')}:{f.get('type', '?')}" for f in fields[:6]]
                if len(fields) > 6:
                    field_strs.append(f"...+{len(fields) - 6}")
                lines.append(f"  {kind} {name}({','.join(field_strs)})")

        return lines

    def _compress_kotlin_di(self, matrix) -> List[str]:
        """Compress Kotlin dependency injection bindings (Koin, Dagger/Hilt, Spring)."""
        lines = []
        if not hasattr(matrix, 'kotlin_di_bindings') or not matrix.kotlin_di_bindings:
            return lines

        # Group by framework
        by_framework = {}
        for di in matrix.kotlin_di_bindings:
            fw = di.get('framework', 'unknown')
            if fw not in by_framework:
                by_framework[fw] = []
            by_framework[fw].append(di)

        for fw, bindings in by_framework.items():
            lines.append(f"# {fw.title()}")
            for b in bindings:
                btype = b.get('type', '')
                target = b.get('target', '')
                scope = b.get('scope', '')
                scope_str = f"|scope:{scope}" if scope else ""
                lines.append(f"  {btype}({target}){scope_str}")

        return lines

    def _compress_kotlin_multiplatform(self, matrix) -> List[str]:
        """Compress Kotlin multiplatform expect/actual declarations."""
        lines = []
        if not hasattr(matrix, 'kotlin_multiplatform_decls') or not matrix.kotlin_multiplatform_decls:
            return lines

        # Group by kind (expect/actual)
        expects = [d for d in matrix.kotlin_multiplatform_decls if d.get('kind') == 'expect']
        actuals = [d for d in matrix.kotlin_multiplatform_decls if d.get('kind') == 'actual']

        if expects:
            lines.append("# expect declarations")
            for d in expects:
                lines.append(f"  expect {d.get('declaration_type', '?')} {d.get('name', '?')}")
        if actuals:
            lines.append("# actual declarations")
            for d in actuals:
                lines.append(f"  actual {d.get('declaration_type', '?')} {d.get('name', '?')}")

        return lines

    def _compress_kotlin_advanced(self, matrix) -> List[str]:
        """Compress Kotlin advanced features: WebSocket, gRPC, GraphQL, context receivers, contracts, DSL markers, annotations, delegations."""
        lines = []

        # WebSocket
        if hasattr(matrix, 'kotlin_websockets') and matrix.kotlin_websockets:
            lines.append("# WebSocket")
            for ws in matrix.kotlin_websockets:
                lines.append(f"  ws:{ws.get('path', '/')}|{ws.get('handler', '')}|{ws.get('framework', '')}")

        # gRPC Services
        if hasattr(matrix, 'kotlin_grpc_services') and matrix.kotlin_grpc_services:
            lines.append("# gRPC Services")
            for grpc in matrix.kotlin_grpc_services:
                methods = grpc.get('methods', [])
                coroutine = "|coroutine" if grpc.get('is_coroutine') else ""
                lines.append(f"  {grpc.get('name', '')}|methods:{','.join(methods[:8])}{coroutine}")

        # GraphQL
        if hasattr(matrix, 'kotlin_graphql') and matrix.kotlin_graphql:
            lines.append("# GraphQL")
            for gql in matrix.kotlin_graphql:
                fields = gql.get('fields', [])
                lines.append(f"  {gql.get('kind', '')} {gql.get('name', '')}|{gql.get('framework', '')}|fields:{','.join(fields[:6])}")

        # Context receivers
        if hasattr(matrix, 'kotlin_context_receivers') and matrix.kotlin_context_receivers:
            lines.append("# Context Receivers")
            for ctx in matrix.kotlin_context_receivers:
                types = ctx.get('context_types', [])
                lines.append(f"  context({','.join(types)}) {ctx.get('name', '')}")

        # Contracts
        if hasattr(matrix, 'kotlin_contracts') and matrix.kotlin_contracts:
            lines.append("# Contracts")
            for c in matrix.kotlin_contracts:
                effects = c.get('effects', [])
                lines.append(f"  {c.get('function', '')}|effects:{','.join(effects[:3])}")

        # DSL Markers
        if hasattr(matrix, 'kotlin_dsl_markers') and matrix.kotlin_dsl_markers:
            names = [d.get('name', '') for d in matrix.kotlin_dsl_markers]
            lines.append(f"# DSL Markers: {','.join(names)}")

        # Annotation definitions
        if hasattr(matrix, 'kotlin_annotation_defs') and matrix.kotlin_annotation_defs:
            lines.append("# Custom Annotations")
            for ann in matrix.kotlin_annotation_defs:
                targets = ann.get('targets', [])
                ret = ann.get('retention', '')
                target_str = f"|targets:{','.join(targets)}" if targets else ""
                ret_str = f"|{ret}" if ret else ""
                lines.append(f"  @{ann.get('name', '')}{target_str}{ret_str}")

        # Type aliases
        if hasattr(matrix, 'kotlin_type_aliases') and matrix.kotlin_type_aliases:
            lines.append("# Type Aliases")
            for ta in matrix.kotlin_type_aliases:
                lines.append(f"  typealias {ta.get('name', '')} = {ta.get('actual_type', ta.get('type', '?'))}")

        # Delegations
        if hasattr(matrix, 'kotlin_delegations') and matrix.kotlin_delegations:
            lines.append("# Delegations")
            for d in matrix.kotlin_delegations:
                lines.append(f"  {d.get('property', '')} by {d.get('delegate', '')}|{d.get('kind', '')}")

        # Kotlin version
        if hasattr(matrix, 'kotlin_version') and matrix.kotlin_version:
            lines.append(f"# Kotlin version: {matrix.kotlin_version}")
            if hasattr(matrix, 'kotlin_uses_k2_compiler') and matrix.kotlin_uses_k2_compiler:
                lines.append("# K2 Compiler: enabled")

        return lines

    # ============================================
    # v4.13: C# Compression Methods
    # ============================================

    def _compress_csharp_types(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress C# type definitions (classes, interfaces, structs, records, enums, delegates)."""
        lines = []

        # Classes
        if hasattr(matrix, 'csharp_classes') and matrix.csharp_classes:
            lines.append("# Classes")
            for cls in matrix.csharp_classes:
                file_short = cls.get('file', '').split('/')[-1]
                modifiers = []
                if cls.get('is_abstract'):
                    modifiers.append('abstract')
                if cls.get('is_sealed'):
                    modifiers.append('sealed')
                if cls.get('is_static'):
                    modifiers.append('static')
                if cls.get('is_partial'):
                    modifiers.append('partial')
                mod_str = ' '.join(modifiers) + ' ' if modifiers else ''

                extends_str = f" : {cls['extends']}" if cls.get('extends') else ""
                impl_str = ""
                if cls.get('implements'):
                    impl_str = f", {', '.join(cls['implements'][:3])}"
                    if len(cls.get('implements', [])) > 3:
                        impl_str += f", +{len(cls['implements']) - 3}more"

                # Properties
                props = cls.get('properties', [])
                prop_strs = []
                for p in props[:8]:
                    prop_strs.append(f"{p['name']}:{p.get('type', '?')}")
                if len(props) > 8:
                    prop_strs.append(f"+{len(props) - 8}more")

                # Methods
                methods = cls.get('methods', [])
                meth_str = ""
                if methods:
                    shown = methods[:8] if isinstance(methods[0], str) else [m.get('name', '') for m in methods[:8]]
                    meth_str = f"|methods:[{','.join(shown)}]"
                    if len(methods) > 8:
                        meth_str = meth_str[:-1] + f",+{len(methods) - 8}more]"

                # Attributes
                attrs = cls.get('attributes', [])
                attr_str = f"|@[{','.join(attrs[:3])}]" if attrs else ""

                lines.append(f"  {mod_str}class {cls['name']}{extends_str}{impl_str}|{file_short}({','.join(prop_strs)}){meth_str}{attr_str}")

        # Interfaces
        if hasattr(matrix, 'csharp_interfaces') and matrix.csharp_interfaces:
            lines.append("# Interfaces")
            for iface in matrix.csharp_interfaces:
                file_short = iface.get('file', '').split('/')[-1]
                extends_str = ""
                if iface.get('extends'):
                    extends_str = f" : {', '.join(iface['extends'][:3])}"

                methods = iface.get('methods', [])
                meth_strs = []
                for m in methods[:8]:
                    if isinstance(m, str):
                        meth_strs.append(m)
                    else:
                        meth_strs.append(m.get('name', ''))
                if len(methods) > 8:
                    meth_strs.append(f"+{len(methods) - 8}more")

                lines.append(f"  interface {iface['name']}{extends_str}|{file_short}|methods:[{','.join(meth_strs)}]")

        # Structs
        if hasattr(matrix, 'csharp_structs') and matrix.csharp_structs:
            lines.append("# Structs")
            for s in matrix.csharp_structs:
                file_short = s.get('file', '').split('/')[-1]
                mod_parts = []
                if s.get('is_readonly'):
                    mod_parts.append('readonly')
                if s.get('is_ref'):
                    mod_parts.append('ref')
                mod_str = ' '.join(mod_parts) + ' ' if mod_parts else ''
                lines.append(f"  {mod_str}struct {s['name']}|{file_short}")

        # Records
        if hasattr(matrix, 'csharp_records') and matrix.csharp_records:
            lines.append("# Records")
            for rec in matrix.csharp_records:
                file_short = rec.get('file', '').split('/')[-1]
                params = rec.get('parameters', [])
                param_strs = [f"{p.get('name', '')}:{p.get('type', '?')}" for p in params[:5]]
                if len(params) > 5:
                    param_strs.append(f"+{len(params) - 5}more")
                lines.append(f"  record {rec['name']}({','.join(param_strs)})|{file_short}")

        # Enums
        if hasattr(matrix, 'csharp_enums') and matrix.csharp_enums:
            lines.append("# Enums")
            for enum in matrix.csharp_enums:
                file_short = enum.get('file', '').split('/')[-1]
                members = enum.get('members', [])
                member_names = [m.get('name', '') for m in members[:8]]
                if len(members) > 8:
                    member_names.append(f"+{len(members) - 8}more")
                flags_str = "|[Flags]" if enum.get('is_flags') else ""
                type_str = f"|:{enum['underlying_type']}" if enum.get('underlying_type') else ""
                lines.append(f"  enum {enum['name']}{flags_str}{type_str}|{file_short}[{','.join(member_names)}]")

        # Delegates
        if hasattr(matrix, 'csharp_delegates') and matrix.csharp_delegates:
            lines.append("# Delegates")
            for dlg in matrix.csharp_delegates:
                file_short = dlg.get('file', '').split('/')[-1]
                lines.append(f"  delegate {dlg.get('return_type', 'void')} {dlg['name']}|{file_short}")

        return lines

    def _compress_csharp_api(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress C# API endpoints, gRPC services, SignalR hubs."""
        lines = []

        # ASP.NET Core / Minimal API endpoints
        if hasattr(matrix, 'csharp_endpoints') and matrix.csharp_endpoints:
            # Group by framework
            by_framework = {}
            for ep in matrix.csharp_endpoints:
                fw = ep.get('framework', 'aspnet')
                if fw not in by_framework:
                    by_framework[fw] = []
                by_framework[fw].append(ep)

            for fw, endpoints in by_framework.items():
                lines.append(f"# {fw} ({len(endpoints)} endpoints)")
                for ep in endpoints[:30]:
                    file_short = ep.get('file', '').split('/')[-1]
                    auth_str = "|🔒" if ep.get('is_authorized') else ""
                    ctrl_str = f"|{ep['controller']}" if ep.get('controller') else ""
                    lines.append(f"  {ep['method']} {ep['path']}→{ep['handler']}{ctrl_str}|{file_short}{auth_str}")
                if len(endpoints) > 30:
                    lines.append(f"  # ... and {len(endpoints) - 30} more endpoints")

        # gRPC services
        if hasattr(matrix, 'csharp_grpc_services') and matrix.csharp_grpc_services:
            lines.append("# gRPC Services")
            for svc in matrix.csharp_grpc_services:
                file_short = svc.get('file', '').split('/')[-1]
                methods = svc.get('methods', [])
                method_names = [m.get('name', '') for m in methods[:5]] if methods else []
                lines.append(f"  grpc {svc['name']}:{svc.get('base_class', '')}|{file_short}|methods:[{','.join(method_names)}]")

        # SignalR hubs
        if hasattr(matrix, 'csharp_signalr_hubs') and matrix.csharp_signalr_hubs:
            lines.append("# SignalR Hubs")
            for hub in matrix.csharp_signalr_hubs:
                file_short = hub.get('file', '').split('/')[-1]
                methods = hub.get('methods', [])
                method_names = [m.get('name', '') for m in methods[:5]] if methods else []
                lines.append(f"  hub {hub['name']}:{hub.get('base_class', '')}|{file_short}|methods:[{','.join(method_names)}]")

        return lines

    def _compress_csharp_functions(self, matrix) -> List[str]:
        """Compress C# methods and constructors."""
        lines = []

        # Methods
        if hasattr(matrix, 'csharp_methods') and matrix.csharp_methods:
            lines.append(f"# Methods ({len(matrix.csharp_methods)} total)")
            for method in matrix.csharp_methods[:40]:
                file_short = method.get('file', '').split('/')[-1]
                params = method.get('params', [])
                param_strs = [f"{p.get('name', '')}:{p.get('type', '?')}" for p in params[:4]]
                if len(params) > 4:
                    param_strs.append(f"+{len(params) - 4}")

                modifiers = []
                if method.get('is_async'):
                    modifiers.append('async')
                if method.get('is_static'):
                    modifiers.append('static')
                if method.get('is_virtual'):
                    modifiers.append('virtual')
                if method.get('is_override'):
                    modifiers.append('override')
                mod_str = ' '.join(modifiers) + ' ' if modifiers else ''

                class_str = f"{method['class_name']}." if method.get('class_name') else ""
                lines.append(f"  {mod_str}{method.get('return_type', 'void')} {class_str}{method['name']}({','.join(param_strs)})|{file_short}")
            if len(matrix.csharp_methods) > 40:
                lines.append(f"  # ... and {len(matrix.csharp_methods) - 40} more methods")

        # Constructors
        if hasattr(matrix, 'csharp_constructors') and matrix.csharp_constructors:
            lines.append(f"# Constructors ({len(matrix.csharp_constructors)})")
            for ctor in matrix.csharp_constructors[:20]:
                file_short = ctor.get('file', '').split('/')[-1]
                params = ctor.get('params', [])
                param_strs = [f"{p.get('name', '')}:{p.get('type', '?')}" for p in params[:5]]
                if len(params) > 5:
                    param_strs.append(f"+{len(params) - 5}")
                lines.append(f"  {ctor['name']}({','.join(param_strs)})|{file_short}")

        return lines

    def _compress_csharp_models(self, matrix) -> List[str]:
        """Compress C# EF Core entities, DbContext, DTOs, and repositories."""
        lines = []

        # DbContext
        if hasattr(matrix, 'csharp_db_contexts') and matrix.csharp_db_contexts:
            lines.append("# DbContext")
            for ctx in matrix.csharp_db_contexts:
                file_short = ctx.get('file', '').split('/')[-1]
                db_sets = ctx.get('db_sets', [])
                set_strs = [f"{ds.get('property_name', '')}→{ds.get('entity_type', '')}" for ds in db_sets[:10]]
                if len(db_sets) > 10:
                    set_strs.append(f"+{len(db_sets) - 10}more")
                fluent_str = "|FluentAPI" if ctx.get('uses_fluent_api') else ""
                lines.append(f"  {ctx['name']}:{ctx.get('base_class', 'DbContext')}|{file_short}{fluent_str}")
                if set_strs:
                    lines.append(f"    DbSets: [{','.join(set_strs)}]")

        # EF Core entities
        if hasattr(matrix, 'csharp_entities') and matrix.csharp_entities:
            lines.append("# EF Core Entities")
            for entity in matrix.csharp_entities:
                file_short = entity.get('file', '').split('/')[-1]
                table = entity.get('table_name', '')
                table_str = f"|table:{table}" if table else ""
                owned_str = "|[Owned]" if entity.get('is_owned') else ""
                keyless_str = "|[Keyless]" if entity.get('is_keyless') else ""

                # Properties
                props = entity.get('properties', [])
                prop_strs = []
                for p in props[:8]:
                    prop_strs.append(f"{p.get('name', '')}:{p.get('type', '?')}")
                if len(props) > 8:
                    prop_strs.append(f"+{len(props) - 8}more")

                # Navigation properties
                nav = entity.get('navigation_properties', [])
                nav_strs = []
                for n in nav:
                    nav_strs.append(f"{n.get('relationship', '?')}→{n.get('name', '')}")

                lines.append(f"  {entity['name']}{table_str}{owned_str}{keyless_str}|{file_short}({','.join(prop_strs)})")
                if nav_strs:
                    lines.append(f"    nav: {' | '.join(nav_strs[:5])}")

        # DTOs
        if hasattr(matrix, 'csharp_dtos') and matrix.csharp_dtos:
            lines.append(f"# DTOs/ViewModels ({len(matrix.csharp_dtos)})")
            for dto in matrix.csharp_dtos[:20]:
                file_short = dto.get('file', '').split('/')[-1]
                kind = dto.get('kind', 'dto')
                rec_str = "|record" if dto.get('is_record') else ""
                props = dto.get('properties', [])
                prop_strs = [f"{p.get('name', '')}:{p.get('type', '?')}" for p in props[:5]]
                if len(props) > 5:
                    prop_strs.append(f"+{len(props) - 5}more")
                lines.append(f"  [{kind}] {dto['name']}{rec_str}|{file_short}({','.join(prop_strs)})")

        # Repositories
        if hasattr(matrix, 'csharp_repositories') and matrix.csharp_repositories:
            lines.append("# Repositories")
            for repo in matrix.csharp_repositories:
                file_short = repo.get('file', '').split('/')[-1]
                entity_str = f"<{repo['entity_type']}>" if repo.get('entity_type') else ""
                iface_str = f" : {repo['interface']}" if repo.get('interface') else ""
                methods = repo.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                lines.append(f"  {repo['name']}{entity_str}{iface_str}|{file_short}{meth_str}")

        return lines

    def _compress_csharp_dependencies(self, matrix) -> List[str]:
        """Compress C# NuGet dependencies."""
        lines = []

        if hasattr(matrix, 'csharp_dependencies') and matrix.csharp_dependencies:
            deps = matrix.csharp_dependencies
            if isinstance(deps, dict):
                for name, version in deps.items():
                    lines.append(f"  {name}@{version}")
            elif isinstance(deps, list):
                for dep in deps:
                    if isinstance(dep, dict):
                        name = dep.get('name', '')
                        version = dep.get('version', '')
                        lines.append(f"  {name}@{version}")

        # Also show detected frameworks
        if hasattr(matrix, 'csharp_detected_frameworks') and matrix.csharp_detected_frameworks:
            lines.append(f"# Detected: {', '.join(matrix.csharp_detected_frameworks[:15])}")

        # Namespaces
        if hasattr(matrix, 'csharp_namespaces') and matrix.csharp_namespaces:
            lines.append(f"# Namespaces ({len(matrix.csharp_namespaces)}): {', '.join(matrix.csharp_namespaces[:10])}")
            if len(matrix.csharp_namespaces) > 10:
                lines.append(f"#   ... and {len(matrix.csharp_namespaces) - 10} more")

        return lines

    # ========================================================================
    # v4.14: Rust Language Compressor Methods
    # ========================================================================

    def _compress_rust_types(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress Rust type definitions (structs, enums, traits, type aliases, impls)."""
        lines = []

        # Structs
        if hasattr(matrix, 'rust_structs') and matrix.rust_structs:
            lines.append("# Structs")
            for s in matrix.rust_structs:
                file_short = s.get('file', '').split('/')[-1]
                vis = f"{s['visibility']} " if s.get('visibility') and s['visibility'] != 'pub' else "pub " if s.get('visibility') == 'pub' else ""
                generics = f"<{','.join(s['generic_params'])}>" if s.get('generic_params') else ""
                derives_str = f"|#[derive({','.join(s['derives'][:5])})]" if s.get('derives') else ""
                tuple_str = "|tuple" if s.get('is_tuple') else ""

                fields = s.get('fields', [])
                field_strs = [f"{f['name']}:{f.get('type', '?')}" for f in fields[:8]]
                if len(fields) > 8:
                    field_strs.append(f"+{len(fields) - 8}more")

                lines.append(f"  {vis}struct {s['name']}{generics}|{file_short}({','.join(field_strs)}){derives_str}{tuple_str}")

        # Enums
        if hasattr(matrix, 'rust_enums') and matrix.rust_enums:
            lines.append("# Enums")
            for e in matrix.rust_enums:
                file_short = e.get('file', '').split('/')[-1]
                vis = f"{e['visibility']} " if e.get('visibility') and e['visibility'] != 'pub' else "pub " if e.get('visibility') == 'pub' else ""
                generics = f"<{','.join(e['generic_params'])}>" if e.get('generic_params') else ""
                derives_str = f"|#[derive({','.join(e['derives'][:5])})]" if e.get('derives') else ""

                variants = e.get('variants', [])
                variant_strs = []
                for v in variants[:8]:
                    kind_str = f"({v['kind']})" if v.get('kind') and v['kind'] != 'unit' else ""
                    variant_strs.append(f"{v['name']}{kind_str}")
                if len(variants) > 8:
                    variant_strs.append(f"+{len(variants) - 8}more")

                lines.append(f"  {vis}enum {e['name']}{generics}|{file_short}[{','.join(variant_strs)}]{derives_str}")

        # Traits
        if hasattr(matrix, 'rust_traits') and matrix.rust_traits:
            lines.append("# Traits")
            for t in matrix.rust_traits:
                file_short = t.get('file', '').split('/')[-1]
                vis = f"{t['visibility']} " if t.get('visibility') and t['visibility'] != 'pub' else "pub " if t.get('visibility') == 'pub' else ""
                unsafe_str = "unsafe " if t.get('is_unsafe') else ""
                generics = f"<{','.join(t['generic_params'])}>" if t.get('generic_params') else ""
                supers = f" : {' + '.join(t['super_traits'][:3])}" if t.get('super_traits') else ""

                methods = t.get('methods', [])
                meth_strs = []
                for m in methods[:8]:
                    async_str = "async " if m.get('is_async') else ""
                    default_str = "=default" if m.get('has_default') else ""
                    meth_strs.append(f"{async_str}{m['name']}{default_str}")
                if len(methods) > 8:
                    meth_strs.append(f"+{len(methods) - 8}more")

                lines.append(f"  {vis}{unsafe_str}trait {t['name']}{generics}{supers}|{file_short}|methods:[{','.join(meth_strs)}]")

        # Type aliases
        if hasattr(matrix, 'rust_type_aliases') and matrix.rust_type_aliases:
            lines.append("# Type Aliases")
            for a in matrix.rust_type_aliases:
                file_short = a.get('file', '').split('/')[-1]
                generics = f"<{','.join(a['generic_params'])}>" if a.get('generic_params') else ""
                lines.append(f"  type {a['name']}{generics} = {a.get('target_type', '?')}|{file_short}")

        # Impl blocks
        if hasattr(matrix, 'rust_impls') and matrix.rust_impls:
            lines.append(f"# Impl Blocks ({len(matrix.rust_impls)})")
            for impl in matrix.rust_impls[:30]:
                file_short = impl.get('file', '').split('/')[-1]
                trait_str = f" {impl['trait_name']} for" if impl.get('trait_name') else ""
                unsafe_str = "unsafe " if impl.get('is_unsafe') else ""
                methods = impl.get('methods', [])
                meth_strs = methods[:8] if isinstance(methods, list) and methods and isinstance(methods[0], str) else [m.get('name', '') for m in methods[:8]] if methods else []
                if len(methods) > 8:
                    meth_strs.append(f"+{len(methods) - 8}more")
                lines.append(f"  {unsafe_str}impl{trait_str} {impl['type_name']}|{file_short}|[{','.join(meth_strs)}]")
            if len(matrix.rust_impls) > 30:
                lines.append(f"  # ... and {len(matrix.rust_impls) - 30} more impl blocks")

        return lines

    def _compress_rust_api(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress Rust API endpoints, gRPC services, GraphQL types."""
        lines = []

        # HTTP routes
        if hasattr(matrix, 'rust_routes') and matrix.rust_routes:
            # Group by framework
            by_framework = {}
            for route in matrix.rust_routes:
                fw = route.get('framework', 'unknown')
                if fw not in by_framework:
                    by_framework[fw] = []
                by_framework[fw].append(route)

            for fw, routes in by_framework.items():
                lines.append(f"# {fw} ({len(routes)} routes)")
                for route in routes[:30]:
                    file_short = route.get('file', '').split('/')[-1]
                    lines.append(f"  {route['method']} {route['path']}→{route['handler']}|{file_short}")
                if len(routes) > 30:
                    lines.append(f"  # ... and {len(routes) - 30} more routes")

        # gRPC services
        if hasattr(matrix, 'rust_grpc_services') and matrix.rust_grpc_services:
            lines.append("# Tonic gRPC Services")
            for svc in matrix.rust_grpc_services:
                file_short = svc.get('file', '').split('/')[-1]
                methods = svc.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                lines.append(f"  grpc {svc['name']}{meth_str}|{file_short}")

        # GraphQL types
        if hasattr(matrix, 'rust_graphql_types') and matrix.rust_graphql_types:
            lines.append("# async-graphql Types")
            for gql in matrix.rust_graphql_types:
                file_short = gql.get('file', '').split('/')[-1]
                fields = gql.get('fields', [])
                field_str = f"|fields:[{','.join(fields[:5])}]" if fields else ""
                lines.append(f"  {gql['kind']} {gql['name']}{field_str}|{file_short}")

        return lines

    def _compress_rust_functions(self, matrix) -> List[str]:
        """Compress Rust functions and methods."""
        lines = []

        # Functions
        if hasattr(matrix, 'rust_functions') and matrix.rust_functions:
            lines.append(f"# Functions ({len(matrix.rust_functions)} total)")
            for func in matrix.rust_functions[:40]:
                file_short = func.get('file', '').split('/')[-1]
                params = func.get('params', [])
                param_strs = [f"{p.get('name', '')}:{p.get('type', '?')}" for p in params[:4]]
                if len(params) > 4:
                    param_strs.append(f"+{len(params) - 4}")

                qualifiers = []
                if func.get('is_async'):
                    qualifiers.append('async')
                if func.get('is_unsafe'):
                    qualifiers.append('unsafe')
                if func.get('is_const'):
                    qualifiers.append('const')
                if func.get('is_test'):
                    qualifiers.append('test')
                qual_str = ' '.join(qualifiers) + ' ' if qualifiers else ''
                vis = f"{func['visibility']} " if func.get('visibility') else ""
                ret_str = f" -> {func['return_type']}" if func.get('return_type') else ""
                generics = f"<{','.join(func['generic_params'])}>" if func.get('generic_params') else ""

                lines.append(f"  {vis}{qual_str}fn {func['name']}{generics}({','.join(param_strs)}){ret_str}|{file_short}")
            if len(matrix.rust_functions) > 40:
                lines.append(f"  # ... and {len(matrix.rust_functions) - 40} more functions")

        # Methods
        if hasattr(matrix, 'rust_methods') and matrix.rust_methods:
            lines.append(f"# Methods ({len(matrix.rust_methods)} total)")
            for method in matrix.rust_methods[:40]:
                file_short = method.get('file', '').split('/')[-1]
                params = method.get('params', [])
                param_strs = [f"{p.get('name', '')}:{p.get('type', '?')}" for p in params[:4]]
                if len(params) > 4:
                    param_strs.append(f"+{len(params) - 4}")

                qualifiers = []
                if method.get('is_async'):
                    qualifiers.append('async')
                if method.get('is_unsafe'):
                    qualifiers.append('unsafe')
                qual_str = ' '.join(qualifiers) + ' ' if qualifiers else ''
                self_str = f"({method['self_param']})" if method.get('self_param') else ""
                impl_str = f"{method['impl_type']}." if method.get('impl_type') else ""
                ret_str = f" -> {method['return_type']}" if method.get('return_type') else ""

                lines.append(f"  {qual_str}{impl_str}{method['name']}{self_str}({','.join(param_strs)}){ret_str}|{file_short}")
            if len(matrix.rust_methods) > 40:
                lines.append(f"  # ... and {len(matrix.rust_methods) - 40} more methods")

        return lines

    def _compress_rust_models(self, matrix) -> List[str]:
        """Compress Rust database models (Diesel, SeaORM, SQLx)."""
        lines = []

        # ORM models
        if hasattr(matrix, 'rust_models') and matrix.rust_models:
            # Group by ORM
            by_orm = {}
            for model in matrix.rust_models:
                orm = model.get('orm', 'unknown')
                if orm not in by_orm:
                    by_orm[orm] = []
                by_orm[orm].append(model)

            for orm, models in by_orm.items():
                lines.append(f"# {orm} Models ({len(models)})")
                for model in models:
                    file_short = model.get('file', '').split('/')[-1]
                    table_str = f"|table:{model['table_name']}" if model.get('table_name') else ""
                    query_str = "|Queryable" if model.get('is_queryable') else ""
                    insert_str = "|Insertable" if model.get('is_insertable') else ""
                    fields = model.get('fields', [])
                    field_strs = [f"{f.get('name', '')}:{f.get('type', '?')}" for f in fields[:8]]
                    if len(fields) > 8:
                        field_strs.append(f"+{len(fields) - 8}more")
                    lines.append(f"  {model['name']}{table_str}{query_str}{insert_str}|{file_short}({','.join(field_strs)})")

        # Schema definitions
        if hasattr(matrix, 'rust_schemas') and matrix.rust_schemas:
            lines.append("# Schema Tables")
            for schema in matrix.rust_schemas:
                file_short = schema.get('file', '').split('/')[-1]
                cols = schema.get('columns', [])
                col_strs = [f"{c.get('name', '')}:{c.get('type', '?')}" for c in cols[:8]]
                if len(cols) > 8:
                    col_strs.append(f"+{len(cols) - 8}more")
                lines.append(f"  table!({schema['table_name']})|{file_short}|cols:[{','.join(col_strs)}]")

        return lines

    def _compress_rust_dependencies(self, matrix) -> List[str]:
        """Compress Rust Cargo.toml dependencies."""
        lines = []

        if hasattr(matrix, 'rust_dependencies') and matrix.rust_dependencies:
            deps = matrix.rust_dependencies

            # Crate metadata
            if deps.get('_crate_name'):
                lines.append(f"# Crate: {deps['_crate_name']} v{deps.get('_version', '?')} (edition {deps.get('_edition', '?')})")

            # Features
            features = deps.get('_features', {})
            if features:
                feat_strs = [f"{k}=[{','.join(v[:3])}]" for k, v in list(features.items())[:5]]
                lines.append(f"# Features: {' | '.join(feat_strs)}")

            # Workspace
            members = deps.get('_workspace_members', [])
            if members:
                lines.append(f"# Workspace: {', '.join(members[:10])}")

            # Regular dependencies
            dep_lines = []
            dev_dep_lines = []
            for name, version in sorted(deps.items()):
                if name.startswith('_'):
                    continue
                if name.startswith('dev:'):
                    dev_dep_lines.append(f"  {name[4:]}@{version}")
                else:
                    dep_lines.append(f"  {name}@{version}")

            if dep_lines:
                lines.append(f"# Dependencies ({len(dep_lines)})")
                lines.extend(dep_lines[:30])
                if len(dep_lines) > 30:
                    lines.append(f"  # ... and {len(dep_lines) - 30} more")

            if dev_dep_lines:
                lines.append(f"# Dev Dependencies ({len(dev_dep_lines)})")
                lines.extend(dev_dep_lines[:10])

        # Detected frameworks
        if hasattr(matrix, 'rust_detected_frameworks') and matrix.rust_detected_frameworks:
            lines.append(f"# Detected: {', '.join(matrix.rust_detected_frameworks[:15])}")

        # Modules
        if hasattr(matrix, 'rust_modules') and matrix.rust_modules:
            lines.append(f"# Modules ({len(matrix.rust_modules)}): {', '.join(matrix.rust_modules[:15])}")

        # Macro definitions
        if hasattr(matrix, 'rust_macros_defined') and matrix.rust_macros_defined:
            lines.append(f"# Macros: {', '.join(matrix.rust_macros_defined[:10])}")

        return lines

