    # ============================================
    # v4.15: SQL Compression Methods
    # ============================================

    def _compress_sql_tables(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress SQL table definitions."""
        lines = []
        if not hasattr(matrix, 'sql_tables') or not matrix.sql_tables:
            return lines

        # Detected dialects header
        if hasattr(matrix, 'sql_detected_dialects') and matrix.sql_detected_dialects:
            lines.append(f"# Dialects: {', '.join(matrix.sql_detected_dialects)}")

        # Group by schema
        by_schema = {}
        for table in matrix.sql_tables:
            schema = table.get('schema', 'public') or 'public'
            if schema not in by_schema:
                by_schema[schema] = []
            by_schema[schema].append(table)

        for schema, tables in by_schema.items():
            if len(by_schema) > 1:
                lines.append(f"# Schema: {schema} ({len(tables)} tables)")
            for table in tables[:60]:
                file_short = table.get('file', '').split('/')[-1]
                cols = table.get('columns', [])
                col_count = table.get('column_count', len(cols))

                # Column summaries (compact: name:type with PK marker)
                col_strs = []
                for c in cols[:10]:
                    pk = "*" if c.get('primary_key') else ""
                    nullable = "?" if c.get('nullable', True) and not c.get('primary_key') else ""
                    col_strs.append(f"{pk}{c.get('name', '')}:{c.get('type', '?')}{nullable}")
                if col_count > 10:
                    col_strs.append(f"+{col_count - 10}")

                flags = []
                if table.get('is_temporary'):
                    flags.append("TEMP")
                if table.get('is_unlogged'):
                    flags.append("UNLOGGED")
                flag_str = f"|{'|'.join(flags)}" if flags else ""

                lines.append(f"  {table['name']}({','.join(col_strs)}){flag_str}|{file_short}")

            if len(tables) > 60:
                lines.append(f"  # ... and {len(tables) - 60} more tables")

        # Custom types
        if hasattr(matrix, 'sql_custom_types') and matrix.sql_custom_types:
            lines.append(f"# Custom Types ({len(matrix.sql_custom_types)})")
            for ct in matrix.sql_custom_types[:15]:
                file_short = ct.get('file', '').split('/')[-1]
                vals = ct.get('values', [])
                val_str = f"[{','.join(vals[:6])}]" if vals else ""
                lines.append(f"  {ct['name']}|{ct.get('kind', 'enum')}{val_str}|{file_short}")

        # Domains
        if hasattr(matrix, 'sql_domains') and matrix.sql_domains:
            lines.append(f"# Domains ({len(matrix.sql_domains)})")
            for dom in matrix.sql_domains[:10]:
                file_short = dom.get('file', '').split('/')[-1]
                lines.append(f"  {dom['name']}|{dom.get('base_type', '?')}|{file_short}")

        # Sequences
        if hasattr(matrix, 'sql_sequences') and matrix.sql_sequences:
            lines.append(f"# Sequences ({len(matrix.sql_sequences)})")
            for seq in matrix.sql_sequences[:10]:
                file_short = seq.get('file', '').split('/')[-1]
                lines.append(f"  {seq['name']}|{seq.get('data_type', 'bigint')}|{file_short}")

        # Schemas
        if hasattr(matrix, 'sql_schemas') and matrix.sql_schemas:
            lines.append(f"# Schemas: {', '.join(s['name'] for s in matrix.sql_schemas[:15])}")

        return lines

    def _compress_sql_views(self, matrix) -> List[str]:
        """Compress SQL views and materialized views."""
        lines = []

        if hasattr(matrix, 'sql_views') and matrix.sql_views:
            lines.append(f"# Views ({len(matrix.sql_views)})")
            for view in matrix.sql_views[:30]:
                file_short = view.get('file', '').split('/')[-1]
                deps = view.get('dependencies', [])
                dep_str = f"|deps:[{','.join(deps[:5])}]" if deps else ""
                lines.append(f"  {view['name']}{dep_str}|{file_short}")

        if hasattr(matrix, 'sql_materialized_views') and matrix.sql_materialized_views:
            lines.append(f"# Materialized Views ({len(matrix.sql_materialized_views)})")
            for mv in matrix.sql_materialized_views[:15]:
                file_short = mv.get('file', '').split('/')[-1]
                refresh = mv.get('refresh_type', '')
                refresh_str = f"|refresh:{refresh}" if refresh else ""
                lines.append(f"  {mv['name']}{refresh_str}|{file_short}")

        return lines

    def _compress_sql_functions(self, matrix) -> List[str]:
        """Compress SQL functions, stored procedures, triggers."""
        lines = []

        # Functions
        if hasattr(matrix, 'sql_functions') and matrix.sql_functions:
            lines.append(f"# Functions ({len(matrix.sql_functions)})")
            for func in matrix.sql_functions[:40]:
                file_short = func.get('file', '').split('/')[-1]
                params = func.get('parameters', [])
                param_strs = [f"{p.get('name', '')}:{p.get('type', '?')}" for p in params[:5]]
                if len(params) > 5:
                    param_strs.append(f"+{len(params) - 5}")
                ret_str = f" -> {func['return_type']}" if func.get('return_type') else ""
                lang = func.get('language', '')
                lang_str = f"|{lang}" if lang else ""
                lines.append(f"  {func['name']}({','.join(param_strs)}){ret_str}{lang_str}|{file_short}")

        # Stored procedures
        if hasattr(matrix, 'sql_stored_procedures') and matrix.sql_stored_procedures:
            lines.append(f"# Stored Procedures ({len(matrix.sql_stored_procedures)})")
            for proc in matrix.sql_stored_procedures[:30]:
                file_short = proc.get('file', '').split('/')[-1]
                params = proc.get('parameters', [])
                param_strs = [f"{p.get('name', '')}:{p.get('type', '?')}" for p in params[:5]]
                if len(params) > 5:
                    param_strs.append(f"+{len(params) - 5}")
                flags = []
                if proc.get('has_transaction'):
                    flags.append("TXN")
                if proc.get('has_exception_handling'):
                    flags.append("EXH")
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"  PROC {proc['name']}({','.join(param_strs)}){flag_str}|{file_short}")

        # Triggers
        if hasattr(matrix, 'sql_triggers') and matrix.sql_triggers:
            lines.append(f"# Triggers ({len(matrix.sql_triggers)})")
            for trig in matrix.sql_triggers[:20]:
                file_short = trig.get('file', '').split('/')[-1]
                events = trig.get('events', [])
                timing = trig.get('timing', '')
                lines.append(f"  {trig['name']}|{timing} {'/'.join(events)} ON {trig.get('table', '?')}|{file_short}")

        # Events
        if hasattr(matrix, 'sql_events') and matrix.sql_events:
            lines.append(f"# Events ({len(matrix.sql_events)})")
            for evt in matrix.sql_events[:10]:
                file_short = evt.get('file', '').split('/')[-1]
                lines.append(f"  {evt['name']}|{evt.get('schedule', '')}|{file_short}")

        return lines

    def _compress_sql_indexes(self, matrix) -> List[str]:
        """Compress SQL indexes and constraints."""
        lines = []

        if hasattr(matrix, 'sql_indexes') and matrix.sql_indexes:
            lines.append(f"# Indexes ({len(matrix.sql_indexes)})")
            for idx in matrix.sql_indexes[:40]:
                file_short = idx.get('file', '').split('/')[-1]
                cols = idx.get('columns', [])
                unique_str = "UNIQUE " if idx.get('is_unique') else ""
                type_str = idx.get('index_type', '')
                type_str = f"|{type_str}" if type_str and type_str != 'btree' else ""
                concurrent = "|CONCURRENT" if idx.get('is_concurrent') else ""
                lines.append(f"  {unique_str}{idx['name']} ON {idx.get('table', '?')}({','.join(cols[:6])}){type_str}{concurrent}|{file_short}")
            if len(matrix.sql_indexes) > 40:
                lines.append(f"  # ... and {len(matrix.sql_indexes) - 40} more indexes")

        # Foreign keys
        if hasattr(matrix, 'sql_foreign_keys') and matrix.sql_foreign_keys:
            lines.append(f"# Foreign Keys ({len(matrix.sql_foreign_keys)})")
            for fk in matrix.sql_foreign_keys[:30]:
                from_cols = ','.join(fk.get('from_columns', [])[:3])
                to_cols = ','.join(fk.get('to_columns', [])[:3])
                on_del = fk.get('on_delete', '')
                del_str = f"|ON DELETE {on_del}" if on_del and on_del != 'NO ACTION' else ""
                lines.append(f"  {fk.get('from_table', '?')}({from_cols}) -> {fk.get('to_table', '?')}({to_cols}){del_str}")

        # Constraints
        if hasattr(matrix, 'sql_constraints') and matrix.sql_constraints:
            lines.append(f"# Constraints ({len(matrix.sql_constraints)})")
            for con in matrix.sql_constraints[:20]:
                cols = ','.join(con.get('columns', [])[:4])
                lines.append(f"  {con.get('constraint_type', '?')} {con['name']} ON {con.get('table', '?')}({cols})")

        # Partitions
        if hasattr(matrix, 'sql_partitions') and matrix.sql_partitions:
            lines.append(f"# Partitions ({len(matrix.sql_partitions)})")
            for part in matrix.sql_partitions[:10]:
                key_cols = ','.join(part.get('key_columns', [])[:3])
                lines.append(f"  {part.get('parent_table', '?')}|{part.get('strategy', '?')}({key_cols})")

        return lines

    def _compress_sql_security(self, matrix) -> List[str]:
        """Compress SQL security (roles, grants, RLS)."""
        lines = []

        if hasattr(matrix, 'sql_roles') and matrix.sql_roles:
            lines.append(f"# Roles ({len(matrix.sql_roles)})")
            for role in matrix.sql_roles[:15]:
                opts = ', '.join(role.get('options', [])[:4])
                opt_str = f"|{opts}" if opts else ""
                lines.append(f"  {role['name']}{opt_str}")

        if hasattr(matrix, 'sql_grants') and matrix.sql_grants:
            # Group by grantee
            by_grantee = {}
            for grant in matrix.sql_grants:
                grantee = grant.get('grantee', '?')
                if grantee not in by_grantee:
                    by_grantee[grantee] = []
                by_grantee[grantee].append(grant)

            lines.append(f"# Grants ({len(matrix.sql_grants)})")
            for grantee, grants in list(by_grantee.items())[:10]:
                privs = set()
                objects = set()
                for g in grants:
                    privs.add(g.get('privilege', '?'))
                    objects.add(f"{g.get('object_type', '')}:{g.get('object_name', '')}")
                lines.append(f"  {grantee}|{','.join(list(privs)[:5])}|on {len(objects)} objects")

        if hasattr(matrix, 'sql_rls_policies') and matrix.sql_rls_policies:
            lines.append(f"# RLS Policies ({len(matrix.sql_rls_policies)})")
            for pol in matrix.sql_rls_policies[:10]:
                perm = "PERMISSIVE" if pol.get('permissive', True) else "RESTRICTIVE"
                cmd = pol.get('command', 'ALL')
                lines.append(f"  {pol['name']}|{perm} {cmd} ON {pol.get('table', '?')}")

        return lines

    def _compress_sql_migrations(self, matrix) -> List[str]:
        """Compress SQL migration information."""
        lines = []
        if not hasattr(matrix, 'sql_migrations') or not matrix.sql_migrations:
            return lines

        # Group by framework
        by_fw = {}
        for mig in matrix.sql_migrations:
            fw = mig.get('framework', 'unknown')
            if fw not in by_fw:
                by_fw[fw] = []
            by_fw[fw].append(mig)

        for fw, migs in by_fw.items():
            lines.append(f"# {fw} ({len(migs)} migrations)")
            for mig in migs[:20]:
                file_short = mig.get('file', '').split('/')[-1]
                ver = mig.get('version', '')
                desc = mig.get('description', '')[:40]
                dir_str = mig.get('direction', '')
                created = ','.join(mig.get('tables_created', [])[:3])
                dropped = ','.join(mig.get('tables_dropped', [])[:2])

                flags = []
                if mig.get('has_data_migration'):
                    flags.append("DATA")
                if mig.get('is_idempotent'):
                    flags.append("IDMPT")
                if mig.get('has_transaction'):
                    flags.append("TXN")
                flag_str = f"|{'|'.join(flags)}" if flags else ""

                create_str = f"|+[{created}]" if created else ""
                drop_str = f"|-[{dropped}]" if dropped else ""
                lines.append(f"  {ver}|{dir_str}|{desc}{create_str}{drop_str}{flag_str}|{file_short}")

            if len(migs) > 20:
                lines.append(f"  # ... and {len(migs) - 20} more migrations")

        return lines

    def _compress_sql_dependencies(self, matrix) -> List[str]:
        """Compress SQL dependency references and frameworks."""
        lines = []

        if hasattr(matrix, 'sql_detected_frameworks') and matrix.sql_detected_frameworks:
            lines.append(f"# Frameworks/Extensions: {', '.join(matrix.sql_detected_frameworks[:15])}")

        if hasattr(matrix, 'sql_dependencies') and matrix.sql_dependencies:
            deps = matrix.sql_dependencies[:40]
            lines.append(f"# Referenced Objects ({len(matrix.sql_dependencies)}): {', '.join(deps)}")
            if len(matrix.sql_dependencies) > 40:
                lines.append(f"  # ... and {len(matrix.sql_dependencies) - 40} more")

        return lines

    # ============================================
    # v4.16: HTML Compress Methods
    # ============================================

    def _compress_html_structure(self, matrix) -> List[str]:
        """Compress HTML document structure (documents, headings, landmarks)."""
        lines = []
        if not hasattr(matrix, 'html_documents') or not matrix.html_documents:
            return lines

        # Detected frameworks
        if hasattr(matrix, 'html_detected_frameworks') and matrix.html_detected_frameworks:
            lines.append(f"# Frameworks: {', '.join(matrix.html_detected_frameworks[:15])}")

        # Template engines
        if hasattr(matrix, 'html_template_engines') and matrix.html_template_engines:
            lines.append(f"# Template Engines: {', '.join(matrix.html_template_engines[:10])}")

        for doc in matrix.html_documents[:30]:
            file_short = doc.get('file', '').split('/')[-1]
            version = doc.get('html_version', '?')
            title = doc.get('title', '')[:40]
            lang = doc.get('lang', '')
            charset = doc.get('charset', '')
            total_el = doc.get('total_elements', 0)

            flags = []
            if doc.get('has_html5_doctype'):
                flags.append("HTML5")
            if doc.get('has_viewport_meta'):
                flags.append("responsive")
            flag_str = f"|{'|'.join(flags)}" if flags else ""

            lines.append(f"  {file_short}|v={version}|lang={lang}|charset={charset}|el={total_el}{flag_str}")
            if title:
                lines.append(f"    title={title}")

            # Headings summary
            headings = doc.get('headings', [])
            if headings:
                h_counts = {}
                for h in headings:
                    lvl = f"h{h.get('level', '?')}"
                    h_counts[lvl] = h_counts.get(lvl, 0) + 1
                h_str = ','.join(f"{k}:{v}" for k, v in sorted(h_counts.items()))
                lines.append(f"    headings={h_str}")

            # Landmarks
            landmarks = doc.get('landmarks', [])
            if landmarks:
                lm_tags = [l.get('tag', '') for l in landmarks[:10]]
                lines.append(f"    landmarks={','.join(lm_tags)}")

        if len(matrix.html_documents) > 30:
            lines.append(f"  # ... and {len(matrix.html_documents) - 30} more documents")

        return lines

    def _compress_html_forms(self, matrix) -> List[str]:
        """Compress HTML form definitions."""
        lines = []
        if not hasattr(matrix, 'html_forms') or not matrix.html_forms:
            return lines

        for form in matrix.html_forms[:25]:
            file_short = form.get('file', '').split('/')[-1]
            action = form.get('action', '')[:40]
            method = form.get('method', 'get').upper()
            name = form.get('name') or form.get('id') or 'anon'
            inputs = form.get('inputs', [])

            flags = []
            if form.get('has_csrf_token'):
                flags.append("CSRF")
            if form.get('has_file_upload'):
                flags.append("FILE")
            if form.get('novalidate'):
                flags.append("NOVALIDATE")
            flag_str = f"|{'|'.join(flags)}" if flags else ""

            lines.append(f"  {name}|{method}|action={action}|inputs={len(inputs)}{flag_str}|{file_short}")

            # Input summary
            if inputs:
                type_counts = {}
                required_count = 0
                for inp in inputs:
                    itype = inp.get('type', 'text')
                    type_counts[itype] = type_counts.get(itype, 0) + 1
                    if inp.get('required'):
                        required_count += 1
                type_str = ','.join(f"{k}:{v}" for k, v in sorted(type_counts.items()))
                lines.append(f"    types={type_str}|required={required_count}")

            # Fieldsets
            fieldsets = form.get('fieldsets', [])
            if fieldsets:
                fs_strs = [f.get('legend', 'anon') for f in fieldsets[:5]]
                lines.append(f"    fieldsets={','.join(fs_strs)}")

        if len(matrix.html_forms) > 25:
            lines.append(f"  # ... and {len(matrix.html_forms) - 25} more forms")

        return lines

    def _compress_html_meta(self, matrix) -> List[str]:
        """Compress HTML meta, OG, JSON-LD, and link data."""
        lines = []
        has_content = False

        # Open Graph
        if hasattr(matrix, 'html_open_graph') and matrix.html_open_graph:
            has_content = True
            lines.append("  # Open Graph")
            for og in matrix.html_open_graph[:10]:
                file_short = og.get('file', '').split('/')[-1]
                og_type = og.get('type', '')
                og_title = og.get('title', '')[:30]
                lines.append(f"    og:{og_type}|{og_title}|{file_short}")

        # JSON-LD
        if hasattr(matrix, 'html_json_ld') and matrix.html_json_ld:
            has_content = True
            lines.append(f"  # JSON-LD ({len(matrix.html_json_ld)})")
            for ld in matrix.html_json_ld[:10]:
                file_short = ld.get('file', '').split('/')[-1]
                schema_type = ld.get('type', '')
                name = ld.get('name', '')[:30]
                lines.append(f"    @type={schema_type}|name={name}|{file_short}")

        # Aggregated meta summary
        if hasattr(matrix, 'html_metas') and matrix.html_metas:
            has_content = True
            # Group by type
            meta_names = set()
            meta_props = set()
            for m in matrix.html_metas:
                if m.get('name'):
                    meta_names.add(m['name'])
                if m.get('property'):
                    meta_props.add(m['property'])
            if meta_names:
                lines.append(f"  # Meta names: {', '.join(sorted(meta_names)[:15])}")
            if meta_props:
                lines.append(f"  # Meta properties: {', '.join(sorted(meta_props)[:15])}")

        # Links summary
        if hasattr(matrix, 'html_links') and matrix.html_links:
            has_content = True
            link_types = {}
            for link in matrix.html_links:
                lt = link.get('type', 'other')
                link_types[lt] = link_types.get(lt, 0) + 1
            lt_str = ','.join(f"{k}:{v}" for k, v in sorted(link_types.items()))
            lines.append(f"  # Links: {lt_str}")

        if not has_content:
            return []
        return lines

    def _compress_html_accessibility(self, matrix) -> List[str]:
        """Compress HTML accessibility issues and stats."""
        lines = []
        has_content = False

        # A11y stats summary
        if hasattr(matrix, 'html_a11y_stats') and matrix.html_a11y_stats:
            has_content = True
            total_issues = sum(s.get('total_issues', 0) for s in matrix.html_a11y_stats)
            total_critical = sum(s.get('critical_count', 0) for s in matrix.html_a11y_stats)
            total_warning = sum(s.get('warning_count', 0) for s in matrix.html_a11y_stats)
            files_scanned = len(matrix.html_a11y_stats)
            lines.append(f"  # Summary: {files_scanned} files, {total_issues} issues (critical={total_critical}, warning={total_warning})")

        # Issues grouped by severity
        if hasattr(matrix, 'html_a11y_issues') and matrix.html_a11y_issues:
            has_content = True
            by_severity = {}
            for issue in matrix.html_a11y_issues:
                sev = issue.get('severity', 'info')
                if sev not in by_severity:
                    by_severity[sev] = []
                by_severity[sev].append(issue)

            for sev in ['critical', 'warning', 'info']:
                issues = by_severity.get(sev, [])
                if not issues:
                    continue
                lines.append(f"  # {sev.upper()} ({len(issues)})")
                # Group by rule
                by_rule = {}
                for iss in issues:
                    rule = iss.get('rule', 'unknown')
                    if rule not in by_rule:
                        by_rule[rule] = []
                    by_rule[rule].append(iss)
                for rule, rule_issues in list(by_rule.items())[:10]:
                    file_short = rule_issues[0].get('file', '').split('/')[-1]
                    msg = rule_issues[0].get('message', '')[:50]
                    count_str = f" (x{len(rule_issues)})" if len(rule_issues) > 1 else ""
                    lines.append(f"    {rule}{count_str}|{msg}|{file_short}")

        if not has_content:
            return []
        return lines

    def _compress_html_assets(self, matrix) -> List[str]:
        """Compress HTML scripts, styles, and preload hints."""
        lines = []
        has_content = False

        # Scripts
        if hasattr(matrix, 'html_scripts') and matrix.html_scripts:
            has_content = True
            external = [s for s in matrix.html_scripts if s.get('src')]
            inline = [s for s in matrix.html_scripts if s.get('is_inline')]
            modules = [s for s in matrix.html_scripts if s.get('is_module')]

            lines.append(f"  # Scripts: {len(matrix.html_scripts)} total (external={len(external)}, inline={len(inline)}, modules={len(modules)})")
            for script in external[:15]:
                file_short = script.get('file', '').split('/')[-1]
                src = script.get('src', '')[:50]
                flags = []
                if script.get('is_async'):
                    flags.append("async")
                if script.get('is_defer'):
                    flags.append("defer")
                if script.get('is_module'):
                    flags.append("module")
                if script.get('integrity'):
                    flags.append("SRI")
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    src={src}{flag_str}|{file_short}")

        # Styles
        if hasattr(matrix, 'html_styles') and matrix.html_styles:
            has_content = True
            external_css = [s for s in matrix.html_styles if s.get('href')]
            inline_css = [s for s in matrix.html_styles if s.get('is_inline')]
            lines.append(f"  # Styles: {len(matrix.html_styles)} total (external={len(external_css)}, inline={len(inline_css)})")
            for style in external_css[:10]:
                file_short = style.get('file', '').split('/')[-1]
                href = style.get('href', '')[:50]
                lines.append(f"    href={href}|{file_short}")

        # Preloads
        if hasattr(matrix, 'html_preloads') and matrix.html_preloads:
            has_content = True
            hint_types = {}
            for p in matrix.html_preloads:
                ht = p.get('type', 'preload')
                hint_types[ht] = hint_types.get(ht, 0) + 1
            ht_str = ','.join(f"{k}:{v}" for k, v in sorted(hint_types.items()))
            lines.append(f"  # Resource hints: {ht_str}")

        if not has_content:
            return []
        return lines

    def _compress_html_components(self, matrix) -> List[str]:
        """Compress HTML Web Components and custom elements."""
        lines = []
        if not hasattr(matrix, 'html_custom_elements') or not matrix.html_custom_elements:
            return lines

        for elem in matrix.html_custom_elements[:20]:
            file_short = elem.get('file', '').split('/')[-1]
            tag = elem.get('tag_name', '')
            flags = []
            if elem.get('is_autonomous'):
                flags.append("autonomous")
            if elem.get('extends'):
                flags.append(f"extends={elem['extends']}")
            if elem.get('shadow_dom'):
                flags.append("shadow")
            if elem.get('registered_class'):
                flags.append(f"class={elem['registered_class']}")
            flag_str = f"|{'|'.join(flags)}" if flags else ""

            attrs = elem.get('attributes', [])
            attr_str = f"|attrs={','.join(attrs[:5])}" if attrs else ""
            lines.append(f"  <{tag}>{flag_str}{attr_str}|{file_short}")

        if len(matrix.html_custom_elements) > 20:
            lines.append(f"  # ... and {len(matrix.html_custom_elements) - 20} more custom elements")

        return lines

    def _compress_html_templates(self, matrix) -> List[str]:
        """Compress HTML template engine data."""
        lines = []
        if not hasattr(matrix, 'html_templates') or not matrix.html_templates:
            return lines

        # Group by engine
        by_engine = {}
        for tmpl in matrix.html_templates:
            engine = tmpl.get('engine', 'unknown')
            if engine not in by_engine:
                by_engine[engine] = []
            by_engine[engine].append(tmpl)

        for engine, tmpls in by_engine.items():
            avg_conf = sum(t.get('confidence', 0) for t in tmpls) / len(tmpls)
            lines.append(f"  # {engine} ({len(tmpls)} files, confidence={avg_conf:.0%})")

            for tmpl in tmpls[:10]:
                file_short = tmpl.get('file', '').split('/')[-1]
                blocks = tmpl.get('block_count', 0)
                extends = tmpl.get('extends', '')
                includes = tmpl.get('includes', [])
                macros = tmpl.get('macros', [])
                variables = tmpl.get('variables', [])

                parts = [f"blocks={blocks}"]
                if extends:
                    parts.append(f"extends={extends[:30]}")
                if includes:
                    parts.append(f"includes={len(includes)}")
                if macros:
                    parts.append(f"macros={','.join(macros[:3])}")
                if variables:
                    parts.append(f"vars={len(variables)}")

                lines.append(f"    {file_short}|{'|'.join(parts)}")

            if len(tmpls) > 10:
                lines.append(f"    # ... and {len(tmpls) - 10} more {engine} files")

        return lines

    # ============================================
    # v4.17: CSS Compressor Methods
    # ============================================

    def _compress_css_selectors(self, matrix) -> List[str]:
        """Compress CSS selector data (rules, specificity, nesting)."""
        lines = []
        if not hasattr(matrix, 'css_selectors') or not matrix.css_selectors:
            return lines

        # Features and preprocessors summary
        if hasattr(matrix, 'css_detected_features') and matrix.css_detected_features:
            lines.append(f"# Features: {', '.join(matrix.css_detected_features[:20])}")
        if hasattr(matrix, 'css_detected_preprocessors') and matrix.css_detected_preprocessors:
            lines.append(f"# Preprocessors: {', '.join(matrix.css_detected_preprocessors)}")

        # Group by file
        by_file: dict = {}
        for sel in matrix.css_selectors:
            f = sel.get('file', '').split('/')[-1]
            if f not in by_file:
                by_file[f] = []
            by_file[f].append(sel)

        for fname, sels in list(by_file.items())[:20]:
            type_counts: dict = {}
            nested = sum(1 for s in sels if s.get('is_nested'))
            for s in sels:
                st = s.get('type', 'other')
                type_counts[st] = type_counts.get(st, 0) + 1
            type_str = ','.join(f"{k}:{v}" for k, v in sorted(type_counts.items()))
            nest_str = f"|nested={nested}" if nested else ""
            lines.append(f"  {fname}|selectors={len(sels)}|{type_str}{nest_str}")

        total = len(matrix.css_selectors)
        if total > 0:
            nested_total = sum(1 for s in matrix.css_selectors if s.get('is_nested'))
            lines.append(f"  # Total: {total} selectors, {nested_total} nested")
        if len(by_file) > 20:
            lines.append(f"  # ... and {len(by_file) - 20} more CSS files")

        return lines

    def _compress_css_variables(self, matrix) -> List[str]:
        """Compress CSS custom properties and themes."""
        lines = []
        has_content = False

        # Themes
        if hasattr(matrix, 'css_themes') and matrix.css_themes:
            has_content = True
            lines.append("  # Themes")
            for theme in matrix.css_themes[:10]:
                file_short = theme.get('file', '').split('/')[-1]
                name = theme.get('name', 'anon')
                var_count = theme.get('variable_count', 0)
                sel = theme.get('selector', '')[:40]
                lines.append(f"    {name}|vars={var_count}|selector={sel}|{file_short}")

        # Variables grouped by category
        if hasattr(matrix, 'css_variables') and matrix.css_variables:
            has_content = True
            by_category: dict = {}
            for v in matrix.css_variables:
                cat = v.get('category', 'other')
                if cat not in by_category:
                    by_category[cat] = []
                by_category[cat].append(v)

            for cat, vars_list in sorted(by_category.items()):
                lines.append(f"  # {cat} ({len(vars_list)})")
                for v in vars_list[:8]:
                    name = v.get('name', '')[:30]
                    value = v.get('value', '')[:30]
                    scope = v.get('scope', '')
                    scope_str = f"|scope={scope}" if scope != ':root' else ""
                    lines.append(f"    {name}={value}{scope_str}")
                if len(vars_list) > 8:
                    lines.append(f"    # ... and {len(vars_list) - 8} more")

        if not has_content:
            return []
        return lines

    def _compress_css_layout(self, matrix) -> List[str]:
        """Compress CSS layout patterns (flexbox, grid, multi-column)."""
        lines = []
        has_content = False

        # Flexbox
        if hasattr(matrix, 'css_flexbox') and matrix.css_flexbox:
            has_content = True
            lines.append(f"  # Flexbox ({len(matrix.css_flexbox)})")
            for fb in matrix.css_flexbox[:15]:
                file_short = fb.get('file', '').split('/')[-1]
                sel = fb.get('selector', '')[:40]
                parts = []
                if fb.get('direction'):
                    parts.append(f"dir={fb['direction']}")
                if fb.get('wrap'):
                    parts.append(f"wrap={fb['wrap']}")
                if fb.get('justify'):
                    parts.append(f"j={fb['justify']}")
                if fb.get('align'):
                    parts.append(f"a={fb['align']}")
                if fb.get('gap'):
                    parts.append(f"gap={fb['gap']}")
                lines.append(f"    {sel}|{'|'.join(parts)}|{file_short}")
            if len(matrix.css_flexbox) > 15:
                lines.append(f"    # ... and {len(matrix.css_flexbox) - 15} more")

        # Grid
        if hasattr(matrix, 'css_grid') and matrix.css_grid:
            has_content = True
            lines.append(f"  # Grid ({len(matrix.css_grid)})")
            for grid in matrix.css_grid[:15]:
                file_short = grid.get('file', '').split('/')[-1]
                sel = grid.get('selector', '')[:40]
                flags = []
                if grid.get('has_subgrid'):
                    flags.append("subgrid")
                if grid.get('has_masonry'):
                    flags.append("masonry")
                col = grid.get('template_columns', '')[:30]
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                col_str = f"|cols={col}" if col else ""
