    def _compress_sass_variables(self, matrix) -> List[str]:
        """Compress Sass $variables, maps, and lists."""
        lines = []
        has_content = False

        # $variables grouped by data type
        if hasattr(matrix, 'sass_variables') and matrix.sass_variables:
            has_content = True
            by_type: dict = {}
            for v in matrix.sass_variables:
                dt = v.get('data_type', 'value')
                if dt not in by_type:
                    by_type[dt] = []
                by_type[dt].append(v)

            for dtype, vars_list in sorted(by_type.items()):
                lines.append(f"  # {dtype} ({len(vars_list)})")
                for v in vars_list[:8]:
                    name = v.get('name', '')[:30]
                    value = v.get('value', '')[:30]
                    flags = []
                    if v.get('is_default'):
                        flags.append("!default")
                    if v.get('is_global'):
                        flags.append("!global")
                    ns = v.get('namespace', '')
                    if ns:
                        flags.append(f"ns={ns}")
                    flag_str = f"|{'|'.join(flags)}" if flags else ""
                    lines.append(f"    ${name}: {value}{flag_str}")
                if len(vars_list) > 8:
                    lines.append(f"    # ... and {len(vars_list) - 8} more")

        # Maps
        if hasattr(matrix, 'sass_maps') and matrix.sass_maps:
            has_content = True
            lines.append(f"  # Maps ({len(matrix.sass_maps)})")
            for m in matrix.sass_maps[:15]:
                name = m.get('name', '')[:30]
                keys = m.get('keys', [])
                keys_str = ','.join(keys[:5])
                nested_str = "|nested" if m.get('is_nested') else ""
                file_short = m.get('file', '').split('/')[-1]
                lines.append(f"    ${name}: ({keys_str}){nested_str}|{file_short}")
            if len(matrix.sass_maps) > 15:
                lines.append(f"    # ... and {len(matrix.sass_maps) - 15} more")

        # Lists
        if hasattr(matrix, 'sass_lists') and matrix.sass_lists:
            has_content = True
            lines.append(f"  # Lists ({len(matrix.sass_lists)})")
            for lst in matrix.sass_lists[:10]:
                name = lst.get('name', '')[:30]
                items = lst.get('items', [])
                sep = lst.get('separator', 'comma')
                bracketed = "[...]" if lst.get('is_bracketed') else "(...)"
                lines.append(f"    ${name}: {bracketed}|{len(items)} items|sep={sep}")
            if len(matrix.sass_lists) > 10:
                lines.append(f"    # ... and {len(matrix.sass_lists) - 10} more")

        if not has_content:
            return []
        return lines

    def _compress_sass_mixins(self, matrix) -> List[str]:
        """Compress Sass @mixin definitions and @include usages."""
        lines = []
        has_content = False

        # Mixin definitions
        if hasattr(matrix, 'sass_mixin_definitions') and matrix.sass_mixin_definitions:
            has_content = True
            lines.append(f"  # Definitions ({len(matrix.sass_mixin_definitions)})")
            for mdef in matrix.sass_mixin_definitions[:20]:
                file_short = mdef.get('file', '').split('/')[-1]
                name = mdef.get('name', '')
                params = mdef.get('parameters', [])
                param_str = f"({','.join(params[:4])})" if params else "()"
                flags = []
                if mdef.get('has_rest_args'):
                    flags.append("...rest")
                if mdef.get('has_content_block'):
                    flags.append("@content")
                if mdef.get('has_defaults'):
                    flags.append("defaults")
                body = mdef.get('body_lines', 0)
                if body:
                    flags.append(f"{body}L")
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    @mixin {name}{param_str}{flag_str}|{file_short}")
            if len(matrix.sass_mixin_definitions) > 20:
                lines.append(f"    # ... and {len(matrix.sass_mixin_definitions) - 20} more")

        # Mixin usages (aggregated by name)
        if hasattr(matrix, 'sass_mixin_usages') and matrix.sass_mixin_usages:
            has_content = True
            usage_counts: dict = {}
            for mu in matrix.sass_mixin_usages:
                name = mu.get('name', '')
                ns = mu.get('namespace', '')
                key = f"{ns}.{name}" if ns else name
                usage_counts[key] = usage_counts.get(key, 0) + 1
            lines.append(f"  # Usages ({len(matrix.sass_mixin_usages)} total)")
            for key, count in sorted(usage_counts.items(), key=lambda x: -x[1])[:15]:
                lines.append(f"    @include {key} x{count}")
            if len(usage_counts) > 15:
                lines.append(f"    # ... and {len(usage_counts) - 15} more unique mixins")

        if not has_content:
            return []
        return lines

    def _compress_sass_functions(self, matrix) -> List[str]:
        """Compress Sass @function definitions and function calls."""
        lines = []
        has_content = False

        # Function definitions
        if hasattr(matrix, 'sass_function_definitions') and matrix.sass_function_definitions:
            has_content = True
            lines.append(f"  # Definitions ({len(matrix.sass_function_definitions)})")
            for fdef in matrix.sass_function_definitions[:15]:
                file_short = fdef.get('file', '').split('/')[-1]
                name = fdef.get('name', '')
                params = fdef.get('parameters', [])
                param_str = f"({','.join(params[:4])})" if params else "()"
                ret = fdef.get('return_count', 0)
                ret_str = f"|returns={ret}" if ret > 1 else ""
                lines.append(f"    @function {name}{param_str}{ret_str}|{file_short}")
            if len(matrix.sass_function_definitions) > 15:
                lines.append(f"    # ... and {len(matrix.sass_function_definitions) - 15} more")

        # Function calls grouped by category
        if hasattr(matrix, 'sass_function_calls') and matrix.sass_function_calls:
            has_content = True
            by_category: dict = {}
            for fc in matrix.sass_function_calls:
                cat = fc.get('category', 'custom')
                if cat not in by_category:
                    by_category[cat] = []
                by_category[cat].append(fc)
            for cat, calls in sorted(by_category.items()):
                total_count = sum(c.get('count', 1) for c in calls)
                top_funcs = sorted(calls, key=lambda x: -x.get('count', 1))[:5]
                func_names = [f"{c.get('name', '')}x{c.get('count', 1)}" for c in top_funcs]
                lines.append(f"  # {cat} ({total_count} calls): {', '.join(func_names)}")

        if not has_content:
            return []
        return lines

    def _compress_sass_modules(self, matrix) -> List[str]:
        """Compress Sass @use, @forward, @import module system data."""
        lines = []
        has_content = False

        # Module system type
        if hasattr(matrix, 'sass_module_system') and matrix.sass_module_system:
            lines.append(f"  # Module system: {matrix.sass_module_system}")

        # @use statements
        if hasattr(matrix, 'sass_uses') and matrix.sass_uses:
            has_content = True
            lines.append(f"  # @use ({len(matrix.sass_uses)})")
            for use in matrix.sass_uses[:15]:
                path = use.get('path', '')
                ns = use.get('namespace', '')
                as_clause = use.get('as_clause', '')
                flags = []
                if use.get('is_builtin'):
                    flags.append("builtin")
                if use.get('show_members'):
                    flags.append(f"show={len(use['show_members'])}")
                if use.get('hide_members'):
                    flags.append(f"hide={len(use['hide_members'])}")
                if use.get('with_config'):
                    flags.append(f"with={len(use['with_config'])}")
                as_str = f" as {as_clause}" if as_clause else ""
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    @use '{path}'{as_str}{flag_str}")
            if len(matrix.sass_uses) > 15:
                lines.append(f"    # ... and {len(matrix.sass_uses) - 15} more")

        # @forward statements
        if hasattr(matrix, 'sass_forwards') and matrix.sass_forwards:
            has_content = True
            lines.append(f"  # @forward ({len(matrix.sass_forwards)})")
            for fwd in matrix.sass_forwards[:10]:
                path = fwd.get('path', '')
                flags = []
                if fwd.get('prefix'):
                    flags.append(f"prefix={fwd['prefix']}")
                if fwd.get('show_members'):
                    flags.append(f"show={len(fwd['show_members'])}")
                if fwd.get('hide_members'):
                    flags.append(f"hide={len(fwd['hide_members'])}")
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    @forward '{path}'{flag_str}")
            if len(matrix.sass_forwards) > 10:
                lines.append(f"    # ... and {len(matrix.sass_forwards) - 10} more")

        # Legacy @import
        if hasattr(matrix, 'sass_imports') and matrix.sass_imports:
            has_content = True
            partials = sum(1 for i in matrix.sass_imports if i.get('is_partial'))
            css_imports = sum(1 for i in matrix.sass_imports if i.get('is_css_import'))
            lines.append(f"  # @import ({len(matrix.sass_imports)})|partials={partials}|css={css_imports}")
            for imp in matrix.sass_imports[:10]:
                path = imp.get('path', '')
                flags = []
                if imp.get('is_partial'):
                    flags.append("partial")
                if imp.get('is_css_import'):
                    flags.append("css")
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    @import '{path}'{flag_str}")
            if len(matrix.sass_imports) > 10:
                lines.append(f"    # ... and {len(matrix.sass_imports) - 10} more")

        if not has_content:
            return []
        return lines

    def _compress_sass_nesting(self, matrix) -> List[str]:
        """Compress Sass nesting, @extend, placeholders, @at-root."""
        lines = []
        has_content = False

        # Nesting depth analysis
        if hasattr(matrix, 'sass_nesting') and matrix.sass_nesting:
            has_content = True
            depths = [n.get('depth', 0) for n in matrix.sass_nesting]
            max_depth = max(depths) if depths else 0
            avg_depth = sum(depths) / len(depths) if depths else 0
            parent_sel = sum(1 for n in matrix.sass_nesting if n.get('has_parent_selector'))
            bem = sum(1 for n in matrix.sass_nesting if n.get('is_bem_pattern'))
            lines.append(f"  # Depth: max={max_depth}|avg={avg_depth:.1f}|&parent={parent_sel}|BEM={bem}")
            # Show deepest selectors
            deep = sorted(matrix.sass_nesting, key=lambda n: -n.get('depth', 0))[:5]
            for n in deep:
                sel = n.get('selector', '')[:60]
                d = n.get('depth', 0)
                file_short = n.get('file', '').split('/')[-1]
                lines.append(f"    depth={d}|{sel}|{file_short}")

        # @extend
        if hasattr(matrix, 'sass_extends') and matrix.sass_extends:
            has_content = True
            placeholders = sum(1 for e in matrix.sass_extends if e.get('is_placeholder'))
            optional = sum(1 for e in matrix.sass_extends if e.get('is_optional'))
            lines.append(f"  # @extend ({len(matrix.sass_extends)})|placeholder={placeholders}|optional={optional}")
            for ext in matrix.sass_extends[:10]:
                target = ext.get('target', '')[:40]
                flags = []
                if ext.get('is_placeholder'):
                    flags.append("%placeholder")
                if ext.get('is_optional'):
                    flags.append("!optional")
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    @extend {target}{flag_str}")

        # %placeholder definitions
        if hasattr(matrix, 'sass_placeholders') and matrix.sass_placeholders:
            has_content = True
            lines.append(f"  # %placeholders ({len(matrix.sass_placeholders)})")
            for ph in matrix.sass_placeholders[:10]:
                name = ph.get('name', '')
                ext_count = ph.get('extend_count', 0)
                file_short = ph.get('file', '').split('/')[-1]
                lines.append(f"    %{name}|extended={ext_count}|{file_short}")

        # @at-root
        if hasattr(matrix, 'sass_at_roots') and matrix.sass_at_roots:
            has_content = True
            with_query = sum(1 for a in matrix.sass_at_roots if a.get('has_query'))
            lines.append(f"  # @at-root ({len(matrix.sass_at_roots)})|with_query={with_query}")

        if not has_content:
            return []
        return lines

