            css_guards = sum(1 for g in matrix.less_guards if g.get('guard_type') == 'css')
            lines.append(f"  # Guards ({len(matrix.less_guards)})|mixin={mixin_guards}|css={css_guards}")
            for g in matrix.less_guards[:5]:
                expr = g.get('expression', '')[:60]
                gt = g.get('guard_type', 'mixin')
