    def _compress_less_imports(self, matrix) -> List[str]:
        """Compress Less @import statements with options."""
        lines = []
        if not hasattr(matrix, 'less_imports') or not matrix.less_imports:
            return lines

        ref_count = sum(1 for i in matrix.less_imports if i.get('is_reference'))
        url_count = sum(1 for i in matrix.less_imports if i.get('is_url'))
        interp_count = sum(1 for i in matrix.less_imports if i.get('has_interpolation'))
        lines.append(f"  # @import ({len(matrix.less_imports)})|reference={ref_count}|url={url_count}|interpolated={interp_count}")

        for imp in matrix.less_imports[:15]:
            path = imp.get('path', '')[:40]
            options = imp.get('options', [])
            opt_str = f" ({','.join(options)})" if options else ""
            lines.append(f"    @import{opt_str} '{path}'")
        if len(matrix.less_imports) > 15:
            lines.append(f"    # ... and {len(matrix.less_imports) - 15} more")

        return lines

    def _compress_less_rulesets(self, matrix) -> List[str]:
        """Compress Less :extend, detached rulesets, nesting, property merges."""
        lines = []
        has_content = False

        # Nesting depth analysis
        if hasattr(matrix, 'less_nesting') and matrix.less_nesting:
            has_content = True
            depths = [n.get('depth', 0) for n in matrix.less_nesting]
            max_depth = max(depths) if depths else 0
            avg_depth = sum(depths) / len(depths) if depths else 0
            parent_sel = sum(1 for n in matrix.less_nesting if n.get('has_parent_selector'))
            bem = sum(1 for n in matrix.less_nesting if n.get('is_bem_pattern'))
            lines.append(f"  # Depth: max={max_depth}|avg={avg_depth:.1f}|&parent={parent_sel}|BEM={bem}")
            deep = sorted(matrix.less_nesting, key=lambda n: -n.get('depth', 0))[:5]
            for n in deep:
                sel = n.get('selector', '')[:60]
                d = n.get('depth', 0)
                file_short = n.get('file', '').split('/')[-1]
                lines.append(f"    depth={d}|{sel}|{file_short}")

        # :extend()
        if hasattr(matrix, 'less_extends') and matrix.less_extends:
            has_content = True
            all_count = sum(1 for e in matrix.less_extends if e.get('is_all'))
            inline_count = sum(1 for e in matrix.less_extends if e.get('is_inline'))
            lines.append(f"  # :extend ({len(matrix.less_extends)})|all={all_count}|inline={inline_count}")
            for ext in matrix.less_extends[:10]:
                target = ext.get('target', '')[:40]
                flags = []
                if ext.get('is_all'):
                    flags.append("all")
                if ext.get('is_inline'):
                    flags.append("inline")
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    :extend({target}){flag_str}")

        # Detached Rulesets
        if hasattr(matrix, 'less_detached_rulesets') and matrix.less_detached_rulesets:
            has_content = True
            called = sum(1 for d in matrix.less_detached_rulesets if d.get('is_called'))
            lines.append(f"  # Detached rulesets ({len(matrix.less_detached_rulesets)})|called={called}")
            for dr in matrix.less_detached_rulesets[:10]:
                name = dr.get('name', '')[:30]
                body = dr.get('body_lines', 0)
                called_str = "|called" if dr.get('is_called') else ""
                lines.append(f"    @{name}: {{ ... {body}L }}{called_str}")

        # Property merging
        if hasattr(matrix, 'less_property_merges') and matrix.less_property_merges:
            has_content = True
            comma = sum(1 for p in matrix.less_property_merges if p.get('merge_type') == 'comma')
            space = sum(1 for p in matrix.less_property_merges if p.get('merge_type') == 'space')
            lines.append(f"  # Property merge ({len(matrix.less_property_merges)})|comma(+)={comma}|space(+_)={space}")
            for pm in matrix.less_property_merges[:5]:
                prop = pm.get('property', '')[:30]
                mt = pm.get('merge_type', 'comma')
                op = "+" if mt == 'comma' else "+_"
                lines.append(f"    {prop}{op}")

        if not has_content:
            return []
        return lines

