    def _compress_tailwind_config(self, matrix) -> List[str]:
        """Compress Tailwind CSS configuration data."""
        lines = []
        if not hasattr(matrix, 'tailwind_config') or not matrix.tailwind_config:
            return lines

        for cfg in matrix.tailwind_config[:5]:
            ver = cfg.get('version_detected', 'unknown')
            dark = cfg.get('dark_mode', '')
            prefix = cfg.get('prefix', '')
            important = cfg.get('important', False)
            paths = cfg.get('content_paths_count', 0)
            plugins = cfg.get('plugins', [])
            presets = cfg.get('presets', [])
            theme_keys = cfg.get('theme_extend_keys', [])
            file_short = cfg.get('file', '').split('/')[-1]

            lines.append(f"  # {file_short}|version={ver}")
            if dark:
                lines.append(f"    darkMode: {dark}")
            if prefix:
                lines.append(f"    prefix: {prefix}")
            if important:
                lines.append("    important: true")
            if paths:
                lines.append(f"    content: {paths} paths")
            if theme_keys:
                lines.append(f"    theme.extend: {', '.join(theme_keys[:15])}")
            if plugins:
                lines.append(f"    plugins: {', '.join(plugins[:10])}")
            if presets:
                lines.append(f"    presets: {', '.join(presets[:5])}")

        return lines

    def _compress_tailwind_utilities(self, matrix) -> List[str]:
        """Compress Tailwind utility usage data (@apply, directives, arbitrary values)."""
        lines = []
        has_content = False

        # @apply directives — show actual utility classes composed into each selector
        if hasattr(matrix, 'tailwind_apply_directives') and matrix.tailwind_apply_directives:
            has_content = True
            lines.append(f"  # @apply ({len(matrix.tailwind_apply_directives)} usages)")
            limit = 15 if self.tier == OutputTier.COMPACT else 30
            for apply_d in matrix.tailwind_apply_directives[:limit]:
                sel = apply_d.get('selector', '')[:40]
                # Try 'classes' first, fall back to 'utilities' (TailwindApplyInfo uses 'utilities')
                classes = apply_d.get('classes', []) or apply_d.get('utilities', [])
                count = apply_d.get('class_count', 0) or len(classes)
                file_short = apply_d.get('file', '').split('/')[-1]
                if classes:
                    # Show actual utility classes (most useful info)
                    cls_limit = 6 if self.tier == OutputTier.COMPACT else 12
                    cls_str = ' '.join(classes[:cls_limit])
                    extra = f" +{len(classes) - cls_limit}more" if len(classes) > cls_limit else ""
                    lines.append(f"    {sel}|@apply {cls_str}{extra}|{file_short}")
                else:
                    # Fallback: show count if no class detail available
                    lines.append(f"    {sel}|@apply ({count} classes)|{file_short}")
            if len(matrix.tailwind_apply_directives) > limit:
                lines.append(f"    # ... and {len(matrix.tailwind_apply_directives) - limit} more")

        # @tailwind directives
        if hasattr(matrix, 'tailwind_directives') and matrix.tailwind_directives:
            has_content = True
            directives = [d.get('directive', '') for d in matrix.tailwind_directives]
            lines.append(f"  # @tailwind directives: {', '.join(directives)}")

        # Arbitrary values
        if hasattr(matrix, 'tailwind_arbitrary_values') and matrix.tailwind_arbitrary_values:
            has_content = True
            lines.append(f"  # Arbitrary values ({len(matrix.tailwind_arbitrary_values)})")
            by_category: dict = {}
            for arb in matrix.tailwind_arbitrary_values:
                cat = arb.get('category', 'other')
                if cat not in by_category:
                    by_category[cat] = 0
                by_category[cat] += 1
            for cat, count in sorted(by_category.items(), key=lambda x: -x[1])[:10]:
                lines.append(f"    {cat}: {count}")

        if not has_content:
            return []
        return lines

