    # ============================================================
    # v4.18: Bash/Shell Compress Methods
    # ============================================================

    def _compress_bash_functions(self, matrix) -> List[str]:
        """Compress Bash function data into matrix.prompt format."""
        lines = []
        if not hasattr(matrix, 'bash_functions') or not matrix.bash_functions:
            return lines

        # Group by file
        by_file: dict = {}
        for fn in matrix.bash_functions:
            f = fn.get('file', '').split('/')[-1]
            if f not in by_file:
                by_file[f] = []
            by_file[f].append(fn)

        for file_name, funcs in by_file.items():
            lines.append(f"  # {file_name} ({len(funcs)} functions)")
            for fn in funcs[:30]:
                name = fn.get('name', '')
                syntax = fn.get('syntax', 'posix')
                complexity = fn.get('complexity', 0)
                body_lines = fn.get('body_lines', 0)
                calls = fn.get('calls', [])
                params = fn.get('params', [])

                # Build compact representation
                flags = []
                if fn.get('is_exported'):
                    flags.append("exported")
                if fn.get('is_recursive'):
                    flags.append("recursive")
                if complexity > 5:
                    flags.append(f"cx={complexity}")

                param_str = ""
                if params:
                    param_names = [p.get('name', '') for p in params[:5]]
                    param_str = f"({','.join(param_names)})"

                call_str = ""
                if calls:
                    call_str = f"|calls:{','.join(calls[:5])}"

                flag_str = f"|{'|'.join(flags)}" if flags else ""
                docstring = fn.get('docstring', '')
                doc_str = f"|doc:{docstring[:60]}" if docstring else ""

                lines.append(f"    {name}{param_str}|{syntax}|L{fn.get('line', 0)}|{body_lines}lines{flag_str}{call_str}{doc_str}")

            if len(funcs) > 30:
                lines.append(f"    # ... and {len(funcs) - 30} more")

        return lines

    def _compress_bash_variables(self, matrix) -> List[str]:
        """Compress Bash variables, exports, and arrays."""
        lines = []
        has_content = False

        # Exports (environment variables)
        if hasattr(matrix, 'bash_exports') and matrix.bash_exports:
            has_content = True
            lines.append(f"  # Exports ({len(matrix.bash_exports)})")
            for exp in matrix.bash_exports[:30]:
                name = exp.get('name', '')
                value = exp.get('value', '')
                file_short = exp.get('file', '').split('/')[-1]
                val_str = f"={value[:50]}" if value else ""
                lines.append(f"    export {name}{val_str}|{file_short}|L{exp.get('line', 0)}")
            if len(matrix.bash_exports) > 30:
                lines.append(f"    # ... and {len(matrix.bash_exports) - 30} more")

        # Variables (grouped by scope)
        if hasattr(matrix, 'bash_variables') and matrix.bash_variables:
            has_content = True
            by_scope: dict = {}
            for var in matrix.bash_variables:
                scope = var.get('scope', 'global')
                if scope not in by_scope:
                    by_scope[scope] = []
                by_scope[scope].append(var)

            for scope, vars_list in by_scope.items():
                lines.append(f"  # {scope} variables ({len(vars_list)})")
                for var in vars_list[:20]:
                    name = var.get('name', '')
                    var_type = var.get('var_type', 'string')
                    flags = []
                    if var.get('is_readonly'):
                        flags.append("readonly")
                    if var.get('is_integer'):
                        flags.append("int")
                    flag_str = f"|{'|'.join(flags)}" if flags else ""
                    file_short = var.get('file', '').split('/')[-1]
                    lines.append(f"    {name}|{var_type}{flag_str}|{file_short}|L{var.get('line', 0)}")
                if len(vars_list) > 20:
                    lines.append(f"    # ... and {len(vars_list) - 20} more")

        # Arrays
        if hasattr(matrix, 'bash_arrays') and matrix.bash_arrays:
            has_content = True
            lines.append(f"  # Arrays ({len(matrix.bash_arrays)})")
            for arr in matrix.bash_arrays[:15]:
                name = arr.get('name', '')
                arr_type = arr.get('array_type', 'indexed')
                elem_count = arr.get('element_count', 0)
                file_short = arr.get('file', '').split('/')[-1]
                flags = []
                if arr.get('is_readonly'):
                    flags.append("readonly")
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    {name}|{arr_type}|{elem_count}elems{flag_str}|{file_short}|L{arr.get('line', 0)}")
            if len(matrix.bash_arrays) > 15:
                lines.append(f"    # ... and {len(matrix.bash_arrays) - 15} more")

        if not has_content:
            return []
        return lines

    def _compress_bash_api(self, matrix) -> List[str]:
        """Compress Bash API calls: HTTP, services, cron jobs."""
        lines = []
        has_content = False

        # HTTP calls (curl/wget/httpie)
        if hasattr(matrix, 'bash_http_calls') and matrix.bash_http_calls:
            has_content = True
            lines.append(f"  # HTTP Calls ({len(matrix.bash_http_calls)})")
            for http in matrix.bash_http_calls[:20]:
                tool = http.get('tool', 'curl')
                method = http.get('method', 'GET')
                url = http.get('url', '')
                file_short = http.get('file', '').split('/')[-1]
                flags = []
                if http.get('has_auth'):
                    flags.append("auth")
                if http.get('has_data'):
                    flags.append("data")
                if http.get('content_type'):
                    flags.append(http['content_type'])
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    {tool} {method} {url[:80]}{flag_str}|{file_short}|L{http.get('line', 0)}")
            if len(matrix.bash_http_calls) > 20:
                lines.append(f"    # ... and {len(matrix.bash_http_calls) - 20} more")

        # Services (docker, k8s, systemd, cloud)
        if hasattr(matrix, 'bash_services') and matrix.bash_services:
            has_content = True
            by_type: dict = {}
            for svc in matrix.bash_services:
                st = svc.get('service_type', 'other')
                if st not in by_type:
                    by_type[st] = []
                by_type[st].append(svc)

            for svc_type, svcs in by_type.items():
                lines.append(f"  # {svc_type} commands ({len(svcs)})")
                for svc in svcs[:15]:
                    cmd = svc.get('command', '')
                    target = svc.get('target', '')
                    file_short = svc.get('file', '').split('/')[-1]
                    flag_list = svc.get('flags', [])
                    flag_str = f"|flags:{','.join(flag_list[:3])}" if flag_list else ""
                    lines.append(f"    {svc_type} {cmd} {target[:60]}{flag_str}|{file_short}|L{svc.get('line', 0)}")
                if len(svcs) > 15:
                    lines.append(f"    # ... and {len(svcs) - 15} more")

        # Cron jobs
        if hasattr(matrix, 'bash_cron_jobs') and matrix.bash_cron_jobs:
            has_content = True
            lines.append(f"  # Cron Jobs ({len(matrix.bash_cron_jobs)})")
            for cron in matrix.bash_cron_jobs[:10]:
                schedule = cron.get('schedule', '')
                command = cron.get('command', '')
                file_short = cron.get('file', '').split('/')[-1]
                desc = cron.get('description', '')
                desc_str = f"|{desc[:40]}" if desc else ""
                lines.append(f"    {schedule} {command[:60]}{desc_str}|{file_short}|L{cron.get('line', 0)}")
            if len(matrix.bash_cron_jobs) > 10:
                lines.append(f"    # ... and {len(matrix.bash_cron_jobs) - 10} more")

        if not has_content:
            return []
        return lines

    def _compress_bash_commands(self, matrix) -> List[str]:
        """Compress Bash command constructs: pipelines, traps, heredocs."""
        lines = []
        has_content = False

        # Pipelines
        if hasattr(matrix, 'bash_pipelines') and matrix.bash_pipelines:
            has_content = True
            lines.append(f"  # Pipelines ({len(matrix.bash_pipelines)})")
            for pipe in matrix.bash_pipelines[:20]:
                cmds = pipe.get('commands', [])
                pipe_count = pipe.get('pipe_count', 0)
                file_short = pipe.get('file', '').split('/')[-1]
                flags = []
                if pipe.get('has_error_pipe'):
                    flags.append("|&")
                if pipe.get('is_backgrounded'):
                    flags.append("&")
                flag_str = f"|{''.join(flags)}" if flags else ""
                cmd_str = ' | '.join(cmds[:5])
                if len(cmds) > 5:
                    cmd_str += f" | ... (+{len(cmds) - 5})"
                lines.append(f"    {cmd_str}{flag_str}|{file_short}|L{pipe.get('line', 0)}")
            if len(matrix.bash_pipelines) > 20:
                lines.append(f"    # ... and {len(matrix.bash_pipelines) - 20} more")

        # Traps
        if hasattr(matrix, 'bash_traps') and matrix.bash_traps:
            has_content = True
            lines.append(f"  # Traps ({len(matrix.bash_traps)})")
            for trap in matrix.bash_traps[:10]:
                signal = trap.get('signal', '')
                handler = trap.get('handler', '')
                file_short = trap.get('file', '').split('/')[-1]
                cleanup_str = "|cleanup" if trap.get('is_cleanup') else ""
                lines.append(f"    trap {signal}|{handler[:60]}{cleanup_str}|{file_short}|L{trap.get('line', 0)}")
            if len(matrix.bash_traps) > 10:
                lines.append(f"    # ... and {len(matrix.bash_traps) - 10} more")

        # Heredocs
        if hasattr(matrix, 'bash_heredocs') and matrix.bash_heredocs:
            has_content = True
            lines.append(f"  # Heredocs ({len(matrix.bash_heredocs)})")
            for hd in matrix.bash_heredocs[:15]:
                delimiter = hd.get('delimiter', '')
                target_cmd = hd.get('target_command', '')
                file_short = hd.get('file', '').split('/')[-1]
                indent_str = "|indented" if hd.get('is_indented') else ""
                lines.append(f"    <<{delimiter}|{target_cmd}{indent_str}|{file_short}|L{hd.get('line', 0)}")
            if len(matrix.bash_heredocs) > 15:
                lines.append(f"    # ... and {len(matrix.bash_heredocs) - 15} more")

        if not has_content:
            return []
        return lines

    def _compress_bash_dependencies(self, matrix) -> List[str]:
        """Compress Bash dependency info: sources, aliases, frameworks, shell options."""
        lines = []
        has_content = False

        # Sources (imported files)
        if hasattr(matrix, 'bash_sources') and matrix.bash_sources:
            has_content = True
            lines.append(f"  # Source Imports ({len(matrix.bash_sources)})")
            for src in matrix.bash_sources[:20]:
                path = src.get('path', '')
                file_short = src.get('file', '').split('/')[-1]
                syntax = src.get('syntax', 'source')
                flags = []
                if src.get('is_conditional'):
                    flags.append("conditional")
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    {syntax} {path}{flag_str}|{file_short}|L{src.get('line', 0)}")
            if len(matrix.bash_sources) > 20:
                lines.append(f"    # ... and {len(matrix.bash_sources) - 20} more")

        # Aliases
        if hasattr(matrix, 'bash_aliases') and matrix.bash_aliases:
            has_content = True
            lines.append(f"  # Aliases ({len(matrix.bash_aliases)})")
            for alias in matrix.bash_aliases[:20]:
                name = alias.get('name', '')
                command = alias.get('command', '')
                file_short = alias.get('file', '').split('/')[-1]
                lines.append(f"    alias {name}='{command[:60]}'|{file_short}|L{alias.get('line', 0)}")
            if len(matrix.bash_aliases) > 20:
                lines.append(f"    # ... and {len(matrix.bash_aliases) - 20} more")

        # Detected frameworks
        if hasattr(matrix, 'bash_detected_frameworks') and matrix.bash_detected_frameworks:
            has_content = True
            lines.append(f"  # Detected frameworks: {', '.join(matrix.bash_detected_frameworks)}")

        # Detected shells
        if hasattr(matrix, 'bash_detected_shells') and matrix.bash_detected_shells:
            has_content = True
            lines.append(f"  # Detected shells: {', '.join(matrix.bash_detected_shells)}")

        # Shell options (set -e, shopt, etc.)
        if hasattr(matrix, 'bash_shell_options') and matrix.bash_shell_options:
            has_content = True
            opts = [str(o) if isinstance(o, str) else o.get('option', str(o)) for o in matrix.bash_shell_options[:20]]
            lines.append(f"  # Shell options: {', '.join(opts)}")

        # Shebangs summary
        if hasattr(matrix, 'bash_shebangs') and matrix.bash_shebangs:
            has_content = True
            interpreters = list(set(s.get('shell_type', '') or s.get('interpreter', '') for s in matrix.bash_shebangs))
            lines.append(f"  # Shebangs ({len(matrix.bash_shebangs)} scripts): {', '.join(interpreters)}")

        if not has_content:
            return []
        return lines

    # ═══════════════════════════════════════════════════════════════
    # v4.19: C Language Compression Methods
    # ═══════════════════════════════════════════════════════════════

    def _compress_c_types(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress C type definitions: structs, unions, enums, typedefs."""
        lines = []
        has_content = False

        # Structs
        if hasattr(matrix, 'c_structs') and matrix.c_structs:
            has_content = True
            lines.append(f"  # Structs ({len(matrix.c_structs)})")
            for s in matrix.c_structs[:30]:
                name = s.get('name', 'anonymous')
                file_short = s.get('file', '').split('/')[-1]
                fields = s.get('fields', [])
                field_str = ','.join(f"{f['name']}:{f['type']}" for f in fields[:8])
                if len(fields) > 8:
                    field_str += f",+{len(fields)-8}"
                flags = []
                if s.get('is_packed'):
                    flags.append('packed')
                if s.get('is_typedef'):
                    flags.append('typedef')
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    struct {name}{{{field_str}}}{flag_str}|{file_short}|L{s.get('line', 0)}")
            if len(matrix.c_structs) > 30:
                lines.append(f"    # ... and {len(matrix.c_structs) - 30} more")

        # Unions
        if hasattr(matrix, 'c_unions') and matrix.c_unions:
            has_content = True
            lines.append(f"  # Unions ({len(matrix.c_unions)})")
            for u in matrix.c_unions[:20]:
                name = u.get('name', 'anonymous')
                file_short = u.get('file', '').split('/')[-1]
                fields = u.get('fields', [])
                field_str = ','.join(f"{f['name']}:{f['type']}" for f in fields[:6])
                lines.append(f"    union {name}{{{field_str}}}|{file_short}|L{u.get('line', 0)}")
            if len(matrix.c_unions) > 20:
                lines.append(f"    # ... and {len(matrix.c_unions) - 20} more")

        # Enums
        if hasattr(matrix, 'c_enums') and matrix.c_enums:
            has_content = True
            lines.append(f"  # Enums ({len(matrix.c_enums)})")
            for e in matrix.c_enums[:20]:
                name = e.get('name', 'anonymous')
                file_short = e.get('file', '').split('/')[-1]
                constants = e.get('constants', [])
                const_str = ','.join(c['name'] for c in constants[:8])
                if len(constants) > 8:
                    const_str += f",+{len(constants)-8}"
                lines.append(f"    enum {name}{{{const_str}}}|{file_short}|L{e.get('line', 0)}")
            if len(matrix.c_enums) > 20:
                lines.append(f"    # ... and {len(matrix.c_enums) - 20} more")

        # Typedefs
        if hasattr(matrix, 'c_typedefs') and matrix.c_typedefs:
            has_content = True
            lines.append(f"  # Typedefs ({len(matrix.c_typedefs)})")
            for td in matrix.c_typedefs[:25]:
                name = td.get('name', '')
                orig = td.get('underlying_type', '')
                file_short = td.get('file', '').split('/')[-1]
                fp_flag = "|fnptr" if td.get('is_function_pointer') else ""
                lines.append(f"    typedef {orig} → {name}{fp_flag}|{file_short}|L{td.get('line', 0)}")
            if len(matrix.c_typedefs) > 25:
                lines.append(f"    # ... and {len(matrix.c_typedefs) - 25} more")

        # Forward declarations
        if hasattr(matrix, 'c_forward_decls') and matrix.c_forward_decls:
            has_content = True
            lines.append(f"  # Forward Declarations ({len(matrix.c_forward_decls)})")
            for fd in matrix.c_forward_decls[:15]:
                kind = fd.get('kind', '')
                name = fd.get('name', '')
                file_short = fd.get('file', '').split('/')[-1]
                lines.append(f"    {kind} {name}|{file_short}|L{fd.get('line', 0)}")
            if len(matrix.c_forward_decls) > 15:
                lines.append(f"    # ... and {len(matrix.c_forward_decls) - 15} more")

        if not has_content:
            return []
        return lines

    def _compress_c_functions(self, matrix) -> List[str]:
        """Compress C function definitions."""
        lines = []
        has_content = False

        # Functions
        if hasattr(matrix, 'c_functions') and matrix.c_functions:
            has_content = True
            lines.append(f"  # Functions ({len(matrix.c_functions)})")
            for func in matrix.c_functions[:40]:
                name = func.get('name', '')
                ret = func.get('return_type', 'void')
                file_short = func.get('file', '').split('/')[-1]
                params = func.get('params', [])
                param_str = ','.join(f"{p.get('type', '')}" for p in params[:6])
                if len(params) > 6:
                    param_str += f",+{len(params)-6}"
                qualifiers = []
                if func.get('is_static'):
                    qualifiers.append('static')
                if func.get('is_inline'):
                    qualifiers.append('inline')
                if func.get('is_extern'):
                    qualifiers.append('extern')
                if func.get('is_noreturn'):
                    qualifiers.append('_Noreturn')
                if func.get('is_variadic'):
                    qualifiers.append('...')
                qual_str = f"[{'|'.join(qualifiers)}]" if qualifiers else ""
                body = func.get('body_lines', 0)
                cx = func.get('complexity', 0)
                metrics = f"|lines:{body}|cx:{cx}" if body or cx else ""
                lines.append(f"    {qual_str}{ret} {name}({param_str}){metrics}|{file_short}|L{func.get('line', 0)}")
            if len(matrix.c_functions) > 40:
                lines.append(f"    # ... and {len(matrix.c_functions) - 40} more")

        # Function pointers
        if hasattr(matrix, 'c_function_pointers') and matrix.c_function_pointers:
            has_content = True
            lines.append(f"  # Function Pointers ({len(matrix.c_function_pointers)})")
            for fp in matrix.c_function_pointers[:20]:
                name = fp.get('name', '')
                ret = fp.get('return_type', 'void')
                ptypes = ','.join(fp.get('param_types', [])[:5])
                file_short = fp.get('file', '').split('/')[-1]
                lines.append(f"    {ret} (*{name})({ptypes})|{file_short}|L{fp.get('line', 0)}")
            if len(matrix.c_function_pointers) > 20:
                lines.append(f"    # ... and {len(matrix.c_function_pointers) - 20} more")

        if not has_content:
            return []
        return lines

    def _compress_c_api(self, matrix) -> List[str]:
        """Compress C API patterns: sockets, signals, IPC, threading, HTTP."""
        lines = []
