    def _compress_c_dependencies(self, matrix) -> List[str]:
        """Compress C dependencies: includes, macros, preprocessor, frameworks."""
        lines = []
        has_content = False

        # Includes
        if hasattr(matrix, 'c_includes') and matrix.c_includes:
            has_content = True
            # Separate system and local includes
            system_incs = [i for i in matrix.c_includes if i.get('is_system')]
            local_incs = [i for i in matrix.c_includes if not i.get('is_system')]
            # Deduplicate paths
            sys_paths = sorted(set(i.get('path', '') for i in system_incs))
            local_paths = sorted(set(i.get('path', '') for i in local_incs))
            if sys_paths:
                lines.append(f"  # System includes ({len(sys_paths)}): {', '.join(sys_paths[:20])}")
                if len(sys_paths) > 20:
                    lines.append(f"    # ... and {len(sys_paths) - 20} more")
            if local_paths:
                lines.append(f"  # Local includes ({len(local_paths)}): {', '.join(local_paths[:20])}")
                if len(local_paths) > 20:
                    lines.append(f"    # ... and {len(local_paths) - 20} more")

        # Key macros (function-like)
        if hasattr(matrix, 'c_macros') and matrix.c_macros:
            has_content = True
            fn_macros = [m for m in matrix.c_macros if m.get('is_function_like')]
            obj_macros = [m for m in matrix.c_macros if not m.get('is_function_like')]
            if fn_macros:
                lines.append(f"  # Function-like macros ({len(fn_macros)})")
                for m in fn_macros[:15]:
                    name = m.get('name', '')
                    params = ','.join(m.get('params', []))
                    body = m.get('body', '')[:60]
                    file_short = m.get('file', '').split('/')[-1]
                    lines.append(f"    {name}({params})→{body}|{file_short}|L{m.get('line', 0)}")
                if len(fn_macros) > 15:
                    lines.append(f"    # ... and {len(fn_macros) - 15} more")
            if obj_macros:
                lines.append(f"  # Object-like macros ({len(obj_macros)})")
                for m in obj_macros[:15]:
                    name = m.get('name', '')
                    body = m.get('body', '')[:60]
                    file_short = m.get('file', '').split('/')[-1]
                    lines.append(f"    {name}={body}|{file_short}|L{m.get('line', 0)}")
                if len(obj_macros) > 15:
                    lines.append(f"    # ... and {len(obj_macros) - 15} more")

        # Detected frameworks
        if hasattr(matrix, 'c_detected_frameworks') and matrix.c_detected_frameworks:
            has_content = True
            lines.append(f"  # Detected frameworks: {', '.join(matrix.c_detected_frameworks)}")

        # C standard
        if hasattr(matrix, 'c_c_standard') and matrix.c_c_standard:
            has_content = True
            lines.append(f"  # C standard: {matrix.c_c_standard}")

        # Detected compiler
        if hasattr(matrix, 'c_detected_compiler') and matrix.c_detected_compiler:
            has_content = True
            lines.append(f"  # Target compiler: {matrix.c_detected_compiler}")

        # Features
        if hasattr(matrix, 'c_detected_features') and matrix.c_detected_features:
            has_content = True
            lines.append(f"  # C features: {', '.join(matrix.c_detected_features)}")

        # Pragmas summary
        if hasattr(matrix, 'c_pragmas') and matrix.c_pragmas:
            has_content = True
            pragma_dirs = list(set(p.get('directive', '') for p in matrix.c_pragmas))
            lines.append(f"  # Pragmas ({len(matrix.c_pragmas)}): {', '.join(pragma_dirs[:10])}")

        # Attributes summary
        if hasattr(matrix, 'c_attributes') and matrix.c_attributes:
            has_content = True
            attr_names = list(set(a.get('name', '') for a in matrix.c_attributes))
            lines.append(f"  # Attributes ({len(matrix.c_attributes)}): {', '.join(attr_names[:10])}")

        if not has_content:
            return []
        return lines

    # ============================================
    # v4.20: C++ Compression Methods
    # ============================================

    def _compress_cpp_types(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress C++ type definitions: classes, structs, unions, enums, concepts, type aliases, namespaces."""
        lines = []
        has_content = False

        # Classes / Structs
        if hasattr(matrix, 'cpp_classes') and matrix.cpp_classes:
            has_content = True
            lines.append(f"  # Classes/Structs ({len(matrix.cpp_classes)})")
            for cls in matrix.cpp_classes[:35]:
                name = cls.get('name', '')
                kind = cls.get('kind', 'class')
                file_short = cls.get('file', '').split('/')[-1]
                bases = cls.get('bases', [])
                base_str = ''
                if bases:
                    base_names = [f"{b.get('access', 'public')} {b.get('name', '')}" for b in bases[:4]]
                    base_str = ' : ' + ', '.join(base_names)
                    if len(bases) > 4:
                        base_str += f", +{len(bases)-4}"
                fields = cls.get('fields', [])
                field_str = ','.join(f"{f['name']}:{f['type']}" for f in fields[:6])
                if len(fields) > 6:
                    field_str += f",+{len(fields)-6}"
                flags = []
                if cls.get('is_template'):
                    tparams = cls.get('template_params', '')
                    flags.append(f"template<{tparams[:50]}>")
                if cls.get('is_abstract'):
                    flags.append('abstract')
                if cls.get('is_final'):
                    flags.append('final')
                if cls.get('is_crtp'):
                    flags.append('CRTP')
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    {kind} {name}{base_str}{{{field_str}}}{flag_str}|{file_short}|L{cls.get('line', 0)}")
            if len(matrix.cpp_classes) > 35:
                lines.append(f"    # ... and {len(matrix.cpp_classes) - 35} more")

        # Unions
        if hasattr(matrix, 'cpp_unions') and matrix.cpp_unions:
            has_content = True
            lines.append(f"  # Unions ({len(matrix.cpp_unions)})")
            for u in matrix.cpp_unions[:15]:
                name = u.get('name', 'anonymous')
                file_short = u.get('file', '').split('/')[-1]
                fields = u.get('fields', [])
                field_str = ','.join(f"{f['name']}:{f['type']}" for f in fields[:6])
                tmpl = "|template" if u.get('is_template') else ""
                lines.append(f"    union {name}{{{field_str}}}{tmpl}|{file_short}|L{u.get('line', 0)}")
            if len(matrix.cpp_unions) > 15:
                lines.append(f"    # ... and {len(matrix.cpp_unions) - 15} more")

        # Enums
        if hasattr(matrix, 'cpp_enums') and matrix.cpp_enums:
            has_content = True
            lines.append(f"  # Enums ({len(matrix.cpp_enums)})")
            for e in matrix.cpp_enums[:20]:
                name = e.get('name', 'anonymous')
                file_short = e.get('file', '').split('/')[-1]
                scoped = "enum class" if e.get('is_scoped') else "enum"
                underlying = f" : {e['underlying_type']}" if e.get('underlying_type') else ""
                constants = e.get('constants', [])
                const_str = ','.join(c['name'] for c in constants[:8])
                if len(constants) > 8:
                    const_str += f",+{len(constants)-8}"
                lines.append(f"    {scoped} {name}{underlying}{{{const_str}}}|{file_short}|L{e.get('line', 0)}")
            if len(matrix.cpp_enums) > 20:
                lines.append(f"    # ... and {len(matrix.cpp_enums) - 20} more")

        # Type Aliases
        if hasattr(matrix, 'cpp_type_aliases') and matrix.cpp_type_aliases:
            has_content = True
            lines.append(f"  # Type Aliases ({len(matrix.cpp_type_aliases)})")
            for ta in matrix.cpp_type_aliases[:20]:
                name = ta.get('name', '')
                underlying = ta.get('underlying_type', '')
                kind = ta.get('kind', 'using')
                file_short = ta.get('file', '').split('/')[-1]
                tmpl = "|template" if ta.get('is_template') else ""
                lines.append(f"    {kind} {name} = {underlying[:60]}{tmpl}|{file_short}|L{ta.get('line', 0)}")
            if len(matrix.cpp_type_aliases) > 20:
                lines.append(f"    # ... and {len(matrix.cpp_type_aliases) - 20} more")

        # Concepts (C++20)
        if hasattr(matrix, 'cpp_concepts') and matrix.cpp_concepts:
            has_content = True
            lines.append(f"  # Concepts ({len(matrix.cpp_concepts)})")
            for c in matrix.cpp_concepts[:15]:
                name = c.get('name', '')
                tparams = c.get('template_params', '')
                constraint = c.get('constraint', '')[:80]
                file_short = c.get('file', '').split('/')[-1]
                lines.append(f"    concept {name}<{tparams}>|{constraint}|{file_short}|L{c.get('line', 0)}")
            if len(matrix.cpp_concepts) > 15:
                lines.append(f"    # ... and {len(matrix.cpp_concepts) - 15} more")

        # Namespaces
        if hasattr(matrix, 'cpp_namespaces') and matrix.cpp_namespaces:
            has_content = True
            ns_names = sorted(set(ns.get('name', '') for ns in matrix.cpp_namespaces))
            inline_ns = [ns.get('name', '') for ns in matrix.cpp_namespaces if ns.get('is_inline')]
            lines.append(f"  # Namespaces ({len(ns_names)}): {', '.join(ns_names[:15])}")
            if inline_ns:
                lines.append(f"  # Inline namespaces: {', '.join(sorted(set(inline_ns[:10])))}")

        # Forward Declarations
        if hasattr(matrix, 'cpp_forward_decls') and matrix.cpp_forward_decls:
            has_content = True
            lines.append(f"  # Forward Declarations ({len(matrix.cpp_forward_decls)})")
            for fd in matrix.cpp_forward_decls[:15]:
                kind = fd.get('kind', '')
                name = fd.get('name', '')
                file_short = fd.get('file', '').split('/')[-1]
                lines.append(f"    {kind} {name}|{file_short}|L{fd.get('line', 0)}")
            if len(matrix.cpp_forward_decls) > 15:
                lines.append(f"    # ... and {len(matrix.cpp_forward_decls) - 15} more")

        if not has_content:
            return []
        return lines

    def _compress_cpp_functions(self, matrix) -> List[str]:
        """Compress C++ function/method definitions."""
        lines = []
        has_content = False

        # Methods / Functions
        if hasattr(matrix, 'cpp_methods') and matrix.cpp_methods:
            has_content = True
            lines.append(f"  # Methods/Functions ({len(matrix.cpp_methods)})")
            for m in matrix.cpp_methods[:50]:
                name = m.get('name', '')
                ret = m.get('return_type', 'void')
                cls = m.get('class_name', '')
                file_short = m.get('file', '').split('/')[-1]
                params = m.get('params', [])
                param_str = ','.join(f"{p.get('type', '')}" for p in params[:6])
                if len(params) > 6:
                    param_str += f",+{len(params)-6}"
                qualifiers = []
                if m.get('is_virtual'):
                    qualifiers.append('virtual')
                if m.get('is_static'):
                    qualifiers.append('static')
                if m.get('is_constexpr'):
                    qualifiers.append('constexpr')
                if m.get('is_consteval'):
                    qualifiers.append('consteval')
                if m.get('is_const'):
                    qualifiers.append('const')
                if m.get('is_noexcept'):
                    qualifiers.append('noexcept')
                if m.get('is_override'):
                    qualifiers.append('override')
                if m.get('is_template'):
                    qualifiers.append('template')
                if m.get('is_coroutine'):
                    qualifiers.append('coroutine')
                if m.get('is_deleted'):
                    qualifiers.append('=delete')
                if m.get('is_defaulted'):
                    qualifiers.append('=default')
                qual_str = f"[{'|'.join(qualifiers)}]" if qualifiers else ""
                scope = f"{cls}::" if cls else ""
                body = m.get('body_lines', 0)
                cx = m.get('complexity', 0)
                metrics = f"|lines:{body}|cx:{cx}" if body or cx else ""
                lines.append(f"    {qual_str}{ret} {scope}{name}({param_str}){metrics}|{file_short}|L{m.get('line', 0)}")
            if len(matrix.cpp_methods) > 50:
                lines.append(f"    # ... and {len(matrix.cpp_methods) - 50} more")

        # Lambdas
        if hasattr(matrix, 'cpp_lambdas') and matrix.cpp_lambdas:
            has_content = True
            lines.append(f"  # Lambdas ({len(matrix.cpp_lambdas)})")
            for lam in matrix.cpp_lambdas[:20]:
                capture = lam.get('capture', '')
                ret = lam.get('return_type', '')
                file_short = lam.get('file', '').split('/')[-1]
                flags = []
                if lam.get('is_generic'):
                    flags.append('generic')
                if lam.get('is_mutable'):
                    flags.append('mutable')
                if lam.get('is_constexpr'):
                    flags.append('constexpr')
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                ret_str = f" -> {ret}" if ret else ""
                lines.append(f"    [{capture}](...){ret_str}{flag_str}|{file_short}|L{lam.get('line', 0)}")
            if len(matrix.cpp_lambdas) > 20:
                lines.append(f"    # ... and {len(matrix.cpp_lambdas) - 20} more")

        if not has_content:
            return []
        return lines

