    def _compress_cpp_models(self, matrix) -> List[str]:
        """Compress C++ model/data patterns: containers, smart pointers, RAII, design patterns."""
        lines = []
        has_content = False

        # STL Containers
        if hasattr(matrix, 'cpp_containers') and matrix.cpp_containers:
            has_content = True
            # Group by container type
            by_type = {}
            for c in matrix.cpp_containers:
                ct = c.get('type', '')
                if ct not in by_type:
                    by_type[ct] = 0
                by_type[ct] += 1
            type_summary = ', '.join(f"{t}({n})" for t, n in sorted(by_type.items(), key=lambda x: -x[1])[:15])
            lines.append(f"  # STL Containers ({len(matrix.cpp_containers)}): {type_summary}")

        # Smart Pointers
        if hasattr(matrix, 'cpp_smart_pointers') and matrix.cpp_smart_pointers:
            has_content = True
            by_kind = {}
            for sp in matrix.cpp_smart_pointers:
                k = sp.get('kind', '')
                if k not in by_kind:
                    by_kind[k] = 0
                by_kind[k] += 1
            kind_summary = ', '.join(f"{k}({n})" for k, n in sorted(by_kind.items(), key=lambda x: -x[1]))
            lines.append(f"  # Smart Pointers ({len(matrix.cpp_smart_pointers)}): {kind_summary}")

        # RAII Patterns
        if hasattr(matrix, 'cpp_raii') and matrix.cpp_raii:
            has_content = True
            patterns = sorted(set(r.get('pattern', '') for r in matrix.cpp_raii))
            lines.append(f"  # RAII Patterns ({len(matrix.cpp_raii)}): {', '.join(patterns[:10])}")

        # Design Patterns
        if hasattr(matrix, 'cpp_design_patterns') and matrix.cpp_design_patterns:
            has_content = True
            lines.append(f"  # Design Patterns ({len(matrix.cpp_design_patterns)})")
            for dp in matrix.cpp_design_patterns[:15]:
                pattern = dp.get('pattern', '')
                cls = dp.get('class_name', '')
                confidence = dp.get('confidence', '')
                file_short = dp.get('file', '').split('/')[-1]
                lines.append(f"    {pattern}|{cls}|confidence:{confidence}|{file_short}|L{dp.get('line', 0)}")
            if len(matrix.cpp_design_patterns) > 15:
                lines.append(f"    # ... and {len(matrix.cpp_design_patterns) - 15} more")

        # Global Variables
        if hasattr(matrix, 'cpp_global_vars') and matrix.cpp_global_vars:
            has_content = True
            lines.append(f"  # Global Variables ({len(matrix.cpp_global_vars)})")
            for gv in matrix.cpp_global_vars[:20]:
                name = gv.get('name', '')
                gv_type = gv.get('type', '')
                file_short = gv.get('file', '').split('/')[-1]
                flags = []
                if gv.get('is_const'):
                    flags.append('const')
                if gv.get('is_constexpr'):
                    flags.append('constexpr')
                if gv.get('is_constinit'):
                    flags.append('constinit')
                if gv.get('is_static'):
                    flags.append('static')
                if gv.get('is_extern'):
                    flags.append('extern')
                if gv.get('is_thread_local'):
                    flags.append('thread_local')
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                lines.append(f"    {gv_type} {name}{flag_str}|{file_short}|L{gv.get('line', 0)}")
            if len(matrix.cpp_global_vars) > 20:
                lines.append(f"    # ... and {len(matrix.cpp_global_vars) - 20} more")

        # Constants
        if hasattr(matrix, 'cpp_constants') and matrix.cpp_constants:
            has_content = True
            lines.append(f"  # Constants ({len(matrix.cpp_constants)})")
            for const in matrix.cpp_constants[:20]:
                name = const.get('name', '')
                value = const.get('value', '')
                kind = const.get('kind', '')
                file_short = const.get('file', '').split('/')[-1]
                lines.append(f"    {name}={value[:50]}|{kind}|{file_short}|L{const.get('line', 0)}")
            if len(matrix.cpp_constants) > 20:
                lines.append(f"    # ... and {len(matrix.cpp_constants) - 20} more")

        if not has_content:
            return []
        return lines

    def _compress_cpp_dependencies(self, matrix) -> List[str]:
        """Compress C++ dependencies: includes, macros, modules, frameworks."""
        lines = []
        has_content = False

        # Includes
        if hasattr(matrix, 'cpp_includes') and matrix.cpp_includes:
            has_content = True
            system_incs = [i for i in matrix.cpp_includes if i.get('is_system')]
            local_incs = [i for i in matrix.cpp_includes if not i.get('is_system')]
            sys_paths = sorted(set(i.get('path', '') for i in system_incs))
            local_paths = sorted(set(i.get('path', '') for i in local_incs))
            if sys_paths:
                lines.append(f"  # System includes ({len(sys_paths)}): {', '.join(sys_paths[:25])}")
                if len(sys_paths) > 25:
                    lines.append(f"    # ... and {len(sys_paths) - 25} more")
            if local_paths:
                lines.append(f"  # Local includes ({len(local_paths)}): {', '.join(local_paths[:20])}")
                if len(local_paths) > 20:
                    lines.append(f"    # ... and {len(local_paths) - 20} more")

        # C++20 Modules
        if hasattr(matrix, 'cpp_modules') and matrix.cpp_modules:
            has_content = True
            lines.append(f"  # C++20 Modules ({len(matrix.cpp_modules)})")
            for mod in matrix.cpp_modules[:15]:
                kind = mod.get('kind', '')
                name = mod.get('name', '')
                export = "export " if mod.get('is_export') else ""
                partition = f":{mod['partition']}" if mod.get('partition') else ""
                file_short = mod.get('file', '').split('/')[-1]
                lines.append(f"    {export}{kind} {name}{partition}|{file_short}|L{mod.get('line', 0)}")
            if len(matrix.cpp_modules) > 15:
                lines.append(f"    # ... and {len(matrix.cpp_modules) - 15} more")

        # Key macros
        if hasattr(matrix, 'cpp_macros') and matrix.cpp_macros:
            has_content = True
            fn_macros = [m for m in matrix.cpp_macros if m.get('is_function_like')]
            obj_macros = [m for m in matrix.cpp_macros if not m.get('is_function_like')]
            if fn_macros:
                lines.append(f"  # Function-like macros ({len(fn_macros)})")
                for m in fn_macros[:15]:
                    name = m.get('name', '')
                    params = ','.join(m.get('params', []))
                    body = m.get('body', '')[:60]
                    file_short = m.get('file', '').split('/')[-1]
                    lines.append(f"    {name}({params})→{body}|{file_short}|L{m.get('line', 0)}")
                if len(fn_macros) > 15:
                    lines.append(f"    # ... and {len(fn_macros) - 15} more")
            if obj_macros:
                lines.append(f"  # Object-like macros ({len(obj_macros)})")
                for m in obj_macros[:15]:
                    name = m.get('name', '')
                    body = m.get('body', '')[:60]
                    file_short = m.get('file', '').split('/')[-1]
                    lines.append(f"    {name}={body}|{file_short}|L{m.get('line', 0)}")
                if len(obj_macros) > 15:
                    lines.append(f"    # ... and {len(obj_macros) - 15} more")

        # Detected frameworks
        if hasattr(matrix, 'cpp_detected_frameworks') and matrix.cpp_detected_frameworks:
            has_content = True
            lines.append(f"  # Detected frameworks: {', '.join(matrix.cpp_detected_frameworks)}")

        # C++ standard
        if hasattr(matrix, 'cpp_cpp_standard') and matrix.cpp_cpp_standard:
            has_content = True
            lines.append(f"  # C++ standard: {matrix.cpp_cpp_standard}")

        # Detected compiler
        if hasattr(matrix, 'cpp_detected_compiler') and matrix.cpp_detected_compiler:
            has_content = True
            lines.append(f"  # Target compiler: {matrix.cpp_detected_compiler}")

        # Features
        if hasattr(matrix, 'cpp_detected_features') and matrix.cpp_detected_features:
            has_content = True
            lines.append(f"  # C++ features: {', '.join(matrix.cpp_detected_features)}")

        # Pragmas summary
        if hasattr(matrix, 'cpp_pragmas') and matrix.cpp_pragmas:
            has_content = True
            pragma_dirs = list(set(p.get('directive', '') for p in matrix.cpp_pragmas))
            lines.append(f"  # Pragmas ({len(matrix.cpp_pragmas)}): {', '.join(pragma_dirs[:10])}")

        # Attributes summary
        if hasattr(matrix, 'cpp_attributes') and matrix.cpp_attributes:
            has_content = True
            attr_names = list(set(a.get('name', '') for a in matrix.cpp_attributes))
            lines.append(f"  # C++ Attributes ({len(matrix.cpp_attributes)}): {', '.join(attr_names[:10])}")

        # Static asserts
        if hasattr(matrix, 'cpp_static_asserts') and matrix.cpp_static_asserts:
            has_content = True
            lines.append(f"  # static_assert count: {len(matrix.cpp_static_asserts)}")

        if not has_content:
            return []
        return lines

    # ============================================
    # v4.22: Swift Compression Methods
    # ============================================

    def _compress_swift_types(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress Swift type definitions (classes, structs, enums, protocols, actors, extensions, aliases)."""
        lines = []

        # Classes
        if hasattr(matrix, 'swift_classes') and matrix.swift_classes:
            lines.append(f"# Classes ({len(matrix.swift_classes)})")
            for cls in matrix.swift_classes[:30]:
                file_short = cls.get('file', '').split('/')[-1]
                access = f"{cls['access']} " if cls.get('access') else ""
                final_str = "final " if cls.get('is_final') else ""
                generics = f"<{','.join(cls['generic_params'])}>" if cls.get('generic_params') else ""
                super_str = f" : {cls['superclass']}" if cls.get('superclass') else ""
                protos = f", {', '.join(cls['protocols'][:3])}" if cls.get('protocols') else ""
                fields = cls.get('fields', [])
                field_strs = [f"{f['name']}:{f.get('type', '?')}" for f in fields[:6]]
                if len(fields) > 6:
                    field_strs.append(f"+{len(fields) - 6}more")
                lines.append(f"  {access}{final_str}class {cls['name']}{generics}{super_str}{protos}|{file_short}({','.join(field_strs)})")
            if len(matrix.swift_classes) > 30:
                lines.append(f"  # ... and {len(matrix.swift_classes) - 30} more classes")

        # Structs
        if hasattr(matrix, 'swift_structs') and matrix.swift_structs:
            lines.append(f"# Structs ({len(matrix.swift_structs)})")
            for s in matrix.swift_structs[:30]:
                file_short = s.get('file', '').split('/')[-1]
                access = f"{s['access']} " if s.get('access') else ""
                generics = f"<{','.join(s['generic_params'])}>" if s.get('generic_params') else ""
                protos = f" : {', '.join(s['protocols'][:3])}" if s.get('protocols') else ""
                fields = s.get('fields', [])
                field_strs = [f"{f['name']}:{f.get('type', '?')}" for f in fields[:6]]
                if len(fields) > 6:
                    field_strs.append(f"+{len(fields) - 6}more")
                lines.append(f"  {access}struct {s['name']}{generics}{protos}|{file_short}({','.join(field_strs)})")
            if len(matrix.swift_structs) > 30:
                lines.append(f"  # ... and {len(matrix.swift_structs) - 30} more structs")

        # Enums
        if hasattr(matrix, 'swift_enums') and matrix.swift_enums:
            lines.append(f"# Enums ({len(matrix.swift_enums)})")
            for e in matrix.swift_enums[:30]:
                file_short = e.get('file', '').split('/')[-1]
                access = f"{e['access']} " if e.get('access') else ""
                raw_type = f" : {e['raw_type']}" if e.get('raw_type') else ""
                protos = f", {', '.join(e['protocols'][:3])}" if e.get('protocols') else ""
                cases = e.get('cases', [])
                case_strs = [c['name'] for c in cases[:8]]
                if len(cases) > 8:
                    case_strs.append(f"+{len(cases) - 8}more")
                lines.append(f"  {access}enum {e['name']}{raw_type}{protos}|{file_short}[{','.join(case_strs)}]")
            if len(matrix.swift_enums) > 30:
                lines.append(f"  # ... and {len(matrix.swift_enums) - 30} more enums")

        # Protocols
        if hasattr(matrix, 'swift_protocols') and matrix.swift_protocols:
            lines.append(f"# Protocols ({len(matrix.swift_protocols)})")
            for p in matrix.swift_protocols[:30]:
                file_short = p.get('file', '').split('/')[-1]
                access = f"{p['access']} " if p.get('access') else ""
                inherits = f" : {', '.join(p['inherits'][:3])}" if p.get('inherits') else ""
                reqs = p.get('requirements', [])
                req_strs = [r['name'] for r in reqs[:6]]
                if len(reqs) > 6:
                    req_strs.append(f"+{len(reqs) - 6}more")
                assoc = f"|associatedtype:[{','.join(p['associated_types'][:3])}]" if p.get('associated_types') else ""
                lines.append(f"  {access}protocol {p['name']}{inherits}|{file_short}|reqs:[{','.join(req_strs)}]{assoc}")
            if len(matrix.swift_protocols) > 30:
                lines.append(f"  # ... and {len(matrix.swift_protocols) - 30} more protocols")

        # Actors
        if hasattr(matrix, 'swift_actors') and matrix.swift_actors:
            lines.append(f"# Actors ({len(matrix.swift_actors)})")
            for a in matrix.swift_actors[:20]:
                file_short = a.get('file', '').split('/')[-1]
                access = f"{a['access']} " if a.get('access') else ""
                global_str = "@globalActor " if a.get('is_global') else ""
                protos = f" : {', '.join(a['protocols'][:3])}" if a.get('protocols') else ""
                fields = a.get('fields', [])
                field_strs = [f"{f['name']}:{f.get('type', '?')}" for f in fields[:4]]
                lines.append(f"  {access}{global_str}actor {a['name']}{protos}|{file_short}({','.join(field_strs)})")

        # Extensions
        if hasattr(matrix, 'swift_extensions') and matrix.swift_extensions:
            lines.append(f"# Extensions ({len(matrix.swift_extensions)})")
            for ext in matrix.swift_extensions[:20]:
                file_short = ext.get('file', '').split('/')[-1]
                protos = f" : {', '.join(ext['protocols'][:3])}" if ext.get('protocols') else ""
                where = f" where {ext['where_clause']}" if ext.get('where_clause') else ""
                methods = ext.get('methods', [])
                meth_strs = methods[:5] if methods and isinstance(methods[0], str) else [m.get('name', '') for m in methods[:5]] if methods else []
                lines.append(f"  extension {ext['extended_type']}{protos}{where}|{file_short}|[{','.join(meth_strs)}]")
            if len(matrix.swift_extensions) > 20:
                lines.append(f"  # ... and {len(matrix.swift_extensions) - 20} more extensions")

        # Type Aliases
        if hasattr(matrix, 'swift_type_aliases') and matrix.swift_type_aliases:
            lines.append(f"# Type Aliases ({len(matrix.swift_type_aliases)})")
            for a in matrix.swift_type_aliases[:15]:
                file_short = a.get('file', '').split('/')[-1]
                generics = f"<{','.join(a['generic_params'])}>" if a.get('generic_params') else ""
                lines.append(f"  typealias {a['name']}{generics} = {a.get('target_type', '?')}|{file_short}")

        return lines

    def _compress_swift_functions(self, matrix) -> List[str]:
        """Compress Swift functions, initializers, subscripts."""
        lines = []

        # Functions
        if hasattr(matrix, 'swift_functions') and matrix.swift_functions:
            lines.append(f"# Functions ({len(matrix.swift_functions)} total)")
            for func in matrix.swift_functions[:40]:
                file_short = func.get('file', '').split('/')[-1]
                params = func.get('params', [])
                param_strs = []
                for p in params[:4]:
                    label = f"{p.get('label', '_')} " if p.get('label') and p['label'] != p.get('name') else ""
                    param_strs.append(f"{label}{p.get('name', '')}:{p.get('type', '?')}")
                if len(params) > 4:
                    param_strs.append(f"+{len(params) - 4}")

                qualifiers = []
                if func.get('is_static'):
                    qualifiers.append('static')
                if func.get('is_class_func'):
                    qualifiers.append('class')
                if func.get('is_mutating'):
                    qualifiers.append('mutating')
                if func.get('is_async'):
                    qualifiers.append('async')
                if func.get('is_throws'):
                    qualifiers.append('throws')
                qual_str = ' '.join(qualifiers) + ' ' if qualifiers else ''
                access = f"{func['access']} " if func.get('access') else ""
                ret_str = f" -> {func['return_type']}" if func.get('return_type') else ""
                generics = f"<{','.join(func['generic_params'])}>" if func.get('generic_params') else ""

                lines.append(f"  {access}{qual_str}func {func['name']}{generics}({','.join(param_strs)}){ret_str}|{file_short}")
            if len(matrix.swift_functions) > 40:
                lines.append(f"  # ... and {len(matrix.swift_functions) - 40} more functions")

        # Initializers
        if hasattr(matrix, 'swift_inits') and matrix.swift_inits:
            lines.append(f"# Initializers ({len(matrix.swift_inits)})")
            for init in matrix.swift_inits[:20]:
                file_short = init.get('file', '').split('/')[-1]
                params = init.get('params', [])
                param_strs = [f"{p.get('name', '')}:{p.get('type', '?')}" for p in params[:4]]
                if len(params) > 4:
                    param_strs.append(f"+{len(params) - 4}")
                flags = []
                if init.get('is_convenience'):
                    flags.append('convenience')
                if init.get('is_required'):
                    flags.append('required')
                if init.get('is_failable'):
                    flags.append('failable')
                if init.get('is_async'):
                    flags.append('async')
                if init.get('is_throws'):
                    flags.append('throws')
                flag_str = f"|{'|'.join(flags)}" if flags else ""
                type_name = init.get('type_name', '?')
                lines.append(f"  {type_name}.init({','.join(param_strs)}){flag_str}|{file_short}")

        # Subscripts
        if hasattr(matrix, 'swift_subscripts') and matrix.swift_subscripts:
            lines.append(f"# Subscripts ({len(matrix.swift_subscripts)})")
            for sub in matrix.swift_subscripts[:10]:
                file_short = sub.get('file', '').split('/')[-1]
                params = sub.get('params', [])
                param_strs = [f"{p.get('name', '')}:{p.get('type', '?')}" for p in params[:3]]
                ret_str = f" -> {sub['return_type']}" if sub.get('return_type') else ""
                type_name = sub.get('type_name', '?')
                lines.append(f"  {type_name}.subscript({','.join(param_strs)}){ret_str}|{file_short}")

        return lines

    def _compress_swift_api(self, matrix) -> List[str]:
        """Compress Swift API endpoints, SwiftUI views, Combine publishers, gRPC."""
        lines = []

        # HTTP Routes (Vapor, Hummingbird)
        if hasattr(matrix, 'swift_routes') and matrix.swift_routes:
            by_framework = {}
            for route in matrix.swift_routes:
                fw = route.get('framework', 'unknown')
                if fw not in by_framework:
                    by_framework[fw] = []
                by_framework[fw].append(route)

            for fw, routes in by_framework.items():
                lines.append(f"# {fw} Routes ({len(routes)})")
                for route in routes[:30]:
                    file_short = route.get('file', '').split('/')[-1]
                    lines.append(f"  {route['method']} {route['path']}→{route['handler']}|{file_short}")
                if len(routes) > 30:
                    lines.append(f"  # ... and {len(routes) - 30} more routes")

        # SwiftUI Views
        if hasattr(matrix, 'swift_views') and matrix.swift_views:
            lines.append(f"# SwiftUI Views ({len(matrix.swift_views)})")
            for view in matrix.swift_views[:30]:
                file_short = view.get('file', '').split('/')[-1]
                state = view.get('state_vars', [])
                binding = view.get('binding_vars', [])
                env = view.get('environment_vars', [])
                state_str = f"|@State:[{','.join(state[:3])}]" if state else ""
                binding_str = f"|@Binding:[{','.join(binding[:3])}]" if binding else ""
                env_str = f"|@Environment:[{','.join(env[:2])}]" if env else ""
                lines.append(f"  View {view['name']}{state_str}{binding_str}{env_str}|{file_short}")
            if len(matrix.swift_views) > 30:
                lines.append(f"  # ... and {len(matrix.swift_views) - 30} more views")

        # Combine Publishers
        if hasattr(matrix, 'swift_publishers') and matrix.swift_publishers:
            lines.append(f"# Combine Publishers ({len(matrix.swift_publishers)})")
            for pub in matrix.swift_publishers[:15]:
                file_short = pub.get('file', '').split('/')[-1]
                lines.append(f"  @Published {pub['name']}:{pub.get('type', '?')}|{file_short}")

        # gRPC Services
        if hasattr(matrix, 'swift_grpc_services') and matrix.swift_grpc_services:
            lines.append(f"# gRPC Services ({len(matrix.swift_grpc_services)})")
            for svc in matrix.swift_grpc_services:
                file_short = svc.get('file', '').split('/')[-1]
                methods = svc.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                lines.append(f"  grpc {svc['name']}{meth_str}|{file_short}")

        return lines

    def _compress_swift_models(self, matrix) -> List[str]:
        """Compress Swift database models and Codable types."""
        lines = []

        # ORM Models (Core Data, SwiftData, GRDB, Realm)
        if hasattr(matrix, 'swift_models') and matrix.swift_models:
            by_orm = {}
            for model in matrix.swift_models:
                orm = model.get('orm', 'unknown')
                if orm not in by_orm:
                    by_orm[orm] = []
                by_orm[orm].append(model)

            for orm, models in by_orm.items():
                lines.append(f"# {orm} Models ({len(models)})")
                for model in models[:20]:
                    file_short = model.get('file', '').split('/')[-1]
                    fields = model.get('fields', [])
                    field_strs = [f"{f.get('name', '')}:{f.get('type', '?')}" if isinstance(f, dict) else str(f) for f in fields[:6]]
                    if len(fields) > 6:
                        field_strs.append(f"+{len(fields) - 6}more")
                    rels = model.get('relationships', [])
                    rel_str = f"|rels:[{','.join(r.get('name', '') if isinstance(r, dict) else str(r) for r in rels[:3])}]" if rels else ""
                    lines.append(f"  {model['name']}|{file_short}({','.join(field_strs)}){rel_str}")

        # Codable types
        if hasattr(matrix, 'swift_codables') and matrix.swift_codables:
            lines.append(f"# Codable Types ({len(matrix.swift_codables)})")
            for cod in matrix.swift_codables[:20]:
                file_short = cod.get('file', '').split('/')[-1]
                keys = cod.get('coding_keys', [])
                key_str = f"|CodingKeys:[{','.join(keys[:5])}]" if keys else ""
                custom = []
                if cod.get('has_custom_encode'):
                    custom.append('encode')
                if cod.get('has_custom_decode'):
                    custom.append('decode')
                custom_str = f"|custom:[{','.join(custom)}]" if custom else ""
                lines.append(f"  Codable {cod['name']}{key_str}{custom_str}|{file_short}")

        # Migrations
        if hasattr(matrix, 'swift_migrations') and matrix.swift_migrations:
            lines.append(f"# Migrations ({len(matrix.swift_migrations)})")
            for mig in matrix.swift_migrations[:10]:
                file_short = mig.get('file', '').split('/')[-1]
                lines.append(f"  {mig.get('orm', '?')} migration: {mig['name']}|{file_short}")

        return lines

    def _compress_swift_dependencies(self, matrix) -> List[str]:
        """Compress Swift Package.swift dependencies and metadata."""
        lines = []

        if hasattr(matrix, 'swift_dependencies') and matrix.swift_dependencies:
            deps = matrix.swift_dependencies

            # Package metadata
            pkg_name = deps.get('_package_name', '')
            tools_ver = deps.get('_swift_tools_version', '')
            if pkg_name:
                lines.append(f"# Package: {pkg_name} (swift-tools-version:{tools_ver})")

            # Platforms
            platforms = deps.get('_platforms', [])
            if platforms:
                plat_strs = [f"{p.get('platform', '')} v{p.get('version', '?')}" for p in platforms]
                lines.append(f"# Platforms: {', '.join(plat_strs)}")

            # Products
            products = deps.get('_products', [])
            if products:
                prod_strs = [f"{p.get('name', '')}({p.get('type', '')})" for p in products]
                lines.append(f"# Products: {', '.join(prod_strs)}")

            # Targets
            targets = deps.get('_targets', [])
            if targets:
                target_strs = [f"{t.get('name', '')}({t.get('type', '')})" for t in targets]
                lines.append(f"# Targets: {', '.join(target_strs[:10])}")

            # Dependencies
            dep_lines = []
            for name, version in sorted(deps.items()):
                if name.startswith('_'):
                    continue
                dep_lines.append(f"  {name}@{version}")

            if dep_lines:
                lines.append(f"# Dependencies ({len(dep_lines)})")
                lines.extend(dep_lines[:30])
                if len(dep_lines) > 30:
                    lines.append(f"  # ... and {len(dep_lines) - 30} more")

        # Detected frameworks
        if hasattr(matrix, 'swift_detected_frameworks') and matrix.swift_detected_frameworks:
            lines.append(f"# Detected: {', '.join(matrix.swift_detected_frameworks[:15])}")

        # Modules
        if hasattr(matrix, 'swift_modules') and matrix.swift_modules:
            lines.append(f"# Modules ({len(matrix.swift_modules)}): {', '.join(matrix.swift_modules[:15])}")

        # Swift version
        if hasattr(matrix, 'swift_version') and matrix.swift_version:
            lines.append(f"# Swift version: {matrix.swift_version}")

        # Property wrappers summary
        if hasattr(matrix, 'swift_property_wrappers') and matrix.swift_property_wrappers:
            pw_names = list(set(pw.get('name', '') for pw in matrix.swift_property_wrappers))
            lines.append(f"# Property Wrappers ({len(matrix.swift_property_wrappers)}): {', '.join(pw_names[:10])}")

        # Result builders summary
        if hasattr(matrix, 'swift_result_builders') and matrix.swift_result_builders:
            rb_names = [rb.get('name', '') for rb in matrix.swift_result_builders]
            lines.append(f"# Result Builders: {', '.join(rb_names[:5])}")

        # Macros summary
        if hasattr(matrix, 'swift_macros') and matrix.swift_macros:
            macro_names = [m.get('name', '') for m in matrix.swift_macros]
            lines.append(f"# Macros ({len(matrix.swift_macros)}): {', '.join(macro_names[:10])}")

        # Concurrency summary
        if hasattr(matrix, 'swift_concurrency') and matrix.swift_concurrency:
            conc_kinds = list(set(c.get('kind', '') for c in matrix.swift_concurrency))
            lines.append(f"# Concurrency patterns: {', '.join(conc_kinds[:8])}")

        # Availability summary
        if hasattr(matrix, 'swift_availability') and matrix.swift_availability:
            lines.append(f"# Availability annotations: {len(matrix.swift_availability)}")

        # Imports
        if hasattr(matrix, 'swift_imports') and matrix.swift_imports:
            lines.append(f"# Imports ({len(matrix.swift_imports)}): {', '.join(matrix.swift_imports[:20])}")

        return lines

    # ============================================
    # v4.23: Ruby Language Compression Methods
    # ============================================

    def _compress_ruby_types(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress Ruby type definitions (classes, modules, structs)."""
        lines = []

        # Classes
        if hasattr(matrix, 'ruby_classes') and matrix.ruby_classes:
            lines.append(f"# Classes ({len(matrix.ruby_classes)})")
            for cls in matrix.ruby_classes[:30]:
                file_short = cls.get('file', '').split('/')[-1]
                super_str = f" < {cls['superclass']}" if cls.get('superclass') else ""
                ns = f"{cls['namespace']}::" if cls.get('namespace') else ""
                mixins = cls.get('mixins', [])
                mixin_strs = [f"{m['type']}:{m['name']}" for m in mixins[:3]]
                mixin_str = f"|mix:[{','.join(mixin_strs)}]" if mixin_strs else ""
                fields = cls.get('fields', [])
                field_strs = [f"{f['name']}:{f.get('type', '?')}" for f in fields[:6]]
                if len(fields) > 6:
                    field_strs.append(f"+{len(fields) - 6}more")
                lines.append(f"  class {ns}{cls['name']}{super_str}{mixin_str}|{file_short}({','.join(field_strs)})")
            if len(matrix.ruby_classes) > 30:
                lines.append(f"  # ... and {len(matrix.ruby_classes) - 30} more classes")

        # Modules
        if hasattr(matrix, 'ruby_modules') and matrix.ruby_modules:
            lines.append(f"# Modules ({len(matrix.ruby_modules)})")
            for mod in matrix.ruby_modules[:30]:
                file_short = mod.get('file', '').split('/')[-1]
                ns = f"{mod['namespace']}::" if mod.get('namespace') else ""
                concern_str = "|concern" if mod.get('is_concern') else ""
                mixins = mod.get('mixins', [])
                mixin_strs = [f"{m['type']}:{m['name']}" for m in mixins[:3]]
                mixin_str = f"|mix:[{','.join(mixin_strs)}]" if mixin_strs else ""
                constants = mod.get('constants', [])
                const_str = f"|const:[{','.join(constants[:5])}]" if constants else ""
                lines.append(f"  module {ns}{mod['name']}{concern_str}{mixin_str}{const_str}|{file_short}")
            if len(matrix.ruby_modules) > 30:
                lines.append(f"  # ... and {len(matrix.ruby_modules) - 30} more modules")

        # Structs (Struct.new, Data.define)
        if hasattr(matrix, 'ruby_structs') and matrix.ruby_structs:
            lines.append(f"# Structs ({len(matrix.ruby_structs)})")
            for s in matrix.ruby_structs[:20]:
                file_short = s.get('file', '').split('/')[-1]
                data_str = "Data.define" if s.get('is_data') else "Struct.new"
                kw_str = "|keyword_init" if s.get('keyword_init') else ""
                members = s.get('members', [])
                mem_str = f"(:{', :'.join(members[:8])})" if members else ""
                if len(members) > 8:
                    mem_str = mem_str[:-1] + f", +{len(members) - 8}more)"
                lines.append(f"  {s['name']} = {data_str}{mem_str}{kw_str}|{file_short}")

        return lines

    def _compress_ruby_functions(self, matrix) -> List[str]:
        """Compress Ruby methods and accessors."""
        lines = []

        # Methods
        if hasattr(matrix, 'ruby_methods') and matrix.ruby_methods:
            lines.append(f"# Methods ({len(matrix.ruby_methods)} total)")
            for method in matrix.ruby_methods[:40]:
                file_short = method.get('file', '').split('/')[-1]
                params = method.get('params', [])
                param_strs = [f"{p.get('name', '')}:{p.get('type', '?')}" for p in params[:4]]
                if len(params) > 4:
                    param_strs.append(f"+{len(params) - 4}")

                qualifiers = []
                if method.get('is_class_method'):
                    qualifiers.append('self.')
                if method.get('is_singleton'):
                    qualifiers.append('singleton')
                if method.get('is_endless'):
                    qualifiers.append('endless')
                if method.get('yields'):
                    qualifiers.append('yields')
                qual_str = '|'.join(qualifiers) + '|' if qualifiers else ''
                vis = f"{method['visibility']} " if method.get('visibility') and method['visibility'] != 'public' else ""
                cls_str = f"{method['class_name']}#" if method.get('class_name') else ""
                ret_str = f" -> {method['return_type']}" if method.get('return_type') else ""

                lines.append(f"  {vis}def {cls_str}{method['name']}({','.join(param_strs)}){ret_str}|{qual_str}{file_short}")
            if len(matrix.ruby_methods) > 40:
                lines.append(f"  # ... and {len(matrix.ruby_methods) - 40} more methods")

        # Accessors
        if hasattr(matrix, 'ruby_accessors') and matrix.ruby_accessors:
            # Group by class
            by_class = {}
            for acc in matrix.ruby_accessors:
                cls = acc.get('class_name', 'global')
                if cls not in by_class:
                    by_class[cls] = []
                by_class[cls].append(acc)

            lines.append(f"# Accessors ({len(matrix.ruby_accessors)})")
            for cls, accs in list(by_class.items())[:15]:
                acc_strs = [f"{a['kind']}:{a['name']}" for a in accs[:8]]
                if len(accs) > 8:
                    acc_strs.append(f"+{len(accs) - 8}more")
                lines.append(f"  {cls}|{','.join(acc_strs)}")

        return lines

    def _compress_ruby_api(self, matrix) -> List[str]:
        """Compress Ruby API routes, controllers, gRPC, GraphQL."""
        lines = []

        # HTTP routes
        if hasattr(matrix, 'ruby_routes') and matrix.ruby_routes:
            # Group by framework
            by_framework = {}
            for route in matrix.ruby_routes:
                fw = route.get('framework', 'rails')
                if fw not in by_framework:
                    by_framework[fw] = []
                by_framework[fw].append(route)

            for fw, routes in by_framework.items():
                lines.append(f"# {fw} ({len(routes)} routes)")
                for route in routes[:30]:
                    file_short = route.get('file', '').split('/')[-1]
                    lines.append(f"  {route['method']} {route['path']}→{route['handler']}|{file_short}")
                if len(routes) > 30:
                    lines.append(f"  # ... and {len(routes) - 30} more routes")

        # Controllers
        if hasattr(matrix, 'ruby_controllers') and matrix.ruby_controllers:
            lines.append(f"# Controllers ({len(matrix.ruby_controllers)})")
            for ctrl in matrix.ruby_controllers[:20]:
                file_short = ctrl.get('file', '').split('/')[-1]
                super_str = f" < {ctrl['superclass']}" if ctrl.get('superclass') else ""
                actions = ctrl.get('actions', [])
                action_str = f"|actions:[{','.join(actions[:8])}]" if actions else ""
                if len(actions) > 8:
                    action_str = action_str[:-1] + f",+{len(actions) - 8}more]"
                filters = ctrl.get('filters', [])
                filter_str = f"|filters:[{','.join(filters[:3])}]" if filters else ""
                lines.append(f"  {ctrl['name']}{super_str}{action_str}{filter_str}|{file_short}")

        # gRPC services
        if hasattr(matrix, 'ruby_grpc_services') and matrix.ruby_grpc_services:
            lines.append("# gRPC Services")
            for svc in matrix.ruby_grpc_services:
                file_short = svc.get('file', '').split('/')[-1]
                methods = svc.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                lines.append(f"  grpc {svc['name']}{meth_str}|{file_short}")

        # GraphQL types
        if hasattr(matrix, 'ruby_graphql_types') and matrix.ruby_graphql_types:
            lines.append("# GraphQL Types")
            for gql in matrix.ruby_graphql_types:
                file_short = gql.get('file', '').split('/')[-1]
                fields = gql.get('fields', [])
                field_str = f"|fields:[{','.join(fields[:5])}]" if fields else ""
                lines.append(f"  {gql['kind']} {gql['name']}{field_str}|{file_short}")

        # ActionCable Channels
        if hasattr(matrix, 'ruby_channels') and matrix.ruby_channels:
            lines.append("# ActionCable Channels")
            for ch in matrix.ruby_channels[:10]:
                file_short = ch.get('file', '').split('/')[-1]
                lines.append(f"  channel {ch.get('name', '?')}|{file_short}")

        # Middleware
        if hasattr(matrix, 'ruby_middleware') and matrix.ruby_middleware:
            lines.append(f"# Middleware: {', '.join(matrix.ruby_middleware[:10])}")

        return lines

    def _compress_ruby_models(self, matrix) -> List[str]:
        """Compress Ruby ORM models and migrations."""
        lines = []

        # Models
        if hasattr(matrix, 'ruby_models') and matrix.ruby_models:
            # Group by ORM
            by_orm = {}
            for model in matrix.ruby_models:
                orm = model.get('orm', 'activerecord')
                if orm not in by_orm:
                    by_orm[orm] = []
                by_orm[orm].append(model)

            for orm, models in by_orm.items():
                lines.append(f"# {orm} Models ({len(models)})")
                for model in models[:30]:
                    file_short = model.get('file', '').split('/')[-1]
                    table_str = f"|table:{model['table_name']}" if model.get('table_name') else ""
                    sti_str = "|STI" if model.get('is_sti') else ""

                    assocs = model.get('associations', [])
                    assoc_strs = [f"{a['type']}:{a['name']}" for a in assocs[:5]]
                    assoc_str = f"|assoc:[{','.join(assoc_strs)}]" if assoc_strs else ""

                    vals = model.get('validations', [])
                    val_strs = [f"{v['type']}:{v['field']}" for v in vals[:3]]
                    val_str = f"|val:[{','.join(val_strs)}]" if val_strs else ""

                    scopes = model.get('scopes', [])
                    scope_strs = [s['name'] for s in scopes[:3]]
                    scope_str = f"|scope:[{','.join(scope_strs)}]" if scope_strs else ""

                    enums = model.get('enums', [])
                    enum_str = f"|enum:[{','.join(enums[:3])}]" if enums else ""

                    lines.append(f"  {model['name']}{table_str}{sti_str}{assoc_str}{val_str}{scope_str}{enum_str}|{file_short}")
                if len(models) > 30:
                    lines.append(f"  # ... and {len(models) - 30} more models")

        # Migrations
        if hasattr(matrix, 'ruby_migrations') and matrix.ruby_migrations:
            lines.append(f"# Migrations ({len(matrix.ruby_migrations)})")
            for mig in matrix.ruby_migrations[:20]:
                file_short = mig.get('file', '').split('/')[-1]
                ver_str = f"[{mig['version']}]" if mig.get('version') else ""
                ops = mig.get('operations', [])
                ops_str = f"|ops:[{','.join(ops[:5])}]" if ops else ""
                if len(ops) > 5:
                    ops_str = ops_str[:-1] + f",+{len(ops) - 5}more]"
                lines.append(f"  {mig['name']}{ver_str}{ops_str}|{file_short}")
            if len(matrix.ruby_migrations) > 20:
                lines.append(f"  # ... and {len(matrix.ruby_migrations) - 20} more migrations")

        return lines

    def _compress_ruby_dependencies(self, matrix) -> List[str]:
        """Compress Ruby Gemfile dependencies and metadata."""
        lines = []

        # Gems from Gemfile
        if hasattr(matrix, 'ruby_gems') and matrix.ruby_gems:
            # Group by group
            by_group = {}
            for gem in matrix.ruby_gems:
                group = gem.get('group', 'default')
                if group not in by_group:
                    by_group[group] = []
                by_group[group].append(gem)

            for group, gems in by_group.items():
                lines.append(f"# {group} ({len(gems)} gems)")
                for gem in gems[:30]:
                    ver_str = f"@{gem['version']}" if gem.get('version') else ""
                    lines.append(f"  {gem['name']}{ver_str}")
                if len(gems) > 30:
                    lines.append(f"  # ... and {len(gems) - 30} more gems")

        # Detected frameworks
        if hasattr(matrix, 'ruby_detected_frameworks') and matrix.ruby_detected_frameworks:
            lines.append(f"# Detected: {', '.join(matrix.ruby_detected_frameworks[:15])}")

        # Ruby version
        if hasattr(matrix, 'ruby_version') and matrix.ruby_version:
            lines.append(f"# Ruby version: {matrix.ruby_version}")

        # Concerns summary
        if hasattr(matrix, 'ruby_concerns') and matrix.ruby_concerns:
            concern_names = [c.get('name', '') for c in matrix.ruby_concerns]
            lines.append(f"# Concerns ({len(matrix.ruby_concerns)}): {', '.join(concern_names[:10])}")

        # Workers summary
        if hasattr(matrix, 'ruby_workers') and matrix.ruby_workers:
            worker_names = [w.get('name', '') for w in matrix.ruby_workers]
            lines.append(f"# Workers ({len(matrix.ruby_workers)}): {', '.join(worker_names[:10])}")

        # Rake tasks summary
        if hasattr(matrix, 'ruby_rake_tasks') and matrix.ruby_rake_tasks:
            task_names = [t.get('name', '') for t in matrix.ruby_rake_tasks]
            lines.append(f"# Rake Tasks ({len(matrix.ruby_rake_tasks)}): {', '.join(task_names[:10])}")

        # Callbacks summary
        if hasattr(matrix, 'ruby_callbacks') and matrix.ruby_callbacks:
            cb_types = list(set(cb.get('type', '') for cb in matrix.ruby_callbacks))
            lines.append(f"# Callbacks ({len(matrix.ruby_callbacks)}): {', '.join(cb_types[:8])}")

        # Metaprogramming summary
        if hasattr(matrix, 'ruby_metaprogramming') and matrix.ruby_metaprogramming:
            meta_types = list(set(m.get('type', '') for m in matrix.ruby_metaprogramming))
            lines.append(f"# Metaprogramming: {', '.join(meta_types[:8])}")

        # DSL macros summary
        if hasattr(matrix, 'ruby_dsl_macros') and matrix.ruby_dsl_macros:
            macro_types = list(set(m.get('type', '') for m in matrix.ruby_dsl_macros))
            lines.append(f"# DSL Macros: {', '.join(macro_types[:8])}")

        # Imports
        if hasattr(matrix, 'ruby_imports') and matrix.ruby_imports:
            lines.append(f"# Requires ({len(matrix.ruby_imports)}): {', '.join(matrix.ruby_imports[:20])}")

        return lines

