    def _compress_wordpress(self, matrix) -> List[str]:
        """Compress WordPress framework data (hooks, post types, REST, blocks, etc.)."""
        lines = []
        hooks = getattr(matrix, 'wordpress_hooks', [])
        post_types = getattr(matrix, 'wordpress_post_types', [])
        rest_routes = getattr(matrix, 'wordpress_rest_routes', [])
        if not hooks and not post_types and not rest_routes:
            return lines
        frameworks = getattr(matrix, 'wordpress_detected_frameworks', [])
        version = getattr(matrix, 'wordpress_version', '')
        is_plugin = getattr(matrix, 'wordpress_is_plugin', False)
        is_theme = getattr(matrix, 'wordpress_is_theme', False)
        if frameworks:
            lines.append(f"# Ecosystem: {', '.join(frameworks[:15])}")
        if version:
            lines.append(f"# WordPress version: {version}")
        if is_plugin:
            lines.append("# Type: Plugin")
        if is_theme:
            lines.append("# Type: Theme")
        if hooks:
            actions = [h for h in hooks if h.get('kind') == 'action']
            filters = [h for h in hooks if h.get('kind') == 'filter']
            if actions:
                lines.append(f"## Actions ({len(actions)})")
                for a in actions[:30]:
                    f = a.get('file', '').split('/')[-1]
                    lines.append(f"  {a.get('name', '?')}|cb:{a.get('callback', '?')}|pri:{a.get('priority', 10)}|{f}")
                if len(actions) > 30:
                    lines.append(f"  # ... and {len(actions) - 30} more actions")
            if filters:
                lines.append(f"## Filters ({len(filters)})")
                for fl in filters[:30]:
                    f = fl.get('file', '').split('/')[-1]
                    lines.append(f"  {fl.get('name', '?')}|cb:{fl.get('callback', '?')}|{f}")
                if len(filters) > 30:
                    lines.append(f"  # ... and {len(filters) - 30} more filters")
        if post_types:
            lines.append(f"## CustomPostTypes ({len(post_types)})")
            for pt in post_types[:15]:
                rest = "|rest" if pt.get('show_in_rest') else ""
                lines.append(f"  {pt.get('name', '?')}|label:{pt.get('label', '?')}{rest}")
        taxonomies = getattr(matrix, 'wordpress_taxonomies', [])
        if taxonomies:
            lines.append(f"## Taxonomies ({len(taxonomies)})")
            for t in taxonomies[:15]:
                lines.append(f"  {t.get('name', '?')}|types:{','.join(t.get('post_types', [])[:3])}")
        shortcodes = getattr(matrix, 'wordpress_shortcodes', [])
        if shortcodes:
            lines.append(f"## Shortcodes ({len(shortcodes)})")
            for sc in shortcodes[:15]:
                lines.append(f"  [{sc.get('tag', '?')}]|cb:{sc.get('callback', '?')}")
        if rest_routes:
            lines.append(f"## REST Routes ({len(rest_routes)})")
            for rr in rest_routes[:30]:
                f = rr.get('file', '').split('/')[-1]
                lines.append(f"  {rr.get('method', 'GET')} /{rr.get('namespace', '')}{rr.get('route', '')}|{f}")
            if len(rest_routes) > 30:
                lines.append(f"  # ... and {len(rest_routes) - 30} more REST routes")
        blocks = getattr(matrix, 'wordpress_blocks', [])
        if blocks:
            lines.append(f"## Blocks ({len(blocks)})")
            for b in blocks[:15]:
                dyn = "|dynamic" if b.get('is_dynamic') else ""
                lines.append(f"  {b.get('name', '?')}{dyn}")
        widgets = getattr(matrix, 'wordpress_widgets', [])
        if widgets:
            lines.append(f"## Widgets ({len(widgets)})")
            for w in widgets[:10]:
                lines.append(f"  {w.get('name', '?')}")
        admin_pages = getattr(matrix, 'wordpress_admin_pages', [])
        if admin_pages:
            lines.append(f"## AdminPages ({len(admin_pages)})")
            for ap in admin_pages[:10]:
                lines.append(f"  {ap.get('title', '?')}|slug:{ap.get('slug', '?')}")
        ajax = getattr(matrix, 'wordpress_ajax_handlers', [])
        if ajax:
            lines.append(f"## AJAX ({len(ajax)})")
            for aj in ajax[:15]:
                nopriv = "|nopriv" if aj.get('is_nopriv') else ""
                lines.append(f"  {aj.get('action', '?')}{nopriv}|cb:{aj.get('callback', '?')}")
        cron = getattr(matrix, 'wordpress_cron_events', [])
        if cron:
            lines.append(f"## Cron ({len(cron)})")
            for cr in cron[:10]:
                lines.append(f"  {cr.get('hook', '?')}|{cr.get('recurrence', '?')}")
        return lines

    # ============================================
    # v4.25: Scala Compression Methods
    # ============================================

    def _compress_scala_types(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress Scala types (classes, traits, objects, enums, type aliases, givens)."""
        lines = []

        # Classes
        if hasattr(matrix, 'scala_classes') and matrix.scala_classes:
            lines.append(f"# Classes ({len(matrix.scala_classes)})")
            for cls in matrix.scala_classes[:40]:
                file_short = cls.get('file', '').split('/')[-1]
                kind = cls.get('kind', 'class')
                ext = f"|<{cls['extends']}" if cls.get('extends') else ""
                mixins = cls.get('mixins', [])
                mix_str = f"|with:[{','.join(mixins[:3])}]" if mixins else ""
                flags = []
                if cls.get('is_sealed'):
                    flags.append('sealed')
                if cls.get('is_case'):
                    flags.append('case')
                if cls.get('is_value_class'):
                    flags.append('AnyVal')
                if cls.get('is_implicit'):
                    flags.append('implicit')
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                generics = cls.get('generics', [])
                gen_str = f"[{','.join(generics[:3])}]" if generics else ""
                params = cls.get('params', [])
                param_str = ""
                if params:
                    p_strs = [f"{p['name']}:{p.get('type', '?')}" for p in params[:5]]
                    param_str = f"|({','.join(p_strs)})"
                lines.append(f"  {kind} {cls['name']}{gen_str}{param_str}{ext}{mix_str}{flag_str}|{file_short}")
            if len(matrix.scala_classes) > 40:
                lines.append(f"  # ... and {len(matrix.scala_classes) - 40} more classes")

        # Traits
        if hasattr(matrix, 'scala_traits') and matrix.scala_traits:
            lines.append(f"# Traits ({len(matrix.scala_traits)})")
            for trait in matrix.scala_traits[:30]:
                file_short = trait.get('file', '').split('/')[-1]
                extends = trait.get('extends', [])
                ext_str = f"|<[{','.join(extends[:3])}]" if extends else ""
                flags = []
                if trait.get('is_sealed'):
                    flags.append('sealed')
                if trait.get('is_transparent'):
                    flags.append('transparent')
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                generics = trait.get('generics', [])
                gen_str = f"[{','.join(generics[:3])}]" if generics else ""
                lines.append(f"  trait {trait['name']}{gen_str}{ext_str}{flag_str}|{file_short}")
            if len(matrix.scala_traits) > 30:
                lines.append(f"  # ... and {len(matrix.scala_traits) - 30} more traits")

        # Objects
        if hasattr(matrix, 'scala_objects') and matrix.scala_objects:
            lines.append(f"# Objects ({len(matrix.scala_objects)})")
            for obj in matrix.scala_objects[:30]:
                file_short = obj.get('file', '').split('/')[-1]
                kind = obj.get('kind', 'object')
                ext = f"|<{obj['extends']}" if obj.get('extends') else ""
                lines.append(f"  {kind} {obj['name']}{ext}|{file_short}")
            if len(matrix.scala_objects) > 30:
                lines.append(f"  # ... and {len(matrix.scala_objects) - 30} more objects")

        # Enums
        if hasattr(matrix, 'scala_enums') and matrix.scala_enums:
            lines.append(f"# Enums ({len(matrix.scala_enums)})")
            for enum in matrix.scala_enums[:20]:
                file_short = enum.get('file', '').split('/')[-1]
                cases = enum.get('cases', [])
                cases_str = f"|[{','.join(cases[:5])}]" if cases else ""
                lines.append(f"  enum {enum['name']}{cases_str}|{file_short}")

        # Type Aliases
        if hasattr(matrix, 'scala_type_aliases') and matrix.scala_type_aliases:
            lines.append(f"# Type Aliases ({len(matrix.scala_type_aliases)})")
            for ta in matrix.scala_type_aliases[:20]:
                file_short = ta.get('file', '').split('/')[-1]
                opaque = "opaque " if ta.get('is_opaque') else ""
                lines.append(f"  {opaque}type {ta['name']}={ta.get('target', '?')}|{file_short}")

        # Givens (Scala 3)
        if hasattr(matrix, 'scala_givens') and matrix.scala_givens:
            lines.append(f"# Givens ({len(matrix.scala_givens)})")
            for given in matrix.scala_givens[:20]:
                file_short = given.get('file', '').split('/')[-1]
                lines.append(f"  given {given['name']}:{given.get('type', '?')}|{file_short}")

        return lines

    def _compress_scala_functions(self, matrix) -> List[str]:
        """Compress Scala methods, extension methods, implicits, macros."""
        lines = []

        # Methods
        if hasattr(matrix, 'scala_methods') and matrix.scala_methods:
            lines.append(f"# Methods ({len(matrix.scala_methods)})")
            for method in matrix.scala_methods[:50]:
                file_short = method.get('file', '').split('/')[-1]
                ret = f":{method['return_type']}" if method.get('return_type') else ""
                flags = []
                if method.get('is_override'):
                    flags.append('override')
                if method.get('is_implicit'):
                    flags.append('implicit')
                if method.get('is_inline'):
                    flags.append('inline')
                if method.get('is_abstract'):
                    flags.append('abstract')
                if method.get('is_tailrec'):
                    flags.append('@tailrec')
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                params = method.get('params', [])
                if params:
                    p_strs = [f"{p['name']}:{p.get('type', '?')}" for p in params[:5]]
                    param_str = f"({','.join(p_strs)})"
                else:
                    param_str = ""
                vis = method.get('visibility', 'public')
                vis_str = f"|{vis}" if vis != 'public' else ""
                lines.append(f"  def {method['name']}{param_str}{ret}{flag_str}{vis_str}|{file_short}")
            if len(matrix.scala_methods) > 50:
                lines.append(f"  # ... and {len(matrix.scala_methods) - 50} more methods")

        # Extension Methods
        if hasattr(matrix, 'scala_extension_methods') and matrix.scala_extension_methods:
            lines.append(f"# Extension Methods ({len(matrix.scala_extension_methods)})")
            for ext in matrix.scala_extension_methods[:20]:
                file_short = ext.get('file', '').split('/')[-1]
                ret = f":{ext['return_type']}" if ext.get('return_type') else ""
                params = ext.get('params', [])
                param_str = ""
                if params:
                    p_strs = [f"{p['name']}:{p.get('type', '?')}" for p in params[:5]]
                    param_str = f"({','.join(p_strs)})"
                lines.append(f"  extension def {ext['name']}{param_str}{ret}|{file_short}")

        # Implicits
        if hasattr(matrix, 'scala_implicits') and matrix.scala_implicits:
            lines.append(f"# Implicits/Givens ({len(matrix.scala_implicits)})")
            for impl in matrix.scala_implicits[:20]:
                file_short = impl.get('file', '').split('/')[-1]
                kind = impl.get('kind', 'implicit_val')
                conv_str = ""
                if impl.get('is_conversion'):
                    conv_str = f"|{impl.get('from_type', '?')}->{impl.get('to_type', '?')}"
                lines.append(f"  {kind} {impl['name']}:{impl.get('type', '?')}{conv_str}|{file_short}")

        # Macros
        if hasattr(matrix, 'scala_macros') and matrix.scala_macros:
            lines.append(f"# Macros/Inline ({len(matrix.scala_macros)})")
            for macro in matrix.scala_macros[:15]:
                file_short = macro.get('file', '').split('/')[-1]
                lines.append(f"  {macro.get('kind', 'macro')} {macro['name']}|{file_short}")

        return lines

    def _compress_scala_api(self, matrix) -> List[str]:
        """Compress Scala API routes, controllers, gRPC, GraphQL."""
        lines = []

        # Routes
        if hasattr(matrix, 'scala_routes') and matrix.scala_routes:
            # Group by framework
            by_framework = {}
            for route in matrix.scala_routes:
                fw = route.get('framework', 'unknown')
                if fw not in by_framework:
                    by_framework[fw] = []
                by_framework[fw].append(route)

            for fw, routes in by_framework.items():
                lines.append(f"# {fw} routes ({len(routes)})")
                for route in routes[:25]:
                    file_short = route.get('file', '').split('/')[-1]
                    handler = route.get('handler', '')
                    handler_str = f"|{handler}" if handler else ""
                    controller = route.get('controller', '')
                    ctrl_str = f"|ctrl:{controller}" if controller else ""
                    lines.append(f"  {route.get('method', '?')} {route.get('path', '/')}{handler_str}{ctrl_str}|{file_short}")
                if len(routes) > 25:
                    lines.append(f"  # ... and {len(routes) - 25} more {fw} routes")

        # Controllers
        if hasattr(matrix, 'scala_controllers') and matrix.scala_controllers:
            lines.append(f"# Controllers ({len(matrix.scala_controllers)})")
            for ctrl in matrix.scala_controllers[:20]:
                file_short = ctrl.get('file', '').split('/')[-1]
                fw = ctrl.get('framework', '')
                parent = f"|<{ctrl['parent']}" if ctrl.get('parent') else ""
                actions = ctrl.get('actions', [])
                act_str = f"|actions:[{','.join(actions[:5])}]" if actions else ""
                inj = ctrl.get('injected', [])
                inj_str = f"|inject:[{','.join(inj[:3])}]" if inj else ""
                lines.append(f"  {ctrl['name']}|{fw}{parent}{act_str}{inj_str}|{file_short}")

        # gRPC Services
        if hasattr(matrix, 'scala_grpc_services') and matrix.scala_grpc_services:
            lines.append(f"# gRPC Services ({len(matrix.scala_grpc_services)})")
            for grpc in matrix.scala_grpc_services[:10]:
                file_short = grpc.get('file', '').split('/')[-1]
                methods = grpc.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                lines.append(f"  {grpc['name']}|{grpc.get('framework', 'scalapb')}{meth_str}|{file_short}")

        # GraphQL Types
        if hasattr(matrix, 'scala_graphql_types') and matrix.scala_graphql_types:
            lines.append(f"# GraphQL Types ({len(matrix.scala_graphql_types)})")
            for gql in matrix.scala_graphql_types[:15]:
                file_short = gql.get('file', '').split('/')[-1]
                lines.append(f"  {gql.get('kind', 'type')} {gql['name']}|{gql.get('framework', 'caliban')}|{file_short}")

        return lines

    def _compress_scala_models(self, matrix) -> List[str]:
        """Compress Scala database models, migrations, and codecs."""
        lines = []

        # Models
        if hasattr(matrix, 'scala_models') and matrix.scala_models:
            lines.append(f"# Models ({len(matrix.scala_models)})")
            for model in matrix.scala_models[:25]:
                file_short = model.get('file', '').split('/')[-1]
                orm = model.get('orm', 'slick')
                table = f"|table:{model['table_name']}" if model.get('table_name') else ""
                case_cls = f"|case:{model['case_class']}" if model.get('case_class') else ""
                columns = model.get('columns', [])
                col_strs = []
                for c in columns[:5]:
                    pk_flag = "*" if c.get('pk') else ""
                    col_strs.append(f"{pk_flag}{c['name']}:{c.get('type', '?')}")
                col_str = f"|cols:[{','.join(col_strs)}]" if col_strs else ""
                fks = model.get('foreign_keys', [])
                fk_str = f"|fk({len(fks)})" if fks else ""
                lines.append(f"  {model['name']}|{orm}{table}{case_cls}{col_str}{fk_str}|{file_short}")

        # Migrations
        if hasattr(matrix, 'scala_migrations') and matrix.scala_migrations:
            lines.append(f"# Migrations ({len(matrix.scala_migrations)})")
            for mig in matrix.scala_migrations[:15]:
                file_short = mig.get('file', '').split('/')[-1]
                ver = f"|v{mig['version']}" if mig.get('version') else ""
                lines.append(f"  {mig['name']}|{mig.get('framework', 'evolutions')}{ver}|{file_short}")

        # Codecs
        if hasattr(matrix, 'scala_codecs') and matrix.scala_codecs:
            # Group by framework
            by_fw = {}
            for codec in matrix.scala_codecs:
                fw = codec.get('framework', 'unknown')
                if fw not in by_fw:
                    by_fw[fw] = []
                by_fw[fw].append(codec)

            for fw, codecs in by_fw.items():
                lines.append(f"# {fw} codecs ({len(codecs)})")
                for codec in codecs[:15]:
                    file_short = codec.get('file', '').split('/')[-1]
                    kind = codec.get('kind', 'codec')
                    auto = "|auto" if codec.get('auto_derived') else ""
                    lines.append(f"  {kind} {codec.get('target_type', codec['name'])}{auto}|{file_short}")
                if len(codecs) > 15:
                    lines.append(f"  # ... and {len(codecs) - 15} more {fw} codecs")

        return lines

    def _compress_scala_dependencies(self, matrix) -> List[str]:
        """Compress Scala dependencies, frameworks, compiler options, annotations."""
        lines = []

        # Dependencies
        if hasattr(matrix, 'scala_dependencies') and matrix.scala_dependencies:
            # Group by scope
            by_scope = {}
            for dep in matrix.scala_dependencies:
                scope = dep.get('scope', 'compile')
                if scope not in by_scope:
                    by_scope[scope] = []
                by_scope[scope].append(dep)

            for scope, deps in by_scope.items():
                lines.append(f"# {scope} ({len(deps)} deps)")
                for dep in deps[:30]:
                    cross = dep.get('cross', '%%')
                    lines.append(f"  {dep.get('group', '?')}{cross}{dep.get('artifact', '?')}@{dep.get('version', '?')}")
                if len(deps) > 30:
                    lines.append(f"  # ... and {len(deps) - 30} more {scope} deps")

        # Detected frameworks
        if hasattr(matrix, 'scala_detected_frameworks') and matrix.scala_detected_frameworks:
            lines.append(f"# Detected: {', '.join(matrix.scala_detected_frameworks[:20])}")

        # Scala version
        if hasattr(matrix, 'scala_version') and matrix.scala_version:
            lines.append(f"# Scala version: {matrix.scala_version}")

        # Compiler options
        if hasattr(matrix, 'scala_compiler_options') and matrix.scala_compiler_options:
            opts = matrix.scala_compiler_options[:20]
            lines.append(f"# scalacOptions ({len(matrix.scala_compiler_options)}): {', '.join(opts)}")

        # Annotations (grouped by name)
        if hasattr(matrix, 'scala_annotations') and matrix.scala_annotations:
            ann_names = {}
            for ann in matrix.scala_annotations:
                name = ann.get('name', '?')
                ann_names[name] = ann_names.get(name, 0) + 1
            top_anns = sorted(ann_names.items(), key=lambda x: x[1], reverse=True)[:15]
            ann_str = ', '.join(f"{n}({c})" for n, c in top_anns)
            lines.append(f"# Annotations ({len(matrix.scala_annotations)}): {ann_str}")

        return lines

    # ──────────────────────────────────────────────────────────────────
    # v4.26 R Language Compression Methods
    # ──────────────────────────────────────────────────────────────────

    def _compress_r_types(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress R types (R6/R5/S4/S3/S7 classes, generics, S4 methods, environments)."""
        lines = []

        # Classes (R6, R5, S4, S3, S7)
        if hasattr(matrix, 'r_classes') and matrix.r_classes:
            lines.append(f"# Classes ({len(matrix.r_classes)})")
            for cls in matrix.r_classes[:40]:
                file_short = cls.get('file', '').split('/')[-1]
                kind = cls.get('kind', 'R6')
                sup = f"|<{cls['superclass']}" if cls.get('superclass') else ""
                fields = cls.get('fields', [])
                fld_strs = []
                for f in fields[:5]:
                    acc = f.get('visibility', 'public')[0] if f.get('visibility') else 'p'
                    fld_strs.append(f"{acc}:{f['name']}")
                fld_str = f"|fields:[{','.join(fld_strs)}]" if fld_strs else ""
                methods = cls.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                ab = cls.get('active_bindings', [])
                ab_str = f"|active:[{','.join(ab[:3])}]" if ab else ""
                lines.append(f"  {kind} {cls['name']}{sup}{fld_str}{meth_str}{ab_str}|{file_short}")
            if len(matrix.r_classes) > 40:
                lines.append(f"  # ... and {len(matrix.r_classes) - 40} more classes")

        # Generics (S4 generics, S7 generics)
        if hasattr(matrix, 'r_generics') and matrix.r_generics:
            lines.append(f"# Generics ({len(matrix.r_generics)})")
            for gen in matrix.r_generics[:20]:
                file_short = gen.get('file', '').split('/')[-1]
                kind = gen.get('kind', 'S4')
                sig = gen.get('signature', '')
                sig_str = f"|sig:{sig[:60]}" if sig else ""
                lines.append(f"  {kind} generic {gen['name']}{sig_str}|{file_short}")

        # S4 Methods
        if hasattr(matrix, 'r_s4_methods') and matrix.r_s4_methods:
            lines.append(f"# S4 Methods ({len(matrix.r_s4_methods)})")
            for s4m in matrix.r_s4_methods[:25]:
                file_short = s4m.get('file', '').split('/')[-1]
                sig = s4m.get('signature', {})
                sig_strs = [f"{k}={v}" for k, v in sig.items()] if isinstance(sig, dict) else [str(sig)]
                sig_str = f"|({','.join(sig_strs[:3])})" if sig_strs else ""
                lines.append(f"  setMethod({s4m['generic']}{sig_str})|{file_short}")

        # Environments
        if hasattr(matrix, 'r_environments') and matrix.r_environments:
            lines.append(f"# Environments ({len(matrix.r_environments)})")
            for env in matrix.r_environments[:15]:
                file_short = env.get('file', '').split('/')[-1]
                parent = f"|parent:{env['parent']}" if env.get('parent') else ""
                lines.append(f"  env {env['name']}{parent}|{file_short}")

        return lines

    def _compress_r_functions(self, matrix) -> List[str]:
        """Compress R functions, S3 methods, operators, pipe chains."""
        lines = []

        # Functions
        if hasattr(matrix, 'r_functions') and matrix.r_functions:
            lines.append(f"# Functions ({len(matrix.r_functions)})")
            for func in matrix.r_functions[:50]:
                file_short = func.get('file', '').split('/')[-1]
                params = func.get('params', [])
                if params:
                    p_strs = []
                    for p in params[:5]:
                        dflt = f"={p['default'][:20]}" if p.get('default') else ""
                        p_strs.append(f"{p['name']}{dflt}")
                    param_str = f"({','.join(p_strs)})"
                else:
                    param_str = "()"
                flags = []
                if func.get('is_s3_method'):
                    flags.append(f"S3:{func.get('s3_generic', '')}.{func.get('s3_class', '')}")
                if func.get('is_operator'):
                    flags.append('op')
                if func.get('uses_nse'):
                    flags.append('NSE')
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                cmplx = func.get('complexity', 0)
                try:
                    cmplx = int(cmplx) if cmplx else 0
                except (ValueError, TypeError):
                    cmplx = 0
                cmplx_str = f"|cx:{cmplx}" if cmplx > 5 else ""
                lines.append(f"  {func['name']}{param_str}{flag_str}{cmplx_str}|{file_short}")
            if len(matrix.r_functions) > 50:
                lines.append(f"  # ... and {len(matrix.r_functions) - 50} more functions")

        # Pipe Chains
        if hasattr(matrix, 'r_pipe_chains') and matrix.r_pipe_chains:
            lines.append(f"# Pipe Chains ({len(matrix.r_pipe_chains)})")
            for chain in matrix.r_pipe_chains[:20]:
                file_short = chain.get('file', '').split('/')[-1]
                pipe = chain.get('pipe', '|>')
                steps = chain.get('steps', [])
                steps_str = f"|steps:[{' -> '.join(steps[:6])}]" if steps else ""
                lines.append(f"  {chain.get('start', '?')}{pipe}{steps_str}|len:{chain.get('length', 0)}|{file_short}")

        return lines

    def _compress_r_api(self, matrix) -> List[str]:
        """Compress R API routes, Shiny components, and endpoints."""
        lines = []

        # Routes (Plumber/RestRserve/Ambiorix)
        if hasattr(matrix, 'r_routes') and matrix.r_routes:
            # Group by framework
            by_framework = {}
            for route in matrix.r_routes:
                fw = route.get('framework', 'plumber')
                if fw not in by_framework:
                    by_framework[fw] = []
                by_framework[fw].append(route)

            for fw, routes in by_framework.items():
                lines.append(f"# {fw} routes ({len(routes)})")
                for route in routes[:25]:
                    file_short = route.get('file', '').split('/')[-1]
                    handler = route.get('handler', '')
                    handler_str = f"|{handler}" if handler else ""
                    params = route.get('params', [])
                    param_str = f"|params:[{','.join(params[:5])}]" if params else ""
                    lines.append(f"  {route.get('method', '?')} {route.get('path', '/')}{handler_str}{param_str}|{file_short}")
                if len(routes) > 25:
                    lines.append(f"  # ... and {len(routes) - 25} more {fw} routes")

        # Shiny Components
        if hasattr(matrix, 'r_shiny_components') and matrix.r_shiny_components:
            # Group by kind
            by_kind = {}
            for comp in matrix.r_shiny_components:
                kind = comp.get('kind', 'other')
                if kind not in by_kind:
                    by_kind[kind] = []
                by_kind[kind].append(comp)

            for kind, comps in by_kind.items():
                lines.append(f"# Shiny {kind} ({len(comps)})")
                for comp in comps[:15]:
                    file_short = comp.get('file', '').split('/')[-1]
                    mod = f"|module:{comp['module_id']}" if comp.get('module_id') else ""
                    lines.append(f"  {comp['name']}{mod}|{file_short}")

        # API Endpoints
        if hasattr(matrix, 'r_api_endpoints') and matrix.r_api_endpoints:
            lines.append(f"# API Endpoints ({len(matrix.r_api_endpoints)})")
            for ep in matrix.r_api_endpoints[:20]:
                file_short = ep.get('file', '').split('/')[-1]
                lines.append(f"  {ep.get('method', '?')} {ep.get('path', '/')}|{ep.get('framework', '?')}|{file_short}")

        return lines

    def _compress_r_models(self, matrix) -> List[str]:
        """Compress R database connections, queries, data models, data pipelines."""
        lines = []

        # DB Connections
        if hasattr(matrix, 'r_db_connections') and matrix.r_db_connections:
            lines.append(f"# DB Connections ({len(matrix.r_db_connections)})")
            for conn in matrix.r_db_connections[:15]:
                file_short = conn.get('file', '').split('/')[-1]
                db = f"|db:{conn['database']}" if conn.get('database') else ""
                pool = "|pool" if conn.get('pool') else ""
                lines.append(f"  {conn.get('driver', '?')}{db}{pool}|{file_short}")

        # DB Queries
        if hasattr(matrix, 'r_db_queries') and matrix.r_db_queries:
            lines.append(f"# DB Queries ({len(matrix.r_db_queries)})")
            for query in matrix.r_db_queries[:25]:
                file_short = query.get('file', '').split('/')[-1]
                param = "|param" if query.get('parameterized') else ""
                lines.append(f"  {query.get('operation', '?')} {query.get('table', '?')}{param}|{file_short}")

        # Data Models
        if hasattr(matrix, 'r_data_models') and matrix.r_data_models:
            lines.append(f"# Data Models ({len(matrix.r_data_models)})")
            for model in matrix.r_data_models[:25]:
                file_short = model.get('file', '').split('/')[-1]
                src = f"|src:{model['source']}" if model.get('source') else ""
                fmt = f"|fmt:{model['format']}" if model.get('format') else ""
                cols = model.get('columns', [])
                col_str = f"|cols:[{','.join(cols[:5])}]" if cols else ""
                lines.append(f"  {model['name']}{src}{fmt}{col_str}|{file_short}")

        # Data Pipelines
        if hasattr(matrix, 'r_data_pipelines') and matrix.r_data_pipelines:
            lines.append(f"# Data Pipelines ({len(matrix.r_data_pipelines)})")
            for pl in matrix.r_data_pipelines[:15]:
                file_short = pl.get('file', '').split('/')[-1]
                steps = pl.get('steps', [])
                steps_str = f"|steps:[{' -> '.join(steps[:5])}]" if steps else ""
                lines.append(f"  {pl.get('name', '?')}|src:{pl.get('source', '?')}{steps_str}|{file_short}")

        return lines

    def _compress_r_dependencies(self, matrix) -> List[str]:
        """Compress R dependencies, exports, configs, metadata, and detected frameworks."""
        lines = []

        # Package metadata
        if hasattr(matrix, 'r_package_metadata') and matrix.r_package_metadata:
            meta = matrix.r_package_metadata
            lines.append(f"# Package: {meta.get('name', '?')} v{meta.get('version', '?')}")
            if meta.get('title'):
                lines.append(f"# Title: {meta['title'][:100]}")
            if meta.get('license'):
                lines.append(f"# License: {meta['license']}")

        # Dependencies (group by source)
        if hasattr(matrix, 'r_dependencies') and matrix.r_dependencies:
            by_source = {}
            for dep in matrix.r_dependencies:
                src = dep.get('source', 'code')
                if src not in by_source:
                    by_source[src] = []
                by_source[src].append(dep)

            for src, deps in by_source.items():
                lines.append(f"# {src} deps ({len(deps)})")
                for dep in deps[:30]:
                    ver = f"@{dep['version']}" if dep.get('version') and dep['version'] != '*' else ""
                    lines.append(f"  {dep.get('name', '?')}{ver}")
                if len(deps) > 30:
                    lines.append(f"  # ... and {len(deps) - 30} more {src} deps")

        # Exports
        if hasattr(matrix, 'r_exports') and matrix.r_exports:
            lines.append(f"# Exports ({len(matrix.r_exports)})")
            for exp in matrix.r_exports[:30]:
                kind = exp.get('kind', 'export')
                pattern = f"|pattern:{exp['pattern']}" if exp.get('pattern') else ""
                lines.append(f"  {kind} {exp.get('name', '?')}{pattern}")

        # Detected frameworks
        if hasattr(matrix, 'r_detected_frameworks') and matrix.r_detected_frameworks:
            lines.append(f"# Detected: {', '.join(matrix.r_detected_frameworks[:25])}")

        # R version features
        if hasattr(matrix, 'r_detected_features') and matrix.r_detected_features:
            lines.append(f"# R features: {', '.join(matrix.r_detected_features)}")

        # R version
        if hasattr(matrix, 'r_version') and matrix.r_version:
            lines.append(f"# R version: {matrix.r_version}")

        # Configs
        if hasattr(matrix, 'r_configs') and matrix.r_configs:
            lines.append(f"# Configs ({len(matrix.r_configs)})")
            for cfg in matrix.r_configs[:15]:
                file_short = cfg.get('file', '').split('/')[-1]
                val = f"={cfg['value'][:50]}" if cfg.get('value') else ""
                lines.append(f"  {cfg.get('key', '?')}{val}|{cfg.get('source', 'options')}|{file_short}")

        # Lifecycle hooks
        if hasattr(matrix, 'r_lifecycle_hooks') and matrix.r_lifecycle_hooks:
            hooks = [h.get('name', '?') for h in matrix.r_lifecycle_hooks]
            lines.append(f"# Lifecycle: {', '.join(hooks[:10])}")

        return lines

    # ──────────────────────────────────────────────────────────────────
    # v4.27 Dart Language Compression Methods
    # ──────────────────────────────────────────────────────────────────

    def _compress_dart_types(self, matrix, is_monorepo: bool = False) -> List[str]:
        """Compress Dart types (classes, mixins, enums, extensions, extension types, typedefs)."""
        lines = []

        # Classes
        if hasattr(matrix, 'dart_classes') and matrix.dart_classes:
            lines.append(f"# Classes ({len(matrix.dart_classes)})")
            for cls in matrix.dart_classes[:40]:
                file_short = cls.get('file', '').split('/')[-1]
                mods = cls.get('modifiers', [])
                mod_str = f"[{','.join(mods)}] " if mods else ""
                sup = f"|<{cls['superclass']}" if cls.get('superclass') else ""
                mixins = cls.get('mixins', [])
                mix_str = f"|with:[{','.join(mixins[:5])}]" if mixins else ""
                ifaces = cls.get('interfaces', [])
                iface_str = f"|impl:[{','.join(ifaces[:5])}]" if ifaces else ""
                fields = cls.get('fields', [])
                fld_strs = []
                for f in fields[:5]:
                    flags = []
                    if f.get('is_late'):
                        flags.append('late')
                    if f.get('is_final'):
                        flags.append('final')
                    if f.get('is_static'):
                        flags.append('static')
                    flag_p = f"{'|'.join(flags)}:" if flags else ""
                    fld_strs.append(f"{flag_p}{f.get('name', '?')}:{f.get('type', '?')}")
                fld_str = f"|fields:[{','.join(fld_strs)}]" if fld_strs else ""
                methods = cls.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                lines.append(f"  {mod_str}{cls['name']}{sup}{mix_str}{iface_str}{fld_str}{meth_str}|{file_short}")
            if len(matrix.dart_classes) > 40:
                lines.append(f"  # ... and {len(matrix.dart_classes) - 40} more classes")

        # Mixins
        if hasattr(matrix, 'dart_mixins') and matrix.dart_mixins:
            lines.append(f"# Mixins ({len(matrix.dart_mixins)})")
            for mixin in matrix.dart_mixins[:20]:
                file_short = mixin.get('file', '').split('/')[-1]
                on = f"|on:[{','.join(mixin.get('on_types', [])[:3])}]" if mixin.get('on_types') else ""
                methods = mixin.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                lines.append(f"  mixin {mixin['name']}{on}{meth_str}|{file_short}")

        # Enums
        if hasattr(matrix, 'dart_enums') and matrix.dart_enums:
            lines.append(f"# Enums ({len(matrix.dart_enums)})")
            for enum in matrix.dart_enums[:25]:
                file_short = enum.get('file', '').split('/')[-1]
                enhanced = "|enhanced" if enum.get('is_enhanced') else ""
                values = enum.get('values', [])
                val_names = [v.get('name', '?') for v in values[:8]]
                val_str = f"|values:[{','.join(val_names)}]" if val_names else ""
                methods = enum.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:3])}]" if methods else ""
                lines.append(f"  enum {enum['name']}{enhanced}{val_str}{meth_str}|{file_short}")

        # Extensions
        if hasattr(matrix, 'dart_extensions') and matrix.dart_extensions:
            lines.append(f"# Extensions ({len(matrix.dart_extensions)})")
            for ext in matrix.dart_extensions[:20]:
                file_short = ext.get('file', '').split('/')[-1]
                on = f"|on:{ext['on_type']}" if ext.get('on_type') else ""
                methods = ext.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                lines.append(f"  extension {ext['name']}{on}{meth_str}|{file_short}")

        # Extension Types (Dart 3.3+)
        if hasattr(matrix, 'dart_extension_types') and matrix.dart_extension_types:
            lines.append(f"# Extension Types ({len(matrix.dart_extension_types)})")
            for ext in matrix.dart_extension_types[:15]:
                file_short = ext.get('file', '').split('/')[-1]
                on = f"|on:{ext['on_type']}" if ext.get('on_type') else ""
                lines.append(f"  extension type {ext['name']}{on}|{file_short}")

        # Typedefs
        if hasattr(matrix, 'dart_typedefs') and matrix.dart_typedefs:
            lines.append(f"# Typedefs ({len(matrix.dart_typedefs)})")
            for td in matrix.dart_typedefs[:15]:
                file_short = td.get('file', '').split('/')[-1]
                is_fn = "|fn" if td.get('is_function_typedef') else ""
                target = f"|={td['target_type'][:60]}" if td.get('target_type') else ""
                lines.append(f"  typedef {td['name']}{is_fn}{target}|{file_short}")

        return lines

    def _compress_dart_functions(self, matrix) -> List[str]:
        """Compress Dart functions and constructors."""
        lines = []

        # Functions
        if hasattr(matrix, 'dart_functions') and matrix.dart_functions:
            lines.append(f"# Functions ({len(matrix.dart_functions)})")
            for func in matrix.dart_functions[:50]:
                file_short = func.get('file', '').split('/')[-1]
                ret = f"|-> {func['return_type']}" if func.get('return_type') else ""
                params = func.get('params', [])
                if params:
                    p_strs = []
                    for p in params[:5]:
                        flags = []
                        if p.get('required'):
                            flags.append('req')
                        if p.get('named'):
                            flags.append('named')
                        if p.get('nullable'):
                            flags.append('?')
                        flag_p = f"[{','.join(flags)}]" if flags else ""
                        p_strs.append(f"{p.get('name', '?')}:{p.get('type', 'dynamic')}{flag_p}")
                    param_str = f"({','.join(p_strs)})"
                else:
                    param_str = "()"
                flags = []
                if func.get('is_async'):
                    flags.append('async')
                if func.get('is_generator'):
                    flags.append('gen')
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                lines.append(f"  {func['name']}{param_str}{ret}{flag_str}|{file_short}")
            if len(matrix.dart_functions) > 50:
                lines.append(f"  # ... and {len(matrix.dart_functions) - 50} more functions")

        # Constructors
        if hasattr(matrix, 'dart_constructors') and matrix.dart_constructors:
            lines.append(f"# Constructors ({len(matrix.dart_constructors)})")
            for ctor in matrix.dart_constructors[:30]:
                file_short = ctor.get('file', '').split('/')[-1]
                flags = []
                if ctor.get('is_const'):
                    flags.append('const')
                if ctor.get('is_factory'):
                    flags.append('factory')
                if ctor.get('is_named'):
                    flags.append('named')
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                params = ctor.get('params', [])
                param_str = f"|params:[{','.join(params[:5])}]" if params else ""
                lines.append(f"  {ctor['name']}{flag_str}{param_str}|{file_short}")

        return lines

    def _compress_dart_api(self, matrix) -> List[str]:
        """Compress Dart API: widgets, routes, state managers, gRPC, navigation."""
        lines = []

        # Flutter Widgets
        if hasattr(matrix, 'dart_widgets') and matrix.dart_widgets:
            # Group by kind
            by_kind = {}
            for w in matrix.dart_widgets:
                kind = w.get('kind', 'stateless')
                if kind not in by_kind:
                    by_kind[kind] = []
                by_kind[kind].append(w)

            for kind, widgets in by_kind.items():
                lines.append(f"# {kind} widgets ({len(widgets)})")
                for w in widgets[:20]:
                    file_short = w.get('file', '').split('/')[-1]
                    state = f"|state:{w['state_class']}" if w.get('state_class') else ""
                    key = "|hasKey" if w.get('has_key') else ""
                    lines.append(f"  {w['name']}{state}{key}|{file_short}")
                if len(widgets) > 20:
                    lines.append(f"  # ... and {len(widgets) - 20} more {kind} widgets")

        # Server Routes (Shelf/Dart Frog/Serverpod)
        if hasattr(matrix, 'dart_routes') and matrix.dart_routes:
            by_framework = {}
            for route in matrix.dart_routes:
                fw = route.get('framework', 'shelf')
                if fw not in by_framework:
                    by_framework[fw] = []
                by_framework[fw].append(route)

            for fw, routes in by_framework.items():
                lines.append(f"# {fw} routes ({len(routes)})")
                for route in routes[:25]:
                    file_short = route.get('file', '').split('/')[-1]
                    handler = f"|{route['handler']}" if route.get('handler') else ""
                    lines.append(f"  {route.get('method', '?')} {route.get('path', '/')}{handler}|{file_short}")

        # State Managers (Riverpod/Bloc/GetX/Provider/MobX)
        if hasattr(matrix, 'dart_state_managers') and matrix.dart_state_managers:
            by_framework = {}
            for sm in matrix.dart_state_managers:
                fw = sm.get('framework', 'bloc')
                if fw not in by_framework:
                    by_framework[fw] = []
                by_framework[fw].append(sm)

            for fw, managers in by_framework.items():
                lines.append(f"# {fw} state ({len(managers)})")
                for sm in managers[:15]:
                    file_short = sm.get('file', '').split('/')[-1]
                    kind = f"|{sm['kind']}" if sm.get('kind') else ""
                    state_type = f"|state:{sm['state_type']}" if sm.get('state_type') else ""
                    events = sm.get('events', [])
                    ev_str = f"|events:[{','.join(events[:5])}]" if events else ""
                    lines.append(f"  {sm['name']}{kind}{state_type}{ev_str}|{file_short}")

        # gRPC Services
        if hasattr(matrix, 'dart_grpc_services') and matrix.dart_grpc_services:
            lines.append(f"# gRPC Services ({len(matrix.dart_grpc_services)})")
            for grpc in matrix.dart_grpc_services[:10]:
                file_short = grpc.get('file', '').split('/')[-1]
                methods = grpc.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                lines.append(f"  {grpc['name']}{meth_str}|{file_short}")

        # Flutter Navigation Routes
        if hasattr(matrix, 'dart_flutter_routes') and matrix.dart_flutter_routes:
            lines.append(f"# Flutter Routes ({len(matrix.dart_flutter_routes)})")
            for route in matrix.dart_flutter_routes[:20]:
                file_short = route.get('file', '').split('/')[-1]
                fw = f"|{route['framework']}" if route.get('framework') else ""
                handler = f"|{route['handler']}" if route.get('handler') else ""
                lines.append(f"  {route.get('path', '/')}{fw}{handler}|{file_short}")

        return lines

    def _compress_dart_models(self, matrix) -> List[str]:
        """Compress Dart ORM models, data classes, migrations."""
        lines = []

        # ORM Models (Drift/Floor/Isar/Hive/ObjectBox)
        if hasattr(matrix, 'dart_models') and matrix.dart_models:
            by_framework = {}
            for model in matrix.dart_models:
                fw = model.get('framework', 'drift')
                if fw not in by_framework:
                    by_framework[fw] = []
                by_framework[fw].append(model)

            for fw, models in by_framework.items():
                lines.append(f"# {fw} models ({len(models)})")
                for model in models[:20]:
                    file_short = model.get('file', '').split('/')[-1]
                    table = f"|table:{model['table_name']}" if model.get('table_name') else ""
                    cols = model.get('columns', [])
                    col_strs = [f"{c.get('name', '?')}:{c.get('type', '?')}" for c in cols[:5]]
                    col_str = f"|cols:[{','.join(col_strs)}]" if col_strs else ""
                    lines.append(f"  {model['name']}{table}{col_str}|{file_short}")

        # Data Classes (Freezed/JsonSerializable/Built Value/Equatable)
        if hasattr(matrix, 'dart_data_classes') and matrix.dart_data_classes:
            by_framework = {}
            for dc in matrix.dart_data_classes:
                fw = dc.get('framework', 'freezed')
                if fw not in by_framework:
                    by_framework[fw] = []
                by_framework[fw].append(dc)

            for fw, dcs in by_framework.items():
                lines.append(f"# {fw} data classes ({len(dcs)})")
                for dc in dcs[:20]:
                    file_short = dc.get('file', '').split('/')[-1]
                    union = "|union" if dc.get('is_union') else ""
                    cases = dc.get('union_cases', [])
                    case_str = f"|cases:[{','.join(cases[:5])}]" if cases else ""
                    fields = dc.get('fields', [])
                    fld_strs = [f"{f.get('name', '?')}:{f.get('type', '?')}" for f in fields[:5]]
                    fld_str = f"|fields:[{','.join(fld_strs)}]" if fld_strs else ""
                    lines.append(f"  {dc['name']}{union}{case_str}{fld_str}|{file_short}")

        # Migrations
        if hasattr(matrix, 'dart_migrations') and matrix.dart_migrations:
            lines.append(f"# Migrations ({len(matrix.dart_migrations)})")
            for mig in matrix.dart_migrations[:15]:
                file_short = mig.get('file', '').split('/')[-1]
                fw = f"|{mig['framework']}" if mig.get('framework') else ""
                ver = f"|v{mig['version']}" if mig.get('version') else ""
                lines.append(f"  {mig['name']}{fw}{ver}|{file_short}")

        return lines

    def _compress_dart_dependencies(self, matrix) -> List[str]:
        """Compress Dart dependencies, annotations, imports, platform channels, isolates, frameworks."""
        lines = []

        # Dependencies (from pubspec.yaml)
        if hasattr(matrix, 'dart_dependencies') and matrix.dart_dependencies:
            by_kind = {}
            for dep in matrix.dart_dependencies:
                kind = dep.get('kind', 'dependency')
                if kind not in by_kind:
                    by_kind[kind] = []
                by_kind[kind].append(dep)

            for kind, deps in by_kind.items():
                lines.append(f"# {kind}s ({len(deps)})")
                for dep in deps[:30]:
                    lines.append(f"  {dep.get('name', '?')}")
                if len(deps) > 30:
                    lines.append(f"  # ... and {len(deps) - 30} more {kind}s")

        # Annotations (grouped by category)
        if hasattr(matrix, 'dart_annotations') and matrix.dart_annotations:
            by_cat = {}
            for ann in matrix.dart_annotations:
                cat = ann.get('category', 'other')
                if cat not in by_cat:
                    by_cat[cat] = []
                by_cat[cat].append(ann)

            for cat, anns in by_cat.items():
                ann_names = list(set(a.get('name', '?') for a in anns))
                lines.append(f"# {cat} annotations: {', '.join(ann_names[:15])}")

        # Platform Channels
        if hasattr(matrix, 'dart_platform_channels') and matrix.dart_platform_channels:
            lines.append(f"# Platform Channels ({len(matrix.dart_platform_channels)})")
            for ch in matrix.dart_platform_channels[:10]:
                file_short = ch.get('file', '').split('/')[-1]
                methods = ch.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                lines.append(f"  {ch.get('kind', '?')} {ch.get('name', '?')}{meth_str}|{file_short}")

        # Isolates
        if hasattr(matrix, 'dart_isolates') and matrix.dart_isolates:
            lines.append(f"# Isolates ({len(matrix.dart_isolates)})")
            for iso in matrix.dart_isolates[:10]:
                file_short = iso.get('file', '').split('/')[-1]
                lines.append(f"  {iso.get('kind', '?')} {iso.get('function_name', '?')}|{file_short}")

        # Detected frameworks
        if hasattr(matrix, 'dart_detected_frameworks') and matrix.dart_detected_frameworks:
            lines.append(f"# Detected: {', '.join(matrix.dart_detected_frameworks[:25])}")

        # Null safety stats
        if hasattr(matrix, 'dart_null_safety') and matrix.dart_null_safety:
            ns = matrix.dart_null_safety
            ns_parts = []
            for key, val in ns.items():
                if val:
                    ns_parts.append(f"{key}:{val}")
            if ns_parts:
                lines.append(f"# Null safety: {', '.join(ns_parts[:10])}")

        # Dart 3 features
        if hasattr(matrix, 'dart_dart3_features') and matrix.dart_dart3_features:
            d3 = matrix.dart_dart3_features
            d3_parts = []
            for key, val in d3.items():
                if val:
                    d3_parts.append(f"{key}:{val}")
            if d3_parts:
                lines.append(f"# Dart 3 features: {', '.join(d3_parts[:10])}")

        # Flutter project flag
        if hasattr(matrix, 'dart_is_flutter') and matrix.dart_is_flutter:
            lines.append("# Flutter project: true")

        # Dart/Flutter versions
        if hasattr(matrix, 'dart_version') and matrix.dart_version:
            lines.append(f"# Dart SDK: {matrix.dart_version}")
        if hasattr(matrix, 'dart_flutter_version') and matrix.dart_flutter_version:
            lines.append(f"# Flutter SDK: {matrix.dart_flutter_version}")

        return lines

    def _compress_lua_types(self, matrix) -> List[str]:
        """Compress Lua types (classes, modules, metatables)."""
        lines = []

        # Classes
        if hasattr(matrix, 'lua_classes') and matrix.lua_classes:
            lines.append(f"# Classes ({len(matrix.lua_classes)})")
            for cls in matrix.lua_classes[:40]:
                file_short = cls.get('file', '').split('/')[-1]
                parent = f"|<{cls['parent_class']}" if cls.get('parent_class') else ""
                oop = f"|oop:{cls['oop_library']}" if cls.get('oop_library') else ""
                fields = cls.get('fields', [])
                fld_strs = [f"{f.get('name', '?')}:{f.get('type', '?')}" for f in fields[:5]]
                fld_str = f"|fields:[{','.join(fld_strs)}]" if fld_strs else ""
                methods = cls.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                metamethods = cls.get('metamethods', [])
