    def _compress_lua_dependencies(self, matrix) -> List[str]:
        """Compress Lua imports, FFI, deps, metamethods, frameworks."""
        lines = []

        # Imports (require)
        if hasattr(matrix, 'lua_imports') and matrix.lua_imports:
            lines.append(f"# require() imports ({len(matrix.lua_imports)})")
            for imp in matrix.lua_imports[:40]:
                file_short = imp.get('file', '').split('/')[-1]
                alias = f"|as:{imp['alias']}" if imp.get('alias') and imp['alias'] != imp.get('module', '').split('.')[-1] else ""
                local = "|local" if imp.get('is_local') else ""
                lines.append(f"  {imp.get('module', '?')}{alias}{local}|{file_short}")
            if len(matrix.lua_imports) > 40:
                lines.append(f"  # ... and {len(matrix.lua_imports) - 40} more imports")

        # FFI declarations
        if hasattr(matrix, 'lua_ffi_declarations') and matrix.lua_ffi_declarations:
            lines.append(f"# FFI ({len(matrix.lua_ffi_declarations)})")
            for ffi in matrix.lua_ffi_declarations[:15]:
                file_short = ffi.get('file', '').split('/')[-1]
                c_type = f"|{ffi['c_type']}" if ffi.get('c_type') else ""
                lib = f"|lib:{ffi['library']}" if ffi.get('library') else ""
                lines.append(f"  ffi.{ffi.get('declaration_type', '?')} {ffi.get('name', '?')}{c_type}{lib}|{file_short}")

        # Dependencies (rockspec)
        if hasattr(matrix, 'lua_dependencies') and matrix.lua_dependencies:
            lines.append(f"# Dependencies ({len(matrix.lua_dependencies)})")
            for dep in matrix.lua_dependencies[:25]:
                lines.append(f"  {dep.get('name', '?')}")

        # Metamethods
        if hasattr(matrix, 'lua_metamethods') and matrix.lua_metamethods:
            lines.append(f"# Metamethods ({len(matrix.lua_metamethods)})")
            for mm in matrix.lua_metamethods[:20]:
                file_short = mm.get('file', '').split('/')[-1]
                target = f"|{mm['target']}" if mm.get('target') else ""
                impl = f"|{mm['implementation_type']}" if mm.get('implementation_type') else ""
                lines.append(f"  {mm['name']}{target}{impl}|{file_short}")

        # Detected frameworks
        if hasattr(matrix, 'lua_detected_frameworks') and matrix.lua_detected_frameworks:
            lines.append(f"# Detected: {', '.join(matrix.lua_detected_frameworks[:25])}")

        # LuaJIT flag
        if hasattr(matrix, 'lua_is_luajit') and matrix.lua_is_luajit:
            lines.append("# LuaJIT: true")

        # Lua version
        if hasattr(matrix, 'lua_version') and matrix.lua_version:
            lines.append(f"# Lua version: {matrix.lua_version}")

        return lines

