    def _compress_powershell_types(self, matrix) -> List[str]:
        """Compress PowerShell types: classes, enums, interfaces, DSC resources."""
        lines = []

        # Classes
        if hasattr(matrix, 'ps_classes') and matrix.ps_classes:
            lines.append(f"# Classes ({len(matrix.ps_classes)})")
            for cls in matrix.ps_classes[:40]:
                file_short = cls.get('file', '').split('/')[-1]
                base = f"|<{cls['base_class']}" if cls.get('base_class') else ""
                ifaces = cls.get('interfaces', [])
                iface_str = f"|impl:[{','.join(ifaces[:3])}]" if ifaces else ""
                props = cls.get('properties', [])
                prop_strs = [f"{p.get('name','?')}:{p.get('type','?')}" for p in props[:5]]
                prop_str = f"|props:[{','.join(prop_strs)}]" if prop_strs else ""
                methods = cls.get('methods', [])
                meth_str = f"|methods:[{','.join(methods[:5])}]" if methods else ""
                dsc = "|DSC" if cls.get('is_dsc_resource') else ""
                lines.append(f"  {cls['name']}{base}{iface_str}{dsc}{prop_str}{meth_str}|{file_short}")
            if len(matrix.ps_classes) > 40:
                lines.append(f"  # ... and {len(matrix.ps_classes) - 40} more classes")

        # Enums
        if hasattr(matrix, 'ps_enums') and matrix.ps_enums:
            lines.append(f"# Enums ({len(matrix.ps_enums)})")
            for enum in matrix.ps_enums[:25]:
                file_short = enum.get('file', '').split('/')[-1]
                vals = enum.get('values', [])
                val_str = f"|[{','.join(vals[:6])}]" if vals else ""
                flags = "|[Flags]" if enum.get('is_flags') else ""
                lines.append(f"  {enum['name']}{flags}{val_str}|{file_short}")

        # Interfaces (.NET interop)
        if hasattr(matrix, 'ps_interfaces') and matrix.ps_interfaces:
            lines.append(f"# .NET Interfaces ({len(matrix.ps_interfaces)})")
            for iface in matrix.ps_interfaces[:15]:
                file_short = iface.get('file', '').split('/')[-1]
                ns = f"|ns:{iface['namespace']}" if iface.get('namespace') else ""
                methods = iface.get('methods', [])
                meth_str = f"|[{','.join(methods[:5])}]" if methods else ""
                lines.append(f"  {iface['name']}{ns}{meth_str}|{file_short}")

        # DSC Resources
        if hasattr(matrix, 'ps_dsc_resources') and matrix.ps_dsc_resources:
            lines.append(f"# DSC Resources ({len(matrix.ps_dsc_resources)})")
            for dsc in matrix.ps_dsc_resources[:20]:
                file_short = dsc.get('file', '').split('/')[-1]
                props = dsc.get('properties', [])
                key_props = [p for p in props if p.get('is_key')]
                key_str = f"|key:[{','.join(p.get('name','?') for p in key_props[:3])}]" if key_props else ""
                mand_props = [p for p in props if p.get('is_mandatory') and not p.get('is_key')]
                mand_str = f"|required:[{','.join(p.get('name','?') for p in mand_props[:3])}]" if mand_props else ""
                lines.append(f"  {dsc['name']}{key_str}{mand_str}|{file_short}")

        return lines

    def _compress_powershell_functions(self, matrix) -> List[str]:
        """Compress PowerShell functions, script blocks, pipelines."""
        lines = []

        # Functions
        if hasattr(matrix, 'ps_functions') and matrix.ps_functions:
            # Group by function type
            by_type = {}
            for func in matrix.ps_functions:
                ft = func.get('function_type', 'function')
                if ft not in by_type:
                    by_type[ft] = []
                by_type[ft].append(func)

            for ft, funcs in by_type.items():
                lines.append(f"# {ft.title()}s ({len(funcs)})")
                for func in funcs[:50]:
                    file_short = func.get('file', '').split('/')[-1]
                    params = func.get('params', [])
                    param_strs = []
                    for p in params[:5]:
                        if isinstance(p, dict):
                            pname = p.get('name', '?')
                            ptype = f"[{p.get('type')}]" if p.get('type') else ""
                            pmand = "*" if p.get('is_mandatory') else ""
                            pswitch = "[switch]" if p.get('is_switch') else ""
                            param_strs.append(f"{pmand}{ptype}{pswitch}{pname}")
                        else:
                            param_strs.append(str(p))
                    param_str = f"({','.join(param_strs)})" if param_strs else "()"
                    flags = []
                    if func.get('is_advanced'):
                        flags.append('advanced')
                    if func.get('cmdlet_binding'):
                        flags.append('CmdletBinding')
                    if func.get('supports_should_process'):
                        flags.append('ShouldProcess')
                    if func.get('has_begin_process_end'):
                        flags.append('B/P/E')
                    flag_str = f"|[{','.join(flags)}]" if flags else ""
                    verb_noun = f"|{func['verb']}-{func['noun']}" if func.get('verb') and func.get('noun') else ""
                    out = f"|→{func['output_type']}" if func.get('output_type') else ""
                    lines.append(f"  {func['name']}{param_str}{verb_noun}{flag_str}{out}|{file_short}")
                if len(funcs) > 50:
                    lines.append(f"  # ... and {len(funcs) - 50} more {ft}s")

        # Script Blocks
        if hasattr(matrix, 'ps_script_blocks') and matrix.ps_script_blocks:
            lines.append(f"# Script Blocks ({len(matrix.ps_script_blocks)})")
            for sb in matrix.ps_script_blocks[:15]:
                file_short = sb.get('file', '').split('/')[-1]
                bt = f"|{sb['block_type']}" if sb.get('block_type') else ""
                lines.append(f"  {sb.get('name', '(anonymous)')}{bt}|{file_short}")

        # Pipelines
        if hasattr(matrix, 'ps_pipelines') and matrix.ps_pipelines:
            lines.append(f"# Pipelines ({len(matrix.ps_pipelines)})")
            for pipe in matrix.ps_pipelines[:15]:
                file_short = pipe.get('file', '').split('/')[-1]
                cmds = pipe.get('commands', [])
                cmd_str = ' | '.join(cmds[:5]) if cmds else "?"
                lines.append(f"  {cmd_str}|{file_short}")

        return lines

