    def _compress_powershell_dependencies(self, matrix) -> List[str]:
        """Compress PowerShell imports, usings, requires, dot-sourcing, comment help."""
        lines = []

        # Imports (Import-Module)
        if hasattr(matrix, 'ps_imports') and matrix.ps_imports:
            lines.append(f"# Import-Module ({len(matrix.ps_imports)})")
            for imp in matrix.ps_imports[:30]:
                file_short = imp.get('file', '').split('/')[-1]
