    def _compress_react_routing(self, matrix) -> List[str]:
        """Compress React routing (React Router, Next.js, TanStack, Remix)."""
        lines = []

        # Routes
        if hasattr(matrix, 'react_routes') and matrix.react_routes:
            # Group by framework
            by_fw = {}
            for rt in matrix.react_routes:
                fw = rt.get('framework', 'unknown')
                if fw not in by_fw:
                    by_fw[fw] = []
                by_fw[fw].append(rt)

            for fw, routes in by_fw.items():
                lines.append(f"# {fw} Routes ({len(routes)})")
                for rt in routes[:20]:
                    file_short = rt.get('file', '').split('/')[-1]
                    comp = f"|→{rt['component']}" if rt.get('component') else ""
                    loader = "|loader" if rt.get('has_loader') else ""
                    action = "|action" if rt.get('has_action') else ""
                    lazy = "|lazy" if rt.get('is_lazy') else ""
                    protected = "|protected" if rt.get('is_protected') else ""
                    lines.append(f"  {rt['path']}{comp}{loader}{action}{lazy}{protected}|{file_short}")

        # Layouts
        if hasattr(matrix, 'react_layouts') and matrix.react_layouts:
            lines.append(f"# Layouts ({len(matrix.react_layouts)})")
            for layout in matrix.react_layouts[:15]:
                file_short = layout.get('file', '').split('/')[-1]
                fw = f"|{layout['framework']}" if layout.get('framework') else ""
                outlet = "|<Outlet/>" if layout.get('has_outlet') else ""
                lines.append(f"  {layout['name']}{fw}{outlet}|{file_short}")

        # Pages (Next.js / Remix)
        if hasattr(matrix, 'react_pages') and matrix.react_pages:
            lines.append(f"# Pages ({len(matrix.react_pages)})")
            for page in matrix.react_pages[:25]:
                file_short = page.get('file', '').split('/')[-1]
                route = f"|{page['route_path']}" if page.get('route_path') else ""
                fw = f"|{page['framework']}" if page.get('framework') else ""
                data = f"|{page['data_fetching']}" if page.get('data_fetching') else ""
                ssr = "|SSR" if page.get('has_ssr') else ""
                ssg = "|SSG" if page.get('has_ssg') else ""
                isr = "|ISR" if page.get('has_isr') else ""
                api = "|API" if page.get('has_api') else ""
                lines.append(f"  {page['name']}{route}{fw}{data}{ssr}{ssg}{isr}{api}|{file_short}")
            if len(matrix.react_pages) > 25:
                lines.append(f"  # ... and {len(matrix.react_pages) - 25} more pages")

        return lines

