    def _compress_redux_stores(self, matrix) -> List[str]:
        """Compress Redux store configurations, reducer composition, and persist configs."""
        lines = []

        # Stores
        if hasattr(matrix, 'redux_stores') and matrix.redux_stores:
            lines.append(f"# Stores ({len(matrix.redux_stores)})")
            for store in matrix.redux_stores[:30]:
                file_short = store.get('file', '').split('/')[-1]
                method = f"|{store['creation_method']}" if store.get('creation_method') else ""
                reducers = f"|reducers:{store['reducer_count']}" if store.get('reducer_count') else ""
                mw = f"|middleware:{','.join(store['middleware_names'][:5])}" if store.get('middleware_names') else ""
                devtools = "|devtools" if store.get('has_devtools') else ""
                persist = "|persist" if store.get('has_persist') else ""
                rtk = f"|{store['rtk_version']}" if store.get('rtk_version') else ""
                lines.append(f"  {store['name']}{method}{reducers}{mw}{devtools}{persist}{rtk}|{file_short}:{store.get('line', 0)}")

        # Reducer compositions
        if hasattr(matrix, 'redux_reducer_compositions') and matrix.redux_reducer_compositions:
            lines.append(f"# Reducer Compositions ({len(matrix.redux_reducer_compositions)})")
            for rc in matrix.redux_reducer_compositions[:20]:
                file_short = rc.get('file', '').split('/')[-1]
                method = f"|{rc['method']}" if rc.get('method') else ""
                names = f"|{','.join(rc['reducer_names'][:8])}" if rc.get('reducer_names') else ""
                lines.append(f"  {rc['name']}{method}|count:{rc.get('reducer_count', 0)}{names}|{file_short}")

        # Persist configs
        if hasattr(matrix, 'redux_persist_configs') and matrix.redux_persist_configs:
            lines.append(f"# Persist Configs ({len(matrix.redux_persist_configs)})")
            for pc in matrix.redux_persist_configs[:15]:
                file_short = pc.get('file', '').split('/')[-1]
                engine = f"|{pc['storage_engine']}" if pc.get('storage_engine') else ""
                wl = f"|whitelist:{pc['whitelist_count']}" if pc.get('whitelist_count') else ""
                bl = f"|blacklist:{pc['blacklist_count']}" if pc.get('blacklist_count') else ""
                transforms = "|transforms" if pc.get('has_transforms') else ""
                migrations = "|migrations" if pc.get('has_migrations') else ""
                lines.append(f"  key:{pc.get('key', '?')}{engine}{wl}{bl}{transforms}{migrations}|{file_short}")

        # Version / Frameworks
        if hasattr(matrix, 'redux_version') and matrix.redux_version:
            lines.append(f"# Version: {matrix.redux_version}")
        if hasattr(matrix, 'redux_detected_frameworks') and matrix.redux_detected_frameworks:
            lines.append(f"# Frameworks: {', '.join(matrix.redux_detected_frameworks[:15])}")

        return lines

    def _compress_redux_slices(self, matrix) -> List[str]:
        """Compress Redux slices, entity adapters, and action creators."""
        lines = []

        # Slices
        if hasattr(matrix, 'redux_slices') and matrix.redux_slices:
            lines.append(f"# Slices ({len(matrix.redux_slices)})")
