    def _compress_redux_api(self, matrix) -> List[str]:
        """Compress Redux RTK Query APIs, endpoints, and cache tags."""
        lines = []

        # RTK Query APIs
        if hasattr(matrix, 'redux_rtk_query_apis') and matrix.redux_rtk_query_apis:
            lines.append(f"# RTK Query APIs ({len(matrix.redux_rtk_query_apis)})")
            for api in matrix.redux_rtk_query_apis[:15]:
                file_short = api.get('file', '').split('/')[-1]
                path = f"|path:{api['reducer_path']}" if api.get('reducer_path') else ""
                url = f"|url:{api['base_url']}" if api.get('base_url') else ""
                bq = f"|{api['base_query_type']}" if api.get('base_query_type') else ""
                tags = f"|tags:[{','.join(api['tag_types'][:8])}]" if api.get('tag_types') else ""
                eps = f"|endpoints:{api['endpoint_count']}" if api.get('endpoint_count') else ""
                hooks = f"|hooks:{len(api.get('generated_hooks', []))}" if api.get('generated_hooks') else ""
                split = "|codeSplit" if api.get('has_code_splitting') else ""
                lines.append(f"  {api['name']}{path}{url}{bq}{tags}{eps}{hooks}{split}|{file_short}:{api.get('line', 0)}")

        # Endpoints
        if hasattr(matrix, 'redux_rtk_query_endpoints') and matrix.redux_rtk_query_endpoints:
            # Group by type
            queries = [e for e in matrix.redux_rtk_query_endpoints if e.get('endpoint_type') == 'query']
            mutations = [e for e in matrix.redux_rtk_query_endpoints if e.get('endpoint_type') == 'mutation']

            if queries:
                lines.append(f"# Query Endpoints ({len(queries)})")
                for ep in queries[:25]:
                    file_short = ep.get('file', '').split('/')[-1]
                    url = f"|{ep['url_pattern']}" if ep.get('url_pattern') else ""
                    tags_p = f"|provides:[{','.join(ep['provides_tags'][:5])}]" if ep.get('provides_tags') else ""
                    oqs = "|onQueryStarted" if ep.get('has_on_query_started') else ""
                    oce = "|onCacheEntryAdded" if ep.get('has_on_cache_entry_added') else ""
                    poll = "|polling" if ep.get('has_polling') else ""
                    lines.append(f"  {ep['name']}|query{url}{tags_p}{oqs}{oce}{poll}|{file_short}")

            if mutations:
                lines.append(f"# Mutation Endpoints ({len(mutations)})")
                for ep in mutations[:25]:
                    file_short = ep.get('file', '').split('/')[-1]
                    url = f"|{ep['url_pattern']}" if ep.get('url_pattern') else ""
                    method = f"|{ep['method']}" if ep.get('method') else ""
                    tags_i = f"|invalidates:[{','.join(ep['invalidates_tags'][:5])}]" if ep.get('invalidates_tags') else ""
                    oqs = "|onQueryStarted" if ep.get('has_on_query_started') else ""
                    lines.append(f"  {ep['name']}|mutation{url}{method}{tags_i}{oqs}|{file_short}")

        # Cache Tags
        if hasattr(matrix, 'redux_cache_tags') and matrix.redux_cache_tags:
            lines.append(f"# Cache Tags ({len(matrix.redux_cache_tags)})")
            for ct in matrix.redux_cache_tags[:20]:
                file_short = ct.get('file', '').split('/')[-1]
                usage = f"|{ct['usage']}" if ct.get('usage') else ""
                eps = f"|endpoints:[{','.join(ct['endpoints'][:5])}]" if ct.get('endpoints') else ""
                lines.append(f"  {ct['tag_type']}{usage}{eps}|{file_short}")

        # Features detected
        if hasattr(matrix, 'redux_detected_features') and matrix.redux_detected_features:
            lines.append(f"# Features: {', '.join(matrix.redux_detected_features[:20])}")

        return lines

