    def _compress_zustand_api(self, matrix) -> List[str]:
        """Compress Zustand imports, integrations, and TypeScript types."""
        lines = []

        # Imports
        if hasattr(matrix, 'zustand_imports') and matrix.zustand_imports:
            # Group by source
            by_source = {}
            for imp in matrix.zustand_imports:
                src = imp.get('source', 'unknown')
                by_source.setdefault(src, []).append(imp)

            lines.append(f"# Imports ({len(matrix.zustand_imports)} from {len(by_source)} sources)")
            for src, imps in list(by_source.items())[:10]:
                all_names = []
                for imp in imps:
                    all_names.extend(imp.get('imported_names', []))
                unique_names = list(dict.fromkeys(all_names))[:12]
                subpath = imps[0].get('subpath', '')
                sp = f"|subpath:{subpath}" if subpath else ""
                lines.append(f"  {src}{sp}|names:[{','.join(unique_names)}]|files:{len(imps)}")

        # Integrations
        if hasattr(matrix, 'zustand_integrations') and matrix.zustand_integrations:
            lines.append(f"# Integrations ({len(matrix.zustand_integrations)})")
            for intg in matrix.zustand_integrations[:15]:
                file_short = intg.get('file', '').split('/')[-1]
                lib = f"|{intg['library']}" if intg.get('library') else ""
                pattern = f"|{intg['pattern']}" if intg.get('pattern') else ""
                lines.append(f"  {intg['integration_type']}{lib}{pattern}|{file_short}:{intg.get('line', 0)}")

        # Types
        if hasattr(matrix, 'zustand_types') and matrix.zustand_types:
            lines.append(f"# TypeScript Types ({len(matrix.zustand_types)})")
            for tp in matrix.zustand_types[:15]:
                file_short = tp.get('file', '').split('/')[-1]
                cat = f"|{tp['type_category']}" if tp.get('type_category') else ""
                expr = f"|{tp['type_expression'][:40]}" if tp.get('type_expression') else ""
                lines.append(f"  {tp['name']}{cat}{expr}|{file_short}:{tp.get('line', 0)}")

        # Features detected
        if hasattr(matrix, 'zustand_detected_features') and matrix.zustand_detected_features:
            lines.append(f"# Features: {', '.join(matrix.zustand_detected_features[:20])}")

        return lines

