    def _compress_pinia_api(self, matrix) -> List[str]:
        """Compress Pinia imports, integrations, TypeScript types, and features."""
        lines = []

        # Imports
        if hasattr(matrix, 'pinia_imports') and matrix.pinia_imports:
            # Group by source
            by_source = {}
            for imp in matrix.pinia_imports:
                src = imp.get('source', 'unknown')
                by_source.setdefault(src, []).append(imp)

            lines.append(f"# Imports ({len(matrix.pinia_imports)} from {len(by_source)} sources)")
            for src, imps in list(by_source.items())[:10]:
                all_names = []
                for imp in imps:
                    all_names.extend(imp.get('imported_names', []))
                unique_names = list(dict.fromkeys(all_names))[:12]
                type_only = "|type" if any(imp.get('is_type_only') for imp in imps) else ""
                lines.append(f"  {src}{type_only}|names:[{','.join(unique_names)}]|files:{len(imps)}")

        # Integrations
        if hasattr(matrix, 'pinia_integrations') and matrix.pinia_integrations:
            # Group by integration type
            by_itype = {}
            for intg in matrix.pinia_integrations:
                itype = intg.get('integration_type', 'unknown')
                by_itype.setdefault(itype, []).append(intg)

            lines.append(f"# Integrations ({len(matrix.pinia_integrations)})")
            for itype, intgs in by_itype.items():
                libs = list(set(intg.get('library', '') for intg in intgs if intg.get('library')))
                patterns = list(set(intg.get('pattern', '') for intg in intgs if intg.get('pattern')))
                lib_str = f"|libs:[{','.join(libs[:5])}]" if libs else ""
                pat_str = f"|patterns:[{','.join(patterns[:5])}]" if patterns else ""
                lines.append(f"  {itype}({len(intgs)}){lib_str}{pat_str}")

        # Types
        if hasattr(matrix, 'pinia_types') and matrix.pinia_types:
            lines.append(f"# TypeScript Types ({len(matrix.pinia_types)})")
            for tp in matrix.pinia_types[:15]:
                file_short = tp.get('file', '').split('/')[-1]
                cat = f"|{tp['type_category']}" if tp.get('type_category') else ""
                expr = f"|{tp['type_expression'][:40]}" if tp.get('type_expression') else ""
                lines.append(f"  {tp['name']}{cat}{expr}|{file_short}:{tp.get('line', 0)}")

        # Features detected
        if hasattr(matrix, 'pinia_detected_features') and matrix.pinia_detected_features:
            lines.append(f"# Features: {', '.join(matrix.pinia_detected_features[:20])}")

        return lines

    # ============================================
    # v4.53: NgRx State Management compression methods
    # ============================================

    def _compress_ngrx_stores(self, matrix) -> List[str]:
        """Compress NgRx store configs, ComponentStore, and SignalStore."""
        lines = []

        # Classic stores (StoreModule / provideStore)
        if hasattr(matrix, 'ngrx_stores') and matrix.ngrx_stores:
            lines.append(f"# Stores ({len(matrix.ngrx_stores)})")
            for store in matrix.ngrx_stores[:30]:
                file_short = store.get('file', '').split('/')[-1]
                method = f"|{store['setup_method']}" if store.get('setup_method') else ""
                feature = f"|feature:{store['feature_name']}" if store.get('feature_name') else ""
                reducers = f"|reducers:{','.join(store['reducer_names'][:5])}" if store.get('reducer_names') else ""
                devtools = "|devtools" if store.get('has_devtools') else ""
                router = "|router-store" if store.get('has_router_store') else ""
                effects = "|effects" if store.get('has_effects') else ""
                entity = "|entity" if store.get('has_entity') else ""
                standalone = "|standalone" if store.get('is_standalone') else ""
                meta = f"|meta:{','.join(store['meta_reducers'][:3])}" if store.get('meta_reducers') else ""
                lines.append(f"  {store['name']}{method}{feature}{reducers}{devtools}{router}{effects}{entity}{standalone}{meta}|{file_short}:{store.get('line', 0)}")

        # Component Stores
        if hasattr(matrix, 'ngrx_component_stores') and matrix.ngrx_component_stores:
            lines.append(f"# ComponentStores ({len(matrix.ngrx_component_stores)})")
            for cs in matrix.ngrx_component_stores[:20]:
                file_short = cs.get('file', '').split('/')[-1]
                state = f"|state:{cs['state_type']}" if cs.get('state_type') else ""
                updaters = f"|updaters:{len(cs.get('updaters', []))}" if cs.get('updaters') else ""
                selectors = f"|selectors:{len(cs.get('selectors', []))}" if cs.get('selectors') else ""
                effects = f"|effects:{len(cs.get('effects', []))}" if cs.get('effects') else ""
                patch = "|patchState" if cs.get('has_patch_state') else ""
                setState = "|setState" if cs.get('has_set_state') else ""
                lines.append(f"  {cs['name']}{state}{updaters}{selectors}{effects}{patch}{setState}|{file_short}:{cs.get('line', 0)}")
                # v4.54: Updater details with param types
                for ud in cs.get('updater_details', [])[:10]:
                    param = f"|param:{ud['param_type']}" if ud.get('param_type') else ""
                    lines.append(f"    updater:{ud['name']}{param}")
                # v4.54: PatchState call details
                for ps in cs.get('patch_state_calls', [])[:10]:
                    fields = ','.join(ps.get('fields', [])[:5])
                    if fields:
                        lines.append(f"    patchState|fields:[{fields}]|line:{ps.get('line', 0)}")

        # Signal Stores
        if hasattr(matrix, 'ngrx_signal_stores') and matrix.ngrx_signal_stores:
            lines.append(f"# SignalStores ({len(matrix.ngrx_signal_stores)})")
            for ss in matrix.ngrx_signal_stores[:20]:
                file_short = ss.get('file', '').split('/')[-1]
                state_count = f"|state:{len(ss.get('state_fields', []))}" if ss.get('state_fields') else ""
                computed = f"|computed:{len(ss.get('computed_fields', []))}" if ss.get('computed_fields') else ""
                methods = f"|methods:{len(ss.get('methods', []))}" if ss.get('methods') else ""
                hooks = "|withHooks" if ss.get('with_hooks') else ""
                entities = "|withEntities" if ss.get('has_entities') else ""
                devtools = "|devtools" if ss.get('has_devtools') else ""
                features = f"|features:[{','.join(ss.get('features', [])[:5])}]" if ss.get('features') else ""
                lines.append(f"  {ss['name']}{state_count}{computed}{methods}{hooks}{entities}{devtools}{features}|{file_short}:{ss.get('line', 0)}")
                # v4.54: Deep computed details
                for cd in ss.get('computed_details', [])[:10]:
                    deps = ','.join(cd.get('deps', [])[:5])
                    if deps:
                        lines.append(f"    computed:{cd['name']}|deps:[{deps}]")
                # v4.54: Deep method details
                for md in ss.get('method_details', [])[:10]:
                    tags = []
                    if md.get('is_async'):
                        tags.append('async')
                    if md.get('is_rxmethod'):
                        tags.append('rxMethod')
                    if md.get('return_type'):
                        tags.append(f"returns:{md['return_type']}")
                    tag_str = f"|{'|'.join(tags)}" if tags else ""
                    lines.append(f"    method:{md['name']}{tag_str}")

        # Version / Frameworks
        if hasattr(matrix, 'ngrx_version') and matrix.ngrx_version:
            lines.append(f"# Version: {matrix.ngrx_version}")
        if hasattr(matrix, 'ngrx_detected_frameworks') and matrix.ngrx_detected_frameworks:
            lines.append(f"# Frameworks: {', '.join(matrix.ngrx_detected_frameworks[:15])}")

        return lines

    def _compress_ngrx_actions(self, matrix) -> List[str]:
        """Compress NgRx actions and action groups."""
        lines = []

        # Actions
        if hasattr(matrix, 'ngrx_actions') and matrix.ngrx_actions:
            lines.append(f"# Actions ({len(matrix.ngrx_actions)})")
            for act in matrix.ngrx_actions[:40]:
                file_short = act.get('file', '').split('/')[-1]
                atype = f"|type:{act['action_type']}" if act.get('action_type') else ""
                source = f"|[{act['source']}]" if act.get('source') else ""
                event = f" {act['event']}" if act.get('event') else ""
                props = f"|props<{act['props_type']}>" if act.get('has_props') and act.get('props_type') else ("|props" if act.get('has_props') else "")
                method = f"|{act['creation_method']}" if act.get('creation_method') else ""
                lines.append(f"  {act['name']}{atype}{source}{event}{props}{method}|{file_short}:{act.get('line', 0)}")

        # Action Groups
        if hasattr(matrix, 'ngrx_action_groups') and matrix.ngrx_action_groups:
            lines.append(f"# Action Groups ({len(matrix.ngrx_action_groups)})")
            for ag in matrix.ngrx_action_groups[:20]:
                file_short = ag.get('file', '').split('/')[-1]
                source = f"|source:{ag['source']}" if ag.get('source') else ""
                events = f"|events:{ag['event_count']}" if ag.get('event_count') else ""
                event_list = f"|[{','.join(ag.get('events', [])[:8])}]" if ag.get('events') else ""
                lines.append(f"  {ag['name']}{source}{events}{event_list}|{file_short}:{ag.get('line', 0)}")

        return lines

    def _compress_ngrx_effects(self, matrix) -> List[str]:
        """Compress NgRx effects and component store effects."""
