    # v4.54: NgRx cross-file store refs compression
    def _compress_ngrx_store_refs(self, matrix) -> List[str]:
        """Compress NgRx cross-file Store.select() and Store.dispatch() references."""
        lines = []

        # Group select refs by selector
        if hasattr(matrix, 'ngrx_store_select_refs') and matrix.ngrx_store_select_refs:
            # Group by selector name
            by_selector: Dict = {}
            for ref in matrix.ngrx_store_select_refs:
                sel = ref.get('selector', '')
                if sel not in by_selector:
                    by_selector[sel] = []
                file_short = ref.get('file', '').split('/')[-1]
                by_selector[sel].append(file_short)

            lines.append(f"# Store.select() refs ({len(matrix.ngrx_store_select_refs)})")
            for sel, files in sorted(by_selector.items())[:30]:
                unique_files = list(dict.fromkeys(files))[:5]
                lines.append(f"  select({sel})|used-in:[{','.join(unique_files)}]")

        # Group dispatch refs by action
        if hasattr(matrix, 'ngrx_store_dispatch_refs') and matrix.ngrx_store_dispatch_refs:
            by_action: Dict = {}
            for ref in matrix.ngrx_store_dispatch_refs:
                act = ref.get('action', '')
                if act not in by_action:
                    by_action[act] = []
                file_short = ref.get('file', '').split('/')[-1]
                by_action[act].append(file_short)

            lines.append(f"# Store.dispatch() refs ({len(matrix.ngrx_store_dispatch_refs)})")
            for act, files in sorted(by_action.items())[:30]:
                unique_files = list(dict.fromkeys(files))[:5]
                lines.append(f"  dispatch({act})|used-in:[{','.join(unique_files)}]")

        return lines

