    # v4.55: XState State Machine compression methods
    # ============================================

    def _compress_xstate_machines(self, matrix) -> List[str]:
        """Compress XState machine definitions."""
        lines = []
        if hasattr(matrix, 'xstate_machines') and matrix.xstate_machines:
            lines.append(f"# Machines ({len(matrix.xstate_machines)})")
            for m in matrix.xstate_machines[:30]:
                file_short = m.get('file', '').split('/')[-1]
                mid = f"|id:{m['machine_id']}" if m.get('machine_id') else ""
                method = f"|{m['creation_method']}" if m.get('creation_method') else ""
                initial = f"|initial:{m['initial_state']}" if m.get('initial_state') else ""
                ctx = f"|ctx:<{m['context_type']}>" if m.get('context_type') else ""
                states = f"|states({m['state_count']})" if m.get('state_count') else ""
                top = f"|[{','.join(m['top_level_states'][:6])}]" if m.get('top_level_states') else ""
                events = f"|events:[{','.join(m['event_types'][:6])}]" if m.get('event_types') else ""
                parallel = "|parallel" if m.get('has_parallel') else ""
                history = "|history" if m.get('has_history') else ""
                final = "|final" if m.get('has_final') else ""
                invoke = "|invoke" if m.get('has_invoke') else ""
                after = "|after" if m.get('has_after') else ""
                always = "|always" if m.get('has_always') else ""
                setup = "|setup" if m.get('has_setup') else ""
                ver = f"|{m['xstate_version']}" if m.get('xstate_version') else ""
                lines.append(f"  {m['name']}{method}{mid}{initial}{ctx}{states}{top}{events}{parallel}{history}{final}{invoke}{after}{always}{setup}{ver}|{file_short}:{m.get('line', 0)}")

            # Setup details
            for m in matrix.xstate_machines[:15]:
                if m.get('setup_actions') or m.get('setup_guards') or m.get('setup_actors'):
                    details = []
                    if m.get('setup_actions'):
                        details.append(f"actions:[{','.join(m['setup_actions'][:6])}]")
                    if m.get('setup_guards'):
                        details.append(f"guards:[{','.join(m['setup_guards'][:6])}]")
                    if m.get('setup_actors'):
                        details.append(f"actors:[{','.join(m['setup_actors'][:6])}]")
                    lines.append(f"    setup({m['name']})|{'|'.join(details)}")

        # Version / Frameworks
        if hasattr(matrix, 'xstate_version') and matrix.xstate_version:
            lines.append(f"# Version: {matrix.xstate_version}")
        if hasattr(matrix, 'xstate_detected_frameworks') and matrix.xstate_detected_frameworks:
            lines.append(f"# Frameworks: {', '.join(matrix.xstate_detected_frameworks[:15])}")
        if hasattr(matrix, 'xstate_detected_features') and matrix.xstate_detected_features:
            lines.append(f"# Features: {', '.join(matrix.xstate_detected_features[:20])}")

        return lines

    def _compress_xstate_states(self, matrix) -> List[str]:
        """Compress XState state nodes, transitions, and invokes."""
        lines = []

        # State nodes grouped by type
        if hasattr(matrix, 'xstate_state_nodes') and matrix.xstate_state_nodes:
            by_type = {}
            for sn in matrix.xstate_state_nodes:
                stype = sn.get('state_type', 'atomic')
                by_type.setdefault(stype, []).append(sn)

            for stype, nodes in by_type.items():
                lines.append(f"# {stype} states ({len(nodes)})")
                for sn in nodes[:20]:
                    file_short = sn.get('file', '').split('/')[-1]
                    machine = f"|machine:{sn['machine_name']}" if sn.get('machine_name') else ""
                    entry = f"|entry:[{','.join(sn['entry_actions'][:4])}]" if sn.get('entry_actions') else ""
                    exit_a = f"|exit:[{','.join(sn['exit_actions'][:4])}]" if sn.get('exit_actions') else ""
                    events = f"|events:[{','.join(sn['event_names'][:4])}]" if sn.get('event_names') else ""
                    invoke = "|invoke" if sn.get('has_invoke') else ""
                    after = "|after" if sn.get('has_after') else ""
                    always = "|always" if sn.get('has_always') else ""
                    tags = f"|tags:[{','.join(sn['tags'][:3])}]" if sn.get('tags') else ""
                    lines.append(f"  {sn['name']}{machine}{entry}{exit_a}{events}{invoke}{after}{always}{tags}|{file_short}:{sn.get('line', 0)}")

        # Transitions
        if hasattr(matrix, 'xstate_transitions') and matrix.xstate_transitions:
            lines.append(f"# Transitions ({len(matrix.xstate_transitions)})")
            for tr in matrix.xstate_transitions[:40]:
                file_short = tr.get('file', '').split('/')[-1]
                source = f"{tr.get('source_state', '?')}"
                target = f"→{tr.get('target_state', '?')}"
                guard = f"|guard:{tr['guard_name']}" if tr.get('guard_name') else ""
                actions = f"|actions:[{','.join(tr['action_names'][:4])}]" if tr.get('action_names') else ""
                lines.append(f"  {tr['event']}|{source}{target}{guard}{actions}|{file_short}:{tr.get('line', 0)}")

        # Invokes
        if hasattr(matrix, 'xstate_invokes') and matrix.xstate_invokes:
            lines.append(f"# Invokes ({len(matrix.xstate_invokes)})")
            for inv in matrix.xstate_invokes[:20]:
                file_short = inv.get('file', '').split('/')[-1]
                state = f"|state:{inv['state_name']}" if inv.get('state_name') else ""
                itype = f"|{inv['invoke_type']}" if inv.get('invoke_type') else ""
                done = f"|onDone→{inv['on_done_target']}" if inv.get('on_done_target') else ""
                error = f"|onError→{inv['on_error_target']}" if inv.get('on_error_target') else ""
                lines.append(f"  {inv['name']}{state}{itype}{done}{error}|{file_short}:{inv.get('line', 0)}")

        return lines

