    def _compress_xstate_api(self, matrix) -> List[str]:
        """Compress XState imports, actors, and typegens."""
        lines = []

        # Imports grouped by source
        if hasattr(matrix, 'xstate_imports') and matrix.xstate_imports:
            by_source = {}
            for imp in matrix.xstate_imports:
                src = imp.get('source', 'unknown')
                by_source.setdefault(src, []).append(imp)

            lines.append(f"# Imports ({len(matrix.xstate_imports)} from {len(by_source)} sources)")
            for src, imps in list(by_source.items())[:10]:
                all_names = []
                for imp in imps:
                    all_names.extend(imp.get('imported_names', []))
                unique_names = list(dict.fromkeys(all_names))[:12]
                lines.append(f"  {src}|names:[{','.join(unique_names)}]|files:{len(imps)}")

        # Actors
        if hasattr(matrix, 'xstate_actors') and matrix.xstate_actors:
            by_method = {}
            for actor in matrix.xstate_actors:
                method = actor.get('creation_method', 'unknown')
                by_method.setdefault(method, []).append(actor)

            for method, actors in by_method.items():
                lines.append(f"# {method} actors ({len(actors)})")
                for actor in actors[:15]:
                    file_short = actor.get('file', '').split('/')[-1]
                    machine = f"|machine:{actor['machine_name']}" if actor.get('machine_name') else ""
                    atype = f"|type:{actor['actor_type']}" if actor.get('actor_type') else ""
                    sub = "|subscribe" if actor.get('has_subscribe') else ""
                    start = "|start" if actor.get('has_start') else ""
                    lines.append(f"  {actor['name']}{machine}{atype}{sub}{start}|{file_short}:{actor.get('line', 0)}")

        # Typegens
        if hasattr(matrix, 'xstate_typegens') and matrix.xstate_typegens:
            lines.append(f"# TypeScript typegen ({len(matrix.xstate_typegens)})")
            for tg in matrix.xstate_typegens[:10]:
                file_short = tg.get('file', '').split('/')[-1]
                ttype = f"|{tg['typegen_type']}" if tg.get('typegen_type') else ""
                ctx = f"|ctx:<{tg['context_type']}>" if tg.get('context_type') else ""
                evt = f"|events:<{tg['event_type']}>" if tg.get('event_type') else ""
                lines.append(f"  typegen{ttype}{ctx}{evt}|{file_short}:{tg.get('line', 0)}")

        return lines

