    def _compress_valtio_proxies(self, matrix) -> List[str]:
        """Compress Valtio proxy, ref, and collection definitions."""
        lines: List[str] = []

        # Proxies
        if hasattr(matrix, 'valtio_proxies') and matrix.valtio_proxies:
            lines.append(f"# Proxies ({len(matrix.valtio_proxies)})")
            for p in matrix.valtio_proxies[:30]:
                file_short = p.get('file', '').split('/')[-1]
                fields = f"|fields({p['field_count']})" if p.get('field_count') else ""
                state_f = f"|[{','.join(p['state_fields'][:6])}]" if p.get('state_fields') else ""
                getters = f"|getters:[{','.join(p['computed_getters'][:4])}]" if p.get('computed_getters') else ""
                nested = "|nested" if p.get('has_nested_proxy') else ""
                exported = "|export" if p.get('is_exported') else ""
                module = "|module" if p.get('is_module_level') else ""
                generic = f"|<{p['generic_type']}>" if p.get('generic_type') else ""
                lines.append(f"  {p['name']}{generic}{fields}{state_f}{getters}{nested}{exported}{module}|{file_short}:{p.get('line', 0)}")

        # Refs
        if hasattr(matrix, 'valtio_refs') and matrix.valtio_refs:
            lines.append(f"# Refs ({len(matrix.valtio_refs)})")
            for r in matrix.valtio_refs[:20]:
                file_short = r.get('file', '').split('/')[-1]
                proxy = f"|proxy:{r['proxy_name']}" if r.get('proxy_name') else ""
                rtype = f"|type:{r['ref_type']}" if r.get('ref_type') else ""
                inline = "|inline" if r.get('is_inline') else ""
                lines.append(f"  {r['name']}{proxy}{rtype}{inline}|{file_short}:{r.get('line', 0)}")

        # Collections (proxyMap, proxySet)
        if hasattr(matrix, 'valtio_collections') and matrix.valtio_collections:
            lines.append(f"# Collections ({len(matrix.valtio_collections)})")
            for c in matrix.valtio_collections[:20]:
                file_short = c.get('file', '').split('/')[-1]
                ctype = f"|{c['collection_type']}" if c.get('collection_type') else ""
                exported = "|export" if c.get('is_exported') else ""
                key_t = f"|K:<{c['generic_key_type']}>" if c.get('generic_key_type') else ""
                val_t = f"|V:<{c['generic_value_type']}>" if c.get('generic_value_type') else ""
                lines.append(f"  {c['name']}{ctype}{key_t}{val_t}{exported}|{file_short}:{c.get('line', 0)}")

        # Version / Frameworks
        if hasattr(matrix, 'valtio_version') and matrix.valtio_version:
            lines.append(f"# Version: {matrix.valtio_version}")
        if hasattr(matrix, 'valtio_detected_frameworks') and matrix.valtio_detected_frameworks:
            lines.append(f"# Frameworks: {', '.join(matrix.valtio_detected_frameworks[:15])}")
        if hasattr(matrix, 'valtio_detected_features') and matrix.valtio_detected_features:
            lines.append(f"# Features: {', '.join(matrix.valtio_detected_features[:20])}")

        return lines

