    def _compress_apollo_queries(self, matrix) -> List[str]:
        """Compress Apollo query usage (useQuery, useLazyQuery, useSuspenseQuery, gql tags)."""
        lines: List[str] = []

        # Queries (useQuery, useSuspenseQuery, useBackgroundQuery, useReadQuery)
        if hasattr(matrix, 'apollo_queries') and matrix.apollo_queries:
            lines.append(f"# Queries ({len(matrix.apollo_queries)})")
            for q in matrix.apollo_queries[:40]:
                file_short = q.get('file', '').split('/')[-1]
                doc = f"|doc:{q['query_name']}" if q.get('query_name') else ""
                ts = f"|<{q['type_params']}>" if q.get('type_params') else ""
                flags = []
                if q.get('has_variables'):
                    flags.append("vars")
                if q.get('fetch_policy'):
                    flags.append(f"fp:{q['fetch_policy']}")
                if q.get('error_policy'):
                    flags.append(f"ep:{q['error_policy']}")
                if q.get('has_poll_interval'):
                    flags.append("poll")
                if q.get('has_skip'):
                    flags.append("skip")
                if q.get('has_ssr'):
                    flags.append("ssr")
                if q.get('is_suspense'):
                    flags.append("suspense")
                if q.get('is_background'):
                    flags.append("background")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                hook = q.get('hook_name', 'useQuery')
                lines.append(f"  {q.get('name', '?')}|{hook}{doc}{ts}{flag_str}|{file_short}:{q.get('line', 0)}")

        # Lazy queries
        if hasattr(matrix, 'apollo_lazy_queries') and matrix.apollo_lazy_queries:
            lines.append(f"# LazyQueries ({len(matrix.apollo_lazy_queries)})")
            for lq in matrix.apollo_lazy_queries[:20]:
                file_short = lq.get('file', '').split('/')[-1]
                doc = f"|doc:{lq['query_name']}" if lq.get('query_name') else ""
                fp = f"|fp:{lq['fetch_policy']}" if lq.get('fetch_policy') else ""
                ts = "|typed" if lq.get('has_typescript') else ""
                lines.append(f"  {lq.get('name', '?')}{doc}{fp}{ts}|{file_short}:{lq.get('line', 0)}")

        # GQL tags
        if hasattr(matrix, 'apollo_gql_tags') and matrix.apollo_gql_tags:
            lines.append(f"# GqlTags ({len(matrix.apollo_gql_tags)})")
            for gt in matrix.apollo_gql_tags[:30]:
                file_short = gt.get('file', '').split('/')[-1]
                op = f"|{gt['operation_type']}:{gt.get('operation_name', '?')}" if gt.get('operation_type') else ""
                flags = []
                if gt.get('has_fragments'):
                    flags.append("fragments")
                if gt.get('has_variables'):
                    flags.append("vars")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                lines.append(f"  {gt.get('name', '?')}{op}{flag_str}|{file_short}:{gt.get('line', 0)}")

        # Version / Frameworks / Features
        if hasattr(matrix, 'apollo_version') and matrix.apollo_version:
            lines.append(f"# Version: {matrix.apollo_version}")
        if hasattr(matrix, 'apollo_detected_frameworks') and matrix.apollo_detected_frameworks:
            lines.append(f"# Frameworks: {', '.join(matrix.apollo_detected_frameworks[:20])}")
        if hasattr(matrix, 'apollo_detected_features') and matrix.apollo_detected_features:
            lines.append(f"# Features: {', '.join(matrix.apollo_detected_features[:25])}")

        return lines

