    def _compress_astro_components(self, matrix) -> List[str]:
        """Compress Astro component info (props, slots, directives, styles)."""
        lines: List[str] = []

        if hasattr(matrix, 'astro_components') and matrix.astro_components:
            lines.append(f"# Components ({len(matrix.astro_components)})")
            for comp in matrix.astro_components[:40]:
                file_short = comp.get('file', '').split('/')[-1]
                flags = []
                if comp.get('props_count', 0):
                    flags.append(f"props:{comp['props_count']}")
                if comp.get('slots_count', 0):
                    flags.append(f"slots:{comp['slots_count']}")
                if comp.get('has_scoped_style'):
                    flags.append("scoped")
                if comp.get('has_global_style'):
                    flags.append("global")
                if comp.get('has_set_html'):
                    flags.append("set:html")
                if comp.get('has_class_list'):
                    flags.append("class:list")
                if comp.get('has_define_vars'):
                    flags.append("define:vars")
                if comp.get('has_view_transitions'):
                    flags.append("ViewTransitions")
                if comp.get('has_fragment'):
                    flags.append("Fragment")
                if comp.get('expression_count', 0):
                    flags.append(f"exprs:{comp['expression_count']}")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                used = f"|uses:[{','.join(comp.get('components_used', [])[:8])}]" if comp.get('components_used') else ""
                style_langs = f"|styles:[{','.join(comp.get('style_langs', []))}]" if comp.get('style_langs') else ""
                lines.append(f"  {comp.get('name', '?')}{flag_str}{used}{style_langs}|{file_short}:{comp.get('line', 0)}")

        # Frontmatter summary
        if hasattr(matrix, 'astro_frontmatter') and matrix.astro_frontmatter:
            fm_count = len(matrix.astro_frontmatter)
            ts_count = sum(1 for f in matrix.astro_frontmatter if f.get('has_typescript'))
            gsp_count = sum(1 for f in matrix.astro_frontmatter if f.get('has_get_static_paths'))
            lines.append(f"# Frontmatter ({fm_count} files, {ts_count} TypeScript, {gsp_count} getStaticPaths)")
            for fm in matrix.astro_frontmatter[:20]:
                file_short = fm.get('file', '').split('/')[-1]
                flags = []
                if fm.get('has_typescript'):
                    flags.append("ts")
                if fm.get('has_get_static_paths'):
                    flags.append("getStaticPaths")
                if fm.get('has_paginate'):
                    flags.append("paginate")
                if fm.get('is_collection_config'):
                    flags.append("collectionConfig")
                if fm.get('uses_astro_redirect'):
                    flags.append("redirect")
                if fm.get('uses_astro_cookies'):
                    flags.append("cookies")
                if fm.get('uses_astro_locals'):
                    flags.append("locals")
                if fm.get('import_count', 0):
                    flags.append(f"imports:{fm['import_count']}")
                if fm.get('variable_count', 0):
                    flags.append(f"vars:{fm['variable_count']}")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                lines.append(f"  {file_short}{flag_str}")

        # Version / Frameworks / Features
        if hasattr(matrix, 'astro_version') and matrix.astro_version:
            lines.append(f"# Version: {matrix.astro_version}")
        if hasattr(matrix, 'astro_detected_frameworks') and matrix.astro_detected_frameworks:
            lines.append(f"# Frameworks: {', '.join(matrix.astro_detected_frameworks[:20])}")
        if hasattr(matrix, 'astro_detected_features') and matrix.astro_detected_features:
            lines.append(f"# Features: {', '.join(matrix.astro_detected_features[:25])}")

        return lines

    def _compress_astro_islands(self, matrix) -> List[str]:
        """Compress Astro island architecture (partial hydration directives)."""
        lines: List[str] = []

        if hasattr(matrix, 'astro_islands') and matrix.astro_islands:
            # Group by directive
            by_directive: dict = {}
            for island in matrix.astro_islands:
                d = island.get('directive', 'unknown')
                by_directive.setdefault(d, []).append(island)

            lines.append(f"# Islands ({len(matrix.astro_islands)} total)")
            for directive, islands in by_directive.items():
                fw_set = set()
                for isl in islands:
                    if isl.get('framework'):
                        fw_set.add(isl['framework'])
                fw_str = f"|frameworks:[{','.join(sorted(fw_set))}]" if fw_set else ""
                lines.append(f"  {directive}|count:{len(islands)}{fw_str}")

            # Detail items
            for island in matrix.astro_islands[:30]:
                file_short = island.get('file', '').split('/')[-1]
                fw = f"|fw:{island['framework']}" if island.get('framework') else ""
                val = f"|val:{island['directive_value']}" if island.get('directive_value') else ""
                props = f"|props:[{','.join(island.get('prop_names', [])[:5])}]" if island.get('has_props') else ""
                lines.append(f"  {island.get('component_name', '?')}|{island.get('directive', '?')}{val}{fw}{props}|{file_short}:{island.get('line', 0)}")

        # Flags
        if hasattr(matrix, 'astro_has_islands') and matrix.astro_has_islands:
            lines.append("# has_islands: true")
        if hasattr(matrix, 'astro_has_view_transitions') and matrix.astro_has_view_transitions:
            lines.append("# has_view_transitions: true")

        return lines

    def _compress_astro_routing(self, matrix) -> List[str]:
        """Compress Astro file-based routing, API endpoints, and middleware."""
        lines: List[str] = []

        # Routes
        if hasattr(matrix, 'astro_routes') and matrix.astro_routes:
            lines.append(f"# Routes ({len(matrix.astro_routes)})")
            for route in matrix.astro_routes[:40]:
                file_short = route.get('file', '').split('/')[-1]
                flags = []
                if route.get('is_dynamic'):
                    flags.append("dynamic")
                if route.get('is_rest'):
                    flags.append("rest")
                if route.get('rendering_mode'):
                    flags.append(route['rendering_mode'])
                if route.get('params'):
                    flags.append(f"params:[{','.join(route['params'][:5])}]")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                lines.append(f"  {route.get('path', '/')}{flag_str}|{file_short}")

        # Endpoints
        if hasattr(matrix, 'astro_endpoints') and matrix.astro_endpoints:
            lines.append(f"# Endpoints ({len(matrix.astro_endpoints)})")
            for ep in matrix.astro_endpoints[:30]:
                file_short = ep.get('file', '').split('/')[-1]
                methods = ','.join(ep.get('methods', []))
                flags = []
                if ep.get('returns_json'):
                    flags.append("json")
                if ep.get('returns_redirect'):
                    flags.append("redirect")
                if ep.get('is_prerendered'):
                    flags.append("prerender")
                if ep.get('has_params'):
                    flags.append("params")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                route = f"|route:{ep['route_path']}" if ep.get('route_path') else ""
                lines.append(f"  [{methods}]{route}{flag_str}|{file_short}:{ep.get('line', 0)}")

        # Middleware
        if hasattr(matrix, 'astro_middleware') and matrix.astro_middleware:
            lines.append(f"# Middleware ({len(matrix.astro_middleware)})")
            for mw in matrix.astro_middleware[:10]:
                file_short = mw.get('file', '').split('/')[-1]
                flags = []
                if mw.get('uses_sequence'):
                    flags.append("sequence")
                if mw.get('uses_locals'):
                    flags.append("locals")
                if mw.get('uses_redirect'):
                    flags.append("redirect")
                if mw.get('uses_rewrite'):
                    flags.append("rewrite")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
