    def _compress_astro_api(self, matrix) -> List[str]:
        """Compress Astro imports, integrations, config, types, version."""
        lines: List[str] = []

        # Imports grouped by source
        if hasattr(matrix, 'astro_imports') and matrix.astro_imports:
            by_source: dict = {}
            for imp in matrix.astro_imports:
                src = imp.get('source', 'unknown')
                by_source.setdefault(src, []).append(imp)

            virtual = sum(1 for imp in matrix.astro_imports if imp.get('is_virtual_module'))
            lines.append(f"# Imports ({len(matrix.astro_imports)} from {len(by_source)} sources, {virtual} virtual)")
            for src, imps in list(by_source.items())[:15]:
                all_names: list = []
                for imp in imps:
                    all_names.extend(imp.get('named_imports', []))
                unique_names = list(dict.fromkeys(all_names))[:12]
                is_virtual = "|virtual" if any(imp.get('is_virtual_module') for imp in imps) else ""
                lines.append(f"  {src}|names:[{','.join(unique_names)}]{is_virtual}|files:{len(imps)}")

        # Integrations
        if hasattr(matrix, 'astro_integrations') and matrix.astro_integrations:
            by_cat: dict = {}
            for intg in matrix.astro_integrations:
                cat = intg.get('category', 'unknown')
                by_cat.setdefault(cat, []).append(intg)

            lines.append(f"# Integrations ({len(matrix.astro_integrations)})")
            for cat, intgs in by_cat.items():
                names = [intg.get('name', '?') for intg in intgs]
                official = sum(1 for intg in intgs if intg.get('is_official'))
                off_str = f"|official:{official}" if official else ""
                lines.append(f"  [{cat}] {', '.join(names[:8])}{off_str}")

        # Config
        if hasattr(matrix, 'astro_config') and matrix.astro_config:
            for cfg in matrix.astro_config[:5]:
                file_short = cfg.get('file', '').split('/')[-1]
                flags = []
                if cfg.get('output_mode'):
                    flags.append(f"output:{cfg['output_mode']}")
                if cfg.get('adapter'):
                    flags.append(f"adapter:{cfg['adapter']}")
                if cfg.get('has_i18n'):
                    flags.append("i18n")
                if cfg.get('has_experimental'):
                    flags.append(f"experimental:[{','.join(cfg.get('experimental_flags', [])[:5])}]")
                if cfg.get('has_vite_config'):
                    flags.append("vite")
                if cfg.get('has_markdown_config'):
                    flags.append("markdown")
                if cfg.get('has_redirects'):
                    flags.append("redirects")
                if cfg.get('has_prefetch'):
                    flags.append("prefetch")
                if cfg.get('integration_count', 0):
                    flags.append(f"integrations:{cfg['integration_count']}")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                lines.append(f"# Config: {file_short}{flag_str}")

        # Types
        if hasattr(matrix, 'astro_types') and matrix.astro_types:
            lines.append(f"# TypeScript types ({len(matrix.astro_types)})")
            for t in matrix.astro_types[:15]:
                file_short = t.get('file', '').split('/')[-1]
                src = f"|from:{t['source']}" if t.get('source') else ""
                lines.append(f"  {t.get('type_name', '?')}{src}|{file_short}:{t.get('line', 0)}")

        return lines

