    def _compress_solidjs_components(self, matrix) -> List[str]:
        """Compress Solid.js components and control flow."""
        lines: List[str] = []

        # Components
        if hasattr(matrix, 'solidjs_components') and matrix.solidjs_components:
            lines.append(f"# Components ({len(matrix.solidjs_components)})")
            for comp in matrix.solidjs_components[:30]:
                file_short = comp.get('file', '').split('/')[-1]
                flags = []
                if comp.get('component_type'):
                    flags.append(comp['component_type'])
