    def _compress_qwik_components(self, matrix) -> List[str]:
        """Compress Qwik components and slots."""
        lines: List[str] = []

        # Components
        if hasattr(matrix, 'qwik_components') and matrix.qwik_components:
            lines.append(f"# Components ({len(matrix.qwik_components)})")
            for comp in matrix.qwik_components[:30]:
                file_short = comp.get('file', '').split('/')[-1]
                flags = []
                if comp.get('component_type'):
                    flags.append(comp['component_type'])
                if comp.get('props_type'):
                    flags.append(f"props:{comp['props_type']}")
                if comp.get('has_slot'):
                    flags.append("Slot")
                if comp.get('has_ref'):
                    flags.append("ref")
                if comp.get('is_exported'):
                    flags.append("exported")
                evts = comp.get('event_handlers', [])
                if evts:
                    flags.append(f"events:[{','.join(evts[:5])}]")
                sigs = comp.get('signals_used', [])
                if sigs:
                    flags.append(f"signals:[{','.join(sigs[:5])}]")
                tasks = comp.get('tasks_used', [])
                if tasks:
                    flags.append(f"tasks:[{','.join(tasks[:3])}]")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                lines.append(f"  {comp.get('name', '?')}{flag_str}|{file_short}:{comp.get('line', 0)}")

        # Slots
        if hasattr(matrix, 'qwik_slots') and matrix.qwik_slots:
            lines.append(f"# Slots ({len(matrix.qwik_slots)})")
            for slot in matrix.qwik_slots[:15]:
                file_short = slot.get('file', '').split('/')[-1]
                name = slot.get('slot_name') or 'default'
                parent = f"|parent:{slot['parent_component']}" if slot.get('parent_component') else ""
                lines.append(f"  {name}{parent}|{file_short}:{slot.get('line', 0)}")

        return lines

