    def _compress_preact_components(self, matrix) -> List[str]:
        """Compress Preact components: functional, class, memo, lazy, forwardRef, error boundaries."""
        lines: List[str] = []

        # Functional components
        if hasattr(matrix, 'preact_components') and matrix.preact_components:
            lines.append(f"# FunctionalComponents ({len(matrix.preact_components)})")
            for comp in matrix.preact_components[:30]:
                file_short = comp.get('file', '').split('/')[-1]
                flags = []
                if comp.get('component_type') and comp['component_type'] != 'functional':
                    flags.append(comp['component_type'])
                if comp.get('props_type'):
                    flags.append(f"props:{comp['props_type']}")
                if comp.get('is_exported'):
                    flags.append("exported")
                if comp.get('is_default_export'):
                    flags.append("default")
                if comp.get('is_compat_mode'):
                    flags.append("compat")
                if comp.get('uses_h_function'):
                    flags.append("h()")
                hooks = comp.get('hooks_used', [])
                if hooks:
                    flags.append(f"hooks:[{','.join(hooks[:5])}]")
                sigs = comp.get('signals_used', [])
                if sigs:
                    flags.append(f"signals:[{','.join(sigs[:5])}]")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                lines.append(f"  {comp.get('name', '?')}{flag_str}|{file_short}:{comp.get('line', 0)}")

        # Class components
        if hasattr(matrix, 'preact_class_components') and matrix.preact_class_components:
            lines.append(f"# ClassComponents ({len(matrix.preact_class_components)})")
            for cc in matrix.preact_class_components[:20]:
                file_short = cc.get('file', '').split('/')[-1]
                flags = []
                if cc.get('superclass'):
                    flags.append(f"extends:{cc['superclass']}")
                if cc.get('props_type'):
                    flags.append(f"props:{cc['props_type']}")
                if cc.get('state_type'):
                    flags.append(f"state:{cc['state_type']}")
                if cc.get('has_error_boundary'):
                    flags.append("errorBoundary")
                if cc.get('has_linked_state'):
                    flags.append("linkState")
                if cc.get('is_exported'):
                    flags.append("exported")
                lcms = cc.get('lifecycle_methods', [])
                if lcms:
                    flags.append(f"lifecycle:[{','.join(lcms[:5])}]")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                lines.append(f"  {cc.get('name', '?')}{flag_str}|{file_short}:{cc.get('line', 0)}")

        # Memos
        if hasattr(matrix, 'preact_memos') and matrix.preact_memos:
            lines.append(f"# Memo ({len(matrix.preact_memos)})")
            for memo in matrix.preact_memos[:15]:
                file_short = memo.get('file', '').split('/')[-1]
