    def _compress_preact_api(self, matrix) -> List[str]:
        """Compress Preact imports, integrations, types, SSR patterns, version, ecosystem."""
        lines: List[str] = []

        # Imports grouped by source
        if hasattr(matrix, 'preact_imports') and matrix.preact_imports:
            by_source: dict = {}
            for imp in matrix.preact_imports:
                src = imp.get('source', 'unknown')
                by_source.setdefault(src, []).append(imp)

            lines.append(f"# Imports ({len(matrix.preact_imports)} from {len(by_source)} sources)")
            for src, imps in list(by_source.items())[:15]:
                all_names: list = []
                for imp in imps:
                    all_names.extend(imp.get('named_imports', []))
                unique_names = list(dict.fromkeys(all_names))[:12]
                cat = imps[0].get('import_category', '')
                cat_str = f"|cat:{cat}" if cat else ""
                type_count = sum(1 for imp in imps if imp.get('is_type_import'))
                type_str = f"|types:{type_count}" if type_count else ""
                lines.append(f"  {src}|names:[{','.join(unique_names)}]{cat_str}{type_str}|files:{len(imps)}")

        # SSR patterns
        if hasattr(matrix, 'preact_ssr_patterns') and matrix.preact_ssr_patterns:
            lines.append(f"# SSR ({len(matrix.preact_ssr_patterns)})")
            for ssr in matrix.preact_ssr_patterns[:10]:
                file_short = ssr.get('file', '').split('/')[-1]
                flags = []
                if ssr.get('ssr_type'):
                    flags.append(ssr['ssr_type'])
                if ssr.get('is_async'):
                    flags.append("async")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                lines.append(f"  {ssr.get('name', '?')}{flag_str}|{file_short}:{ssr.get('line', 0)}")

        # Integrations
        if hasattr(matrix, 'preact_integrations') and matrix.preact_integrations:
            lines.append(f"# Integrations ({len(matrix.preact_integrations)})")
            for integ in matrix.preact_integrations[:15]:
                file_short = integ.get('file', '').split('/')[-1]
                itype = f"|type:{integ['integration_type']}" if integ.get('integration_type') else ""
                pkg = f"|pkg:{integ['source_package']}" if integ.get('source_package') else ""
                lines.append(f"  {integ.get('name', '?')}{itype}{pkg}|{file_short}:{integ.get('line', 0)}")

        # Types
        if hasattr(matrix, 'preact_types') and matrix.preact_types:
            lines.append(f"# TypeScript types ({len(matrix.preact_types)})")
            for t in matrix.preact_types[:15]:
                file_short = t.get('file', '').split('/')[-1]
                src = f"|from:{t['source']}" if t.get('source') else ""
                lines.append(f"  {t.get('type_name', '?')}{src}|{file_short}:{t.get('line', 0)}")

        # Version & metadata
        if hasattr(matrix, 'preact_version') and matrix.preact_version:
            lines.append(f"# version: {matrix.preact_version}")

        if hasattr(matrix, 'preact_detected_frameworks') and matrix.preact_detected_frameworks:
            lines.append(f"# frameworks: [{','.join(matrix.preact_detected_frameworks[:15])}]")

        if hasattr(matrix, 'preact_detected_features') and matrix.preact_detected_features:
            lines.append(f"# features: [{','.join(matrix.preact_detected_features[:25])}]")

        if hasattr(matrix, 'preact_has_signals') and matrix.preact_has_signals:
            lines.append("# has_signals: true")

        if hasattr(matrix, 'preact_has_compat') and matrix.preact_has_compat:
            lines.append("# has_compat: true")

        if hasattr(matrix, 'preact_has_ssr') and matrix.preact_has_ssr:
            lines.append("# has_ssr: true")

        return lines

