    def _compress_lit_components(self, matrix) -> List[str]:
        """Compress Lit components: LitElement, ReactiveElement, controllers, mixins."""
        lines: List[str] = []

        # Components
        if hasattr(matrix, 'lit_components') and matrix.lit_components:
            lines.append(f"# Components ({len(matrix.lit_components)})")
            for comp in matrix.lit_components[:30]:
                file_short = comp.get('file', '').split('/')[-1]
                flags = []
                if comp.get('tag_name'):
                    flags.append(f"<{comp['tag_name']}>")
                if comp.get('superclass'):
                    flags.append(f"extends:{comp['superclass']}")
                if comp.get('component_type') and comp['component_type'] != 'lit-element':
                    flags.append(comp['component_type'])
                if comp.get('has_shadow_dom'):
                    flags.append("shadow")
                lcms = comp.get('lifecycle_methods', [])
                if lcms:
                    flags.append(f"lifecycle:[{','.join(lcms[:5])}]")
                qds = comp.get('query_decorators', [])
                if qds:
                    flags.append(f"queries:[{','.join(qds[:5])}]")
                ctrls = comp.get('controllers_used', [])
                if ctrls:
                    flags.append(f"controllers:[{','.join(ctrls[:3])}]")
                evts = comp.get('events_dispatched', [])
                if evts:
                    flags.append(f"events:[{','.join(evts[:3])}]")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                lines.append(f"  {comp.get('name', '?')}{flag_str}|{file_short}:{comp.get('line', 0)}")

        # Mixins
        if hasattr(matrix, 'lit_mixins') and matrix.lit_mixins:
            lines.append(f"# Mixins ({len(matrix.lit_mixins)})")
            for mx in matrix.lit_mixins[:15]:
                file_short = mx.get('file', '').split('/')[-1]
                dedup = "|dedup" if mx.get('is_dedup') else ""
                lines.append(f"  {mx.get('name', '?')}{dedup}|{file_short}:{mx.get('line', 0)}")

        # Controllers
        if hasattr(matrix, 'lit_controllers') and matrix.lit_controllers:
            lines.append(f"# ReactiveControllers ({len(matrix.lit_controllers)})")
            for ctrl in matrix.lit_controllers[:15]:
                file_short = ctrl.get('file', '').split('/')[-1]
                hooks = []
                if ctrl.get('has_host_connected'):
                    hooks.append("connected")
                if ctrl.get('has_host_disconnected'):
                    hooks.append("disconnected")
                if ctrl.get('has_host_update'):
                    hooks.append("update")
                if ctrl.get('has_host_updated'):
                    hooks.append("updated")
                hook_str = f"|[{','.join(hooks)}]" if hooks else ""
                lines.append(f"  {ctrl.get('name', '?')}{hook_str}|{file_short}:{ctrl.get('line', 0)}")

        return lines

