    def _compress_lit_templates(self, matrix) -> List[str]:
        """Compress Lit templates: html``, svg``, css``, directives, bindings."""
        lines: List[str] = []

        # Templates
        if hasattr(matrix, 'lit_templates') and matrix.lit_templates:
            lines.append(f"# Templates ({len(matrix.lit_templates)})")
            for tpl in matrix.lit_templates[:25]:
                file_short = tpl.get('file', '').split('/')[-1]
                flags = []
                flags.append(tpl.get('template_type', 'html'))
                binds = []
                if tpl.get('property_bindings', 0):
                    binds.append(f".prop:{tpl['property_bindings']}")
                if tpl.get('attribute_bindings', 0):
                    binds.append(f"attr:{tpl['attribute_bindings']}")
                if tpl.get('event_bindings', 0):
                    binds.append(f"@evt:{tpl['event_bindings']}")
                if tpl.get('boolean_bindings', 0):
                    binds.append(f"?bool:{tpl['boolean_bindings']}")
                if binds:
                    flags.append(f"bindings:[{','.join(binds)}]")
                if tpl.get('has_slot'):
                    flags.append("slot")
                if tpl.get('has_conditional'):
                    flags.append("cond")
                if tpl.get('has_loop'):
                    flags.append("loop")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                lines.append(f"  template{flag_str}|{file_short}:{tpl.get('line', 0)}")

        # Directive usages grouped by category
        if hasattr(matrix, 'lit_directive_usages') and matrix.lit_directive_usages:
            by_cat: dict = {}
            for du in matrix.lit_directive_usages:
                cat = du.get('category', 'other')
                by_cat.setdefault(cat, []).append(du)

            lines.append(f"# Directives ({len(matrix.lit_directive_usages)} across {len(by_cat)} categories)")
            for cat, usages in sorted(by_cat.items()):
                dir_counts: dict = {}
                for u in usages:
                    dn = u.get('directive_name', '?')
                    dir_counts.setdefault(dn, 0)
                    dir_counts[dn] += 1
                summary = ', '.join(f"{k}:{v}" for k, v in dir_counts.items())
                lines.append(f"  {cat}: {summary}")

        # CSS Info
        if hasattr(matrix, 'lit_css_info') and matrix.lit_css_info:
            lines.append(f"# CSS ({len(matrix.lit_css_info)})")
            for ci in matrix.lit_css_info[:15]:
                file_short = ci.get('file', '').split('/')[-1]
                flags = []
                flags.append(ci.get('style_type', 'css'))
                if ci.get('has_host'):
                    flags.append(":host")
                if ci.get('has_part'):
                    flags.append("::part")
                if ci.get('has_slotted'):
                    flags.append("::slotted")
                if ci.get('has_adopted_sheets'):
                    flags.append("adoptedSheets")
                cps = ci.get('custom_properties', [])
                if cps:
                    flags.append(f"vars:[{','.join(cps[:3])}]")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                lines.append(f"  style{flag_str}|{file_short}:{ci.get('line', 0)}")

        return lines

