    def _compress_alpinejs_directives(self, matrix) -> List[str]:
        """Compress Alpine.js directives: x-data, x-bind, x-on, x-model, etc."""
        lines: List[str] = []

        if hasattr(matrix, 'alpine_directives') and matrix.alpine_directives:
            # Group by directive name prefix
            by_name: dict = {}
            for d in matrix.alpine_directives:
                prefix = d.get('name', 'unknown').split('.')[0].split(':')[0]
                by_name.setdefault(prefix, []).append(d)

            for prefix, dirs in sorted(by_name.items()):
                lines.append(f"# {prefix} ({len(dirs)})")
                for d in dirs[:25]:
                    file_short = d.get('file', '').split('/')[-1]
                    flags = []
                    mods = d.get('modifiers', [])
                    if mods:
                        flags.append(f"mod:{','.join(mods[:3])}")
                    if d.get('shorthand'):
                        flags.append("shorthand")
                    if d.get('version_hint'):
                        flags.append(d['version_hint'])
                    if d.get('bound_attribute'):
                        flags.append(f"attr:{d['bound_attribute']}")
                    if d.get('event_name'):
                        flags.append(f"evt:{d['event_name']}")
                    value_preview = d.get('value', '')
                    if value_preview and len(value_preview) > 50:
                        value_preview = value_preview[:50] + '...'
                    val_str = f"|val:{value_preview}" if value_preview else ""
                    flag_str = f"|[{','.join(flags)}]" if flags else ""
                    lines.append(f"  {d.get('name', '?')}{flag_str}{val_str}|{file_short}:{d.get('line', 0)}")
                if len(dirs) > 25:
                    lines.append(f"  # ... and {len(dirs) - 25} more {prefix}")

        return lines

