    def _compress_alpinejs_api(self, matrix) -> List[str]:
        """Compress Alpine.js imports, integrations, types, CDNs, version, ecosystem."""
        lines: List[str] = []

        # Imports grouped by source
        if hasattr(matrix, 'alpine_imports') and matrix.alpine_imports:
            by_source: dict = {}
            for imp in matrix.alpine_imports:
                src = imp.get('source', 'unknown')
                by_source.setdefault(src, []).append(imp)

            lines.append(f"# Imports ({len(matrix.alpine_imports)} from {len(by_source)} sources)")
            for src, imps in list(by_source.items())[:15]:
                all_names: list = []
                for imp in imps:
                    all_names.extend(imp.get('named_imports', []))
                unique_names = list(dict.fromkeys(all_names))[:12]
                default_count = sum(1 for imp in imps if imp.get('default_import'))
                default_str = f"|default:{default_count}" if default_count else ""
                type_count = sum(1 for imp in imps if imp.get('is_type_import'))
                type_str = f"|types:{type_count}" if type_count else ""
                names_str = f"|names:[{','.join(unique_names)}]" if unique_names else ""
                lines.append(f"  {src}{names_str}{default_str}{type_str}|files:{len(imps)}")

        # CDNs
        if hasattr(matrix, 'alpine_cdns') and matrix.alpine_cdns:
            lines.append(f"# CDN Scripts ({len(matrix.alpine_cdns)})")
            for cdn in matrix.alpine_cdns[:10]:
                file_short = cdn.get('file', '').split('/')[-1]
                flags = []
                if cdn.get('version'):
                    flags.append(f"v{cdn['version']}")
                if cdn.get('has_defer'):
                    flags.append("defer")
                if cdn.get('is_plugin'):
                    flags.append(f"plugin:{cdn.get('plugin_name', '')}")
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                url_short = cdn.get('url', '')[-60:]
                lines.append(f"  {url_short}{flag_str}|{file_short}:{cdn.get('line', 0)}")

        # Integrations
        if hasattr(matrix, 'alpine_integrations') and matrix.alpine_integrations:
            lines.append(f"# Integrations ({len(matrix.alpine_integrations)})")
            for integ in matrix.alpine_integrations[:15]:
                file_short = integ.get('file', '').split('/')[-1]
                itype = f"|type:{integ['integration_type']}" if integ.get('integration_type') else ""
                lines.append(f"  {integ.get('name', '?')}{itype}|{file_short}:{integ.get('line', 0)}")

        # Types
        if hasattr(matrix, 'alpine_types') and matrix.alpine_types:
            lines.append(f"# TypeScript types ({len(matrix.alpine_types)})")
            for t in matrix.alpine_types[:15]:
                file_short = t.get('file', '').split('/')[-1]
                src = f"|from:{t['source']}" if t.get('source') else ""
                lines.append(f"  {t.get('type_name', '?')}{src}|{file_short}:{t.get('line', 0)}")

        # Version & metadata
        if hasattr(matrix, 'alpine_version') and matrix.alpine_version:
            lines.append(f"# version: {matrix.alpine_version}")

        if hasattr(matrix, 'alpine_detected_frameworks') and matrix.alpine_detected_frameworks:
            lines.append(f"# frameworks: [{','.join(matrix.alpine_detected_frameworks[:15])}]")

        if hasattr(matrix, 'alpine_detected_features') and matrix.alpine_detected_features:
            lines.append(f"# features: [{','.join(matrix.alpine_detected_features[:30])}]")

        if hasattr(matrix, 'alpine_has_stores') and matrix.alpine_has_stores:
            lines.append("# has_stores: true")

        if hasattr(matrix, 'alpine_has_plugins') and matrix.alpine_has_plugins:
            lines.append("# has_plugins: true")

        if hasattr(matrix, 'alpine_has_cdn') and matrix.alpine_has_cdn:
            lines.append("# has_cdn: true")

        return lines

