    def _compress_htmx_requests(self, matrix) -> List[str]:
        """Compress HTMX requests: HTTP method endpoints, data, headers, encoding."""
        lines: List[str] = []

        if hasattr(matrix, 'htmx_requests') and matrix.htmx_requests:
            # Group by HTTP method
            by_method: dict = {}
            for r in matrix.htmx_requests:
                method = r.get('method', 'GET').upper()
                by_method.setdefault(method, []).append(r)

            for method, reqs in sorted(by_method.items()):
                lines.append(f"# {method} ({len(reqs)})")
                for r in reqs[:20]:
                    file_short = r.get('file', '').split('/')[-1]
                    flags = []
                    if r.get('has_vals'):
                        vtype = r.get('vals_type', '')
                        flags.append(f"vals:{vtype}" if vtype else "vals")
                    if r.get('has_headers'):
                        flags.append("headers")
                    if r.get('has_include'):
                        flags.append("include")
                    if r.get('has_params'):
                        flags.append("params")
                    if r.get('has_encoding'):
                        flags.append("encoding")
                    if r.get('has_confirm'):
                        flags.append("confirm")
                    if r.get('swap_strategy'):
                        flags.append(f"swap:{r['swap_strategy']}")
                    if r.get('target_selector'):
                        tgt = r['target_selector']
                        if len(tgt) > 30:
                            tgt = tgt[:30] + '...'
                        flags.append(f"target:{tgt}")
                    if r.get('trigger_spec'):
                        trig = r['trigger_spec']
                        if len(trig) > 30:
                            trig = trig[:30] + '...'
                        flags.append(f"trigger:{trig}")
                    flag_str = f"|[{','.join(flags)}]" if flags else ""
                    endpoint = r.get('endpoint', '?')
                    if len(endpoint) > 60:
                        endpoint = endpoint[:60] + '...'
                    lines.append(f"  {method} {endpoint}{flag_str}|{file_short}:{r.get('line', 0)}")
                if len(reqs) > 20:
                    lines.append(f"  # ... and {len(reqs) - 20} more {method}")

        return lines

