    def _compress_stimulus_controllers(self, matrix) -> List[str]:
        """Compress Stimulus controllers: class definitions, lifecycle, static declarations."""
        lines: List[str] = []

        if hasattr(matrix, 'stimulus_controllers') and matrix.stimulus_controllers:
            for ctrl in matrix.stimulus_controllers[:40]:
                file_short = ctrl.get('file', '').split('/')[-1]
                flags = []
                if ctrl.get('has_connect'):
                    flags.append("connect")
                if ctrl.get('has_disconnect'):
                    flags.append("disconnect")
                if ctrl.get('has_initialize'):
                    flags.append("initialize")
                if ctrl.get('version_hint'):
                    flags.append(ctrl['version_hint'])
                flag_str = f"|[{','.join(flags)}]" if flags else ""

                targets = ctrl.get('static_targets', [])
                tgt_str = f"|targets:[{','.join(targets[:8])}]" if targets else ""

                values = ctrl.get('static_values', [])
                val_str = f"|values:[{','.join(values[:8])}]" if values else ""

                classes = ctrl.get('static_classes', [])
                cls_str = f"|classes:[{','.join(classes[:5])}]" if classes else ""

                outlets = ctrl.get('static_outlets', [])
                out_str = f"|outlets:[{','.join(outlets[:5])}]" if outlets else ""

                methods = ctrl.get('methods', [])
                mth_str = f"|methods:[{','.join(methods[:8])}]" if methods else ""

                identifier = ctrl.get('identifier', '')
                id_str = f"|id:{identifier}" if identifier else ""

                extends = ctrl.get('extends', '')
                ext_str = f"|extends:{extends}" if extends and extends != 'Controller' else ""

                lines.append(
                    f"  {ctrl.get('name', '?')}{id_str}{ext_str}{flag_str}"
                    f"{tgt_str}{val_str}{cls_str}{out_str}{mth_str}"
                    f"|{file_short}:{ctrl.get('line', 0)}"
                )
            if len(matrix.stimulus_controllers) > 40:
                lines.append(f"  # ... and {len(matrix.stimulus_controllers) - 40} more controllers")

        return lines

    def _compress_stimulus_targets(self, matrix) -> List[str]:
        """Compress Stimulus targets: HTML data-*-target, JS getters, callbacks."""
        lines: List[str] = []

