    def _compress_stimulus_actions(self, matrix) -> List[str]:
        """Compress Stimulus actions: data-action descriptors, events, params, options."""
        lines: List[str] = []

        if hasattr(matrix, 'stimulus_actions') and matrix.stimulus_actions:
            # Group by controller
            by_ctrl: dict = {}
            for a in matrix.stimulus_actions:
                ctrl = a.get('controller', 'unknown')
                by_ctrl.setdefault(ctrl, []).append(a)

            for ctrl, actions in sorted(by_ctrl.items()):
                lines.append(f"# {ctrl} ({len(actions)})")
                for a in actions[:25]:
                    file_short = a.get('file', '').split('/')[-1]
                    flags = []
                    if a.get('has_prevent'):
                        flags.append(":prevent")
                    if a.get('has_stop'):
                        flags.append(":stop")
                    if a.get('is_global'):
                        flags.append(f"@{a.get('global_target', '')}")
                    if a.get('keyboard_filter'):
                        flags.append(f"key:{a['keyboard_filter']}")
                    flag_str = f"|[{','.join(flags)}]" if flags else ""

                    params = a.get('params', [])
                    param_str = f"|params:[{','.join(p[:20] for p in params[:5])}]" if params else ""

                    event = a.get('event', '')
                    method = a.get('method', '')
                    desc = f"{event}->{ctrl}#{method}" if event and method else a.get('descriptor', '?')[:60]

                    lines.append(f"  {desc}{flag_str}{param_str}|{file_short}:{a.get('line', 0)}")
                if len(actions) > 25:
                    lines.append(f"  # ... and {len(actions) - 25} more actions")

        return lines

    def _compress_stimulus_values(self, matrix) -> List[str]:
        """Compress Stimulus values: static declarations, HTML attrs, get/set, callbacks."""
        lines: List[str] = []

        if hasattr(matrix, 'stimulus_values') and matrix.stimulus_values:
            # Group by controller
            by_ctrl: dict = {}
            for v in matrix.stimulus_values:
                ctrl = v.get('controller', 'unknown')
                by_ctrl.setdefault(ctrl, []).append(v)

            for ctrl, values in sorted(by_ctrl.items()):
                lines.append(f"# {ctrl} ({len(values)})")
                for v in values[:25]:
                    file_short = v.get('file', '').split('/')[-1]
                    flags = []
                    if v.get('value_type'):
                        flags.append(f"type:{v['value_type']}")
                    if v.get('value_usage'):
                        flags.append(v['value_usage'])
                    if v.get('has_change_callback'):
                        flags.append("changed")
                    flag_str = f"|[{','.join(flags)}]" if flags else ""

                    default = v.get('default_value', '')
                    default_str = f"|default:{default[:30]}" if default else ""

                    lines.append(f"  {v.get('name', '?')}{flag_str}{default_str}|{file_short}:{v.get('line', 0)}")
                if len(values) > 25:
                    lines.append(f"  # ... and {len(values) - 25} more values")

        return lines

    def _compress_stimulus_api(self, matrix) -> List[str]:
        """Compress Stimulus imports, CDNs, configs, integrations, Turbo, Strada, version, ecosystem."""
        lines: List[str] = []

        # Imports grouped by source
        if hasattr(matrix, 'stimulus_imports') and matrix.stimulus_imports:
            by_source: dict = {}
            for imp in matrix.stimulus_imports:
                src = imp.get('source', 'unknown')
                by_source.setdefault(src, []).append(imp)

            lines.append(f"# Imports ({len(matrix.stimulus_imports)} from {len(by_source)} sources)")
            for src, imps in list(by_source.items())[:15]:
                all_names: list = []
                for imp in imps:
                    all_names.extend(imp.get('named_imports', []))
                unique_names = list(dict.fromkeys(all_names))[:12]
                default_count = sum(1 for imp in imps if imp.get('default_import'))
                default_str = f"|default:{default_count}" if default_count else ""
                type_count = sum(1 for imp in imps if imp.get('is_type_import'))
                type_str = f"|types:{type_count}" if type_count else ""
                version = next((imp.get('version_hint', '') for imp in imps if imp.get('version_hint')), '')
                ver_str = f"|{version}" if version else ""
                names_str = f"|names:[{','.join(unique_names)}]" if unique_names else ""
                lines.append(f"  {src}{names_str}{default_str}{type_str}{ver_str}|files:{len(imps)}")

        # CDNs
        if hasattr(matrix, 'stimulus_cdns') and matrix.stimulus_cdns:
            lines.append(f"# CDN Scripts ({len(matrix.stimulus_cdns)})")
            for cdn in matrix.stimulus_cdns[:10]:
                file_short = cdn.get('file', '').split('/')[-1]
                flags = []
                if cdn.get('version'):
                    flags.append(f"v{cdn['version']}")
                if cdn.get('has_defer'):
                    flags.append("defer")
                if cdn.get('has_integrity'):
                    flags.append("integrity")
                if cdn.get('package'):
                    flags.append(cdn['package'])
                flag_str = f"|[{','.join(flags)}]" if flags else ""
                url_short = cdn.get('url', '')[-60:]
                lines.append(f"  {url_short}{flag_str}|{file_short}:{cdn.get('line', 0)}")

        # Configs
        if hasattr(matrix, 'stimulus_configs') and matrix.stimulus_configs:
            lines.append(f"# Config ({len(matrix.stimulus_configs)})")
            for cfg in matrix.stimulus_configs[:15]:
                file_short = cfg.get('file', '').split('/')[-1]
                val = cfg.get('config_value', '')
                if len(val) > 50:
                    val = val[:50] + '...'
                val_str = f"|val:{val}" if val else ""
                lines.append(f"  {cfg.get('config_key', '?')}{val_str}|{file_short}:{cfg.get('line', 0)}")

        # Integrations
        if hasattr(matrix, 'stimulus_integrations') and matrix.stimulus_integrations:
            lines.append(f"# Integrations ({len(matrix.stimulus_integrations)})")
            for integ in matrix.stimulus_integrations[:15]:
                file_short = integ.get('file', '').split('/')[-1]
                itype = f"|type:{integ['integration_type']}" if integ.get('integration_type') else ""
                lines.append(f"  {integ.get('name', '?')}{itype}|{file_short}:{integ.get('line', 0)}")

        # Version & metadata
        if hasattr(matrix, 'stimulus_version') and matrix.stimulus_version:
            lines.append(f"# version: {matrix.stimulus_version}")

        if hasattr(matrix, 'stimulus_detected_frameworks') and matrix.stimulus_detected_frameworks:
            lines.append(f"# frameworks: [{','.join(matrix.stimulus_detected_frameworks[:15])}]")

        if hasattr(matrix, 'stimulus_detected_features') and matrix.stimulus_detected_features:
            lines.append(f"# features: [{','.join(matrix.stimulus_detected_features[:30])}]")

        if hasattr(matrix, 'stimulus_has_turbo') and matrix.stimulus_has_turbo:
            lines.append("# has_turbo: true")

        if hasattr(matrix, 'stimulus_has_strada') and matrix.stimulus_has_strada:
            lines.append("# has_strada: true")

        if hasattr(matrix, 'stimulus_has_turbo_frames') and matrix.stimulus_has_turbo_frames:
            lines.append("# has_turbo_frames: true")

        if hasattr(matrix, 'stimulus_has_turbo_streams') and matrix.stimulus_has_turbo_streams:
            lines.append("# has_turbo_streams: true")

        if hasattr(matrix, 'stimulus_has_cdn') and matrix.stimulus_has_cdn:
            lines.append("# has_cdn: true")

        if hasattr(matrix, 'stimulus_has_outlets') and matrix.stimulus_has_outlets:
            lines.append("# has_outlets: true")

        return lines

