    def _compress_storybook_stories(self, matrix) -> List[str]:
        """Compress Storybook stories: CSF versions, play functions, args, decorators."""
        lines: List[str] = []

        if hasattr(matrix, 'storybook_stories') and matrix.storybook_stories:
            # Group by title (component story group)
            by_title: dict = {}
            for s in matrix.storybook_stories:
                title = s.get('title', 'Ungrouped') or 'Ungrouped'
                by_title.setdefault(title, []).append(s)

            for title, stories in sorted(by_title.items()):
                # Filter out __meta__ from display count
                actual_stories = [s for s in stories if s.get('name') != '__meta__']
                if not actual_stories and not stories:
                    continue
                lines.append(f"# {title} ({len(actual_stories)} stories)")

                for s in stories[:30]:
                    name = s.get('name', '?')
                    if name == '__meta__':
                        continue  # Skip meta entry in story listing
                    file_short = s.get('file', '').split('/')[-1]
                    flags = []
                    if s.get('csf_version'):
                        flags.append(s['csf_version'])
                    if s.get('has_play'):
                        flags.append("play")
                    if s.get('has_render'):
                        flags.append("render")
                    if s.get('has_args'):
                        flags.append("args")
                    if s.get('has_decorators'):
                        flags.append("decorators")
                    if s.get('has_loaders'):
                        flags.append("loaders")
                    if s.get('has_before_each'):
                        flags.append("beforeEach")
                    if s.get('has_mount'):
                        flags.append("mount")
                    flag_str = f"|[{','.join(flags)}]" if flags else ""

                    tags = s.get('tags', [])
                    tag_str = f"|tags:[{','.join(tags[:5])}]" if tags else ""

                    args_keys = s.get('args_keys', [])
                    args_str = f"|args:[{','.join(args_keys[:6])}]" if args_keys else ""

                    lines.append(
                        f"  {name}{flag_str}{tag_str}{args_str}"
                        f"|{file_short}:{s.get('line', 0)}"
                    )
                if len(actual_stories) > 30:
                    lines.append(f"  # ... and {len(actual_stories) - 30} more stories")

        return lines

    def _compress_storybook_components(self, matrix) -> List[str]:
        """Compress Storybook component documentation."""
        lines: List[str] = []

        if hasattr(matrix, 'storybook_components') and matrix.storybook_components:
            # Group by category
            by_cat: dict = {}
            for c in matrix.storybook_components:
                cat = c.get('category', 'Uncategorized') or 'Uncategorized'
                by_cat.setdefault(cat, []).append(c)

            for cat, comps in sorted(by_cat.items()):
                lines.append(f"# {cat} ({len(comps)})")
                for c in comps[:30]:
                    file_short = c.get('file', '').split('/')[-1]
                    flags = []
                    if c.get('has_autodocs'):
                        flags.append("autodocs")
                    if c.get('has_subcomponents'):
                        flags.append(f"sub:[{','.join(c.get('subcomponents', [])[:3])}]")
                    if c.get('has_docs_page'):
                        flags.append("docs-page")
                    if c.get('has_source'):
                        flags.append("source")
                    flag_str = f"|[{','.join(flags)}]" if flags else ""

                    arg_types = c.get('arg_types', [])
                    at_str = f"|argTypes:[{','.join(arg_types[:6])}]" if arg_types else ""

                    controls = c.get('control_types', [])
                    ctrl_str = f"|controls:[{','.join(controls[:5])}]" if controls else ""

                    story_count = c.get('story_count', 0)
                    sc_str = f"|stories:{story_count}" if story_count else ""

                    lines.append(
                        f"  {c.get('name', '?')}{flag_str}{at_str}{ctrl_str}{sc_str}"
                        f"|{file_short}:{c.get('line', 0)}"
                    )

        return lines

    def _compress_storybook_addons(self, matrix) -> List[str]:
        """Compress Storybook addon registrations."""
        lines: List[str] = []

        if hasattr(matrix, 'storybook_addons') and matrix.storybook_addons:
            official = [a for a in matrix.storybook_addons if a.get('is_official')]
            community = [a for a in matrix.storybook_addons if not a.get('is_official')]

            if official:
                lines.append(f"# Official ({len(official)})")
                for a in official[:20]:
                    flags = []
                    if a.get('is_essential'):
                        flags.append("essential")
                    if a.get('has_options'):
                        opts = a.get('options_keys', [])
                        flags.append(f"opts:[{','.join(opts[:5])}]")
                    flag_str = f"|[{','.join(flags)}]" if flags else ""
                    lines.append(f"  {a.get('short_name', a.get('name', '?'))}{flag_str}")

            if community:
                lines.append(f"# Community ({len(community)})")
                for a in community[:15]:
                    flags = []
                    if a.get('addon_type') and a['addon_type'] != 'registration':
                        flags.append(a['addon_type'])
                    flag_str = f"|[{','.join(flags)}]" if flags else ""
                    lines.append(f"  {a.get('short_name', a.get('name', '?'))}{flag_str}")

        return lines

    def _compress_storybook_configs(self, matrix) -> List[str]:
        """Compress Storybook configuration."""
        lines: List[str] = []

        if hasattr(matrix, 'storybook_configs') and matrix.storybook_configs:
            for cfg in matrix.storybook_configs[:5]:
                config_type = cfg.get('config_type', '?')
                file_short = cfg.get('file', '').split('/')[-1]

                flags = []
                if cfg.get('framework'):
                    flags.append(f"framework:{cfg['framework']}")
                if cfg.get('builder'):
                    flags.append(f"builder:{cfg['builder']}")
                if cfg.get('storybook_version'):
                    flags.append(cfg['storybook_version'])
                if cfg.get('has_typescript'):
                    flags.append("typescript")
                if cfg.get('has_docs'):
                    flags.append("autodocs")
                if cfg.get('has_webpack_config'):
                    flags.append("webpackFinal")
                if cfg.get('has_vite_config'):
                    flags.append("viteFinal")
                flag_str = f"|[{','.join(flags)}]" if flags else ""

                stories = cfg.get('stories_globs', [])
                stories_str = f"|stories:[{','.join(stories[:3])}]" if stories else ""

                features = cfg.get('features', [])
                feat_str = f"|features:[{','.join(features[:5])}]" if features else ""

                refs = cfg.get('refs', [])
                refs_str = f"|refs:[{','.join(refs[:3])}]" if refs else ""

                lines.append(
                    f"  {config_type}{flag_str}{stories_str}{feat_str}{refs_str}|{file_short}"
                )

        # Metadata
        if hasattr(matrix, 'storybook_version') and matrix.storybook_version:
            lines.append(f"# version:{matrix.storybook_version}")
        if hasattr(matrix, 'storybook_csf_version') and matrix.storybook_csf_version:
            lines.append(f"# csf:{matrix.storybook_csf_version}")

        meta_flags = []
        if getattr(matrix, 'storybook_has_play_functions', False):
            meta_flags.append("play")
        if getattr(matrix, 'storybook_has_interaction_testing', False):
            meta_flags.append("interactions")
        if getattr(matrix, 'storybook_has_portable_stories', False):
            meta_flags.append("portable")
        if getattr(matrix, 'storybook_has_chromatic', False):
            meta_flags.append("chromatic")
        if getattr(matrix, 'storybook_has_autodocs', False):
            meta_flags.append("autodocs")
        if meta_flags:
            lines.append(f"# features:[{','.join(meta_flags)}]")

        return lines

    def _compress_storybook_api(self, matrix) -> List[str]:
        """Compress Storybook imports, testing, portable stories, Chromatic, version."""
        lines: List[str] = []

        # Imports grouped by category
        if hasattr(matrix, 'storybook_imports') and matrix.storybook_imports:
            by_cat: dict = {}
            for imp in matrix.storybook_imports:
                cat = imp.get('category', 'other')
                by_cat.setdefault(cat, []).append(imp)

            for cat, imps in sorted(by_cat.items()):
                lines.append(f"# {cat} ({len(imps)} imports)")
                # Group by source
                by_source: dict = {}
                for imp in imps:
                    src = imp.get('source', 'unknown')
                    by_source.setdefault(src, []).append(imp)

                for src, source_imps in list(by_source.items())[:15]:
                    all_names: list = []
                    for imp in source_imps:
                        all_names.extend(imp.get('named_imports', []))
                    unique_names = list(dict.fromkeys(all_names))[:12]
                    type_count = sum(1 for imp in source_imps if imp.get('is_type_import'))
                    type_str = f"|types:{type_count}" if type_count else ""
                    names_str = f"|names:[{','.join(unique_names)}]" if unique_names else ""
                    lines.append(f"  {src}{names_str}{type_str}|files:{len(source_imps)}")

        # Testing
        if hasattr(matrix, 'storybook_testing') and matrix.storybook_testing:
            by_type: dict = {}
            for t in matrix.storybook_testing:
                tt = t.get('testing_type', 'other')
                by_type.setdefault(tt, []).append(t)

            for tt, tests in sorted(by_type.items()):
                flags = []
                for t in tests:
                    if t.get('has_play'):
                        flags.append("play")
                    if t.get('has_expect'):
                        flags.append("expect")
                    if t.get('has_user_event'):
                        flags.append("userEvent")
                    if t.get('has_within'):
                        flags.append("within")
                    if t.get('has_step'):
                        flags.append("step")
                    if t.get('has_fn_mock'):
                        flags.append("fn/mock")
                unique_flags = list(dict.fromkeys(flags))
                flag_str = f"|[{','.join(unique_flags)}]" if unique_flags else ""
                lines.append(f"# testing:{tt} ({len(tests)} files){flag_str}")

        # Detected frameworks
        if hasattr(matrix, 'storybook_detected_frameworks') and matrix.storybook_detected_frameworks:
            fws = matrix.storybook_detected_frameworks[:20]
            lines.append(f"# ecosystem:[{','.join(fws)}]")

        return lines

