    def _compress_threejs_scene(self, matrix) -> List[str]:
        """Compress Three.js scene constructs: Canvas, Camera, Renderer, Controls, Lights, Post-processing, Physics."""
        lines: List[str] = []

        # Canvases
        if hasattr(matrix, 'threejs_canvases') and matrix.threejs_canvases:
            lines.append(f"# Canvas ({len(matrix.threejs_canvases)})")
            for c in matrix.threejs_canvases[:10]:
                file_short = c.get('file', '').split('/')[-1]
                shadows = "|shadows" if c.get('has_shadows') else ""
                cam = "|camera" if c.get('has_camera') else ""
                gl = "|gl" if c.get('has_gl_config') else ""
                fl = f"|frameloop:{c['frameloop']}" if c.get('frameloop') else ""
                dpr = f"|dpr:{c['dpr']}" if c.get('dpr') else ""
                lines.append(f"  <Canvas{shadows}{cam}{gl}{fl}{dpr}>|{file_short}")

        # Cameras
        if hasattr(matrix, 'threejs_cameras') and matrix.threejs_cameras:
            lines.append(f"# Cameras ({len(matrix.threejs_cameras)})")
            for cam in matrix.threejs_cameras[:10]:
                file_short = cam.get('file', '').split('/')[-1]
                lines.append(f"  {cam.get('camera_type', cam['name'])}|{file_short}")

        # Renderers
        if hasattr(matrix, 'threejs_renderers') and matrix.threejs_renderers:
            lines.append(f"# Renderers ({len(matrix.threejs_renderers)})")
            for r in matrix.threejs_renderers[:10]:
                file_short = r.get('file', '').split('/')[-1]
                shadows = "|shadows" if r.get('has_shadows') else ""
                aa = "|antialias" if r.get('has_antialiasing') else ""
                lines.append(f"  {r.get('renderer_type', r['name'])}{shadows}{aa}|{file_short}")

        # Controls
        if hasattr(matrix, 'threejs_controls') and matrix.threejs_controls:
            lines.append(f"# Controls ({len(matrix.threejs_controls)})")
            for ctrl in matrix.threejs_controls[:10]:
                file_short = ctrl.get('file', '').split('/')[-1]
                drei = "|drei" if ctrl.get('is_drei') else ""
                lines.append(f"  {ctrl.get('controls_type', ctrl['name'])}{drei}|{file_short}")

        # Lights
        if hasattr(matrix, 'threejs_lights') and matrix.threejs_lights:
            by_type: dict = {}
            for l in matrix.threejs_lights:
                lt = l.get('light_type', 'unknown')
                by_type.setdefault(lt, []).append(l)
            type_summary = ", ".join(f"{t}:{len(ls)}" for t, ls in sorted(by_type.items()))
            lines.append(f"# Lights ({len(matrix.threejs_lights)}): {type_summary}")

        # Post-processing
        if hasattr(matrix, 'threejs_post_processing') and matrix.threejs_post_processing:
            effects = [pp.get('effect_type', pp.get('name', '?')) for pp in matrix.threejs_post_processing]
            unique_effects = list(dict.fromkeys(effects))[:20]
            lines.append(f"# PostProcessing ({len(matrix.threejs_post_processing)}): [{','.join(unique_effects)}]")

        # Physics
        if hasattr(matrix, 'threejs_physics') and matrix.threejs_physics:
            engines = list(set(p.get('engine', '?') for p in matrix.threejs_physics))
            lines.append(f"# Physics ({len(matrix.threejs_physics)}): engines=[{','.join(engines)}]")
            for p in matrix.threejs_physics[:5]:
                file_short = p.get('file', '').split('/')[-1]
                debug = "|debug" if p.get('has_debug') else ""
                lines.append(f"  {p.get('engine', p['name'])}{debug}|{file_short}")

        return lines

    def _compress_threejs_components(self, matrix) -> List[str]:
        """Compress Three.js 3D components: meshes, groups, instanced, drei, custom, models."""
        lines: List[str] = []

        # Meshes
        if hasattr(matrix, 'threejs_meshes') and matrix.threejs_meshes:
            lines.append(f"# Meshes ({len(matrix.threejs_meshes)})")
            for m in matrix.threejs_meshes[:30]:
                file_short = m.get('file', '').split('/')[-1]
                geo = f"|geo:{m['geometry']}" if m.get('geometry') else ""
                mat = f"|mat:{m['material']}" if m.get('material') else ""
                r3f = "|r3f" if m.get('is_r3f') else ""
                lines.append(f"  {m.get('mesh_type', m['name'])}{geo}{mat}{r3f}|{file_short}")
            if len(matrix.threejs_meshes) > 30:
                lines.append(f"  # ... and {len(matrix.threejs_meshes) - 30} more meshes")

        # Groups
        if hasattr(matrix, 'threejs_groups') and matrix.threejs_groups:
            lines.append(f"# Groups ({len(matrix.threejs_groups)})")
            for g in matrix.threejs_groups[:15]:
                file_short = g.get('file', '').split('/')[-1]
                children = f"|children:{g['child_count']}" if g.get('child_count') else ""
                lines.append(f"  group{children}|{file_short}")

        # Instanced Meshes
        if hasattr(matrix, 'threejs_instanced_meshes') and matrix.threejs_instanced_meshes:
            lines.append(f"# InstancedMesh ({len(matrix.threejs_instanced_meshes)})")
            for inst in matrix.threejs_instanced_meshes[:10]:
                file_short = inst.get('file', '').split('/')[-1]
