    def _compress_threejs_materials(self, matrix) -> List[str]:
        """Compress Three.js materials, shaders, textures, uniforms."""
        lines: List[str] = []

        # Materials
        if hasattr(matrix, 'threejs_materials') and matrix.threejs_materials:
            by_type: dict = {}
