        # Textures
        if hasattr(matrix, 'threejs_textures') and matrix.threejs_textures:
            lines.append(f"# Textures ({len(matrix.threejs_textures)})")
            for tex in matrix.threejs_textures[:15]:
                file_short = tex.get('file', '').split('/')[-1]
