    def _compress_threejs_api(self, matrix) -> List[str]:
        """Compress Three.js API: imports, integrations, types, version, ecosystem."""
        lines: List[str] = []

        # Imports grouped by source
        if hasattr(matrix, 'threejs_imports') and matrix.threejs_imports:
            by_source: dict = {}
            for imp in matrix.threejs_imports:
                src = imp.get('source', 'unknown')
                by_source.setdefault(src, []).append(imp)
            for src, imps in sorted(by_source.items()):
                all_specs: list = []
                for imp in imps:
                    all_specs.extend(imp.get('specifiers', []))
                unique_specs = list(dict.fromkeys(all_specs))[:15]
                ns_count = sum(1 for imp in imps if imp.get('is_namespace'))
                dyn_count = sum(1 for imp in imps if imp.get('is_dynamic'))
                type_count = sum(1 for imp in imps if imp.get('is_type_only'))
                flags = []
                if ns_count:
                    flags.append(f"ns:{ns_count}")
                if dyn_count:
                    flags.append(f"dynamic:{dyn_count}")
                if type_count:
                    flags.append(f"types:{type_count}")
                flag_str = f"|{','.join(flags)}" if flags else ""
                spec_str = f"|[{','.join(unique_specs)}]" if unique_specs else ""
                lines.append(f"# {src} ({len(imps)} files){spec_str}{flag_str}")

        # Integrations
        if hasattr(matrix, 'threejs_integrations') and matrix.threejs_integrations:
            by_type: dict = {}
            for integ in matrix.threejs_integrations:
                it = integ.get('integration_type', 'other')
                by_type.setdefault(it, []).append(integ)
            for it, integs in sorted(by_type.items()):
                names = list(dict.fromkeys(i['name'] for i in integs))
                lines.append(f"# integrations/{it}: [{','.join(names)}]")

        # TypeScript types
        if hasattr(matrix, 'threejs_types') and matrix.threejs_types:
            type_names = list(dict.fromkeys(t['name'] for t in matrix.threejs_types))[:20]
            lines.append(f"# Types ({len(matrix.threejs_types)}): [{','.join(type_names)}]")

        # Detected frameworks
        if hasattr(matrix, 'threejs_detected_frameworks') and matrix.threejs_detected_frameworks:
            fws = matrix.threejs_detected_frameworks[:30]
            lines.append(f"# ecosystem:[{','.join(fws)}]")

        # Detected features
        if hasattr(matrix, 'threejs_detected_features') and matrix.threejs_detected_features:
            feats = matrix.threejs_detected_features[:20]
            lines.append(f"# features:[{','.join(feats)}]")

        # Versions
        if hasattr(matrix, 'threejs_version') and matrix.threejs_version:
            lines.append(f"# Three.js version: {matrix.threejs_version}")
        if hasattr(matrix, 'threejs_r3f_version') and matrix.threejs_r3f_version:
            lines.append(f"# R3F version: {matrix.threejs_r3f_version}")

        # Mode
        if hasattr(matrix, 'threejs_is_vanilla') and matrix.threejs_is_vanilla:
            lines.append("# Mode: vanilla Three.js")
        if hasattr(matrix, 'threejs_is_r3f') and matrix.threejs_is_r3f:
            lines.append("# Mode: React Three Fiber")

        return lines

