    def _compress_d3js_visualizations(self, matrix) -> List[str]:
        """Compress D3.js visualizations: selections, data joins, shapes, layouts, SVG elements."""
        lines: List[str] = []

        # Selections
        if hasattr(matrix, 'd3js_selections') and matrix.d3js_selections:
            by_type: dict = {}
            for sel in matrix.d3js_selections:
                st = sel.get('selection_type', 'select')
                by_type.setdefault(st, []).append(sel)
            for st, sels in sorted(by_type.items()):
                selectors = list(dict.fromkeys(s.get('selector', '?') for s in sels))[:10]
                chained_count = sum(1 for s in sels if s.get('is_chained'))
                data_count = sum(1 for s in sels if s.get('has_data_binding'))
                flags = []
                if chained_count:
                    flags.append(f"chained:{chained_count}")
                if data_count:
                    flags.append(f"data:{data_count}")
                flag_str = f"|{','.join(flags)}" if flags else ""
                lines.append(f"  {st}({len(sels)}): [{','.join(selectors)}]{flag_str}")

        # Data Joins
        if hasattr(matrix, 'd3js_data_joins') and matrix.d3js_data_joins:
            by_type = {}
            for dj in matrix.d3js_data_joins:
                jt = dj.get('join_type', 'classic')
                by_type.setdefault(jt, []).append(dj)
            for jt, joins in sorted(by_type.items()):
                elements = list(dict.fromkeys(j.get('element', '') for j in joins if j.get('element')))[:10]
                elem_str = f"|elements=[{','.join(elements)}]" if elements else ""
                lines.append(f"  join/{jt}({len(joins)}){elem_str}")

        # Shapes
        if hasattr(matrix, 'd3js_shapes') and matrix.d3js_shapes:
            by_type = {}
            for shape in matrix.d3js_shapes:
                st = shape.get('shape_type', '?')
                by_type.setdefault(st, []).append(shape)
            shape_summary = [f"{st}:{len(shapes)}" for st, shapes in sorted(by_type.items())]
            lines.append(f"  shapes({len(matrix.d3js_shapes)}): [{','.join(shape_summary)}]")

        # Layouts
        if hasattr(matrix, 'd3js_layouts') and matrix.d3js_layouts:
            for layout in matrix.d3js_layouts[:10]:
                lt = layout.get('layout_type', '?')
                forces = layout.get('forces', [])
                force_str = f"|forces=[{','.join(forces)}]" if forces else ""
                sim_str = "|simulation" if layout.get('has_simulation') else ""
                lines.append(f"  layout/{lt}{sim_str}{force_str}|{layout.get('file', '?')}")

        # SVG Elements summary
        if hasattr(matrix, 'd3js_svg_elements') and matrix.d3js_svg_elements:
            by_type = {}
            for elem in matrix.d3js_svg_elements:
                et = elem.get('element_type', '?')
                by_type.setdefault(et, 0)
                by_type[et] += 1
            elem_summary = [f"{et}:{cnt}" for et, cnt in sorted(by_type.items(), key=lambda x: -x[1])[:15]]
            lines.append(f"  svg_elements({len(matrix.d3js_svg_elements)}): [{','.join(elem_summary)}]")

        return lines

