    def _compress_chartjs_charts(self, matrix) -> List[str]:
        """Compress Chart.js chart instances, types, configs, defaults."""
        lines = []

        # Chart instances by type
        if hasattr(matrix, 'chartjs_instances') and matrix.chartjs_instances:
            by_type = {}
            for inst in matrix.chartjs_instances:
                ct = inst.get('chart_type', 'unknown')
                by_type.setdefault(ct, []).append(inst)
            for ct, instances in sorted(by_type.items()):
                methods = list(dict.fromkeys(i.get('creation_method', '?') for i in instances))
                responsive = sum(1 for i in instances if i.get('is_responsive'))
                flags = []
                if responsive:
                    flags.append(f"responsive:{responsive}")
                flag_str = f" [{','.join(flags)}]" if flags else ""
                lines.append(f"  chart/{ct}({len(instances)}): methods=[{','.join(methods)}]{flag_str}")

        # Chart types summary
        if hasattr(matrix, 'chartjs_chart_types') and matrix.chartjs_chart_types:
            types_used = list(dict.fromkeys(ct['chart_type'] for ct in matrix.chartjs_chart_types))
            mixed_count = sum(1 for ct in matrix.chartjs_chart_types if ct.get('is_mixed'))
            stacked_count = sum(1 for ct in matrix.chartjs_chart_types if ct.get('is_stacked'))
            flags = []
            if mixed_count:
                flags.append(f"mixed:{mixed_count}")
            if stacked_count:
                flags.append(f"stacked:{stacked_count}")
            flag_str = f" [{','.join(flags)}]" if flags else ""
            lines.append(f"  types({len(matrix.chartjs_chart_types)}): [{','.join(types_used)}]{flag_str}")

        # Config objects
        if hasattr(matrix, 'chartjs_configs') and matrix.chartjs_configs:
            lines.append(f"  configs({len(matrix.chartjs_configs)})")

        # Defaults
        if hasattr(matrix, 'chartjs_defaults') and matrix.chartjs_defaults:
            by_type = {}
            for dflt in matrix.chartjs_defaults:
                dt = dflt.get('defaults_type', 'global')
                by_type.setdefault(dt, []).append(dflt)
            for dt, defaults in sorted(by_type.items()):
                v2_count = sum(1 for d in defaults if d.get('is_v2_style'))
                flag_str = f" [v2:{v2_count}]" if v2_count else ""
                lines.append(f"  defaults/{dt}({len(defaults)}){flag_str}")

        return lines

    def _compress_chartjs_datasets(self, matrix) -> List[str]:
        """Compress Chart.js dataset definitions and data points."""
        lines = []

        # Datasets by type
        if hasattr(matrix, 'chartjs_datasets') and matrix.chartjs_datasets:
            by_type = {}
            for ds in matrix.chartjs_datasets:
                dt = ds.get('dataset_type', 'unknown')
                by_type.setdefault(dt, []).append(ds)
            for dt, datasets in sorted(by_type.items()):
                styled = sum(1 for d in datasets if d.get('has_background_color') or d.get('has_border_color'))
                filled = sum(1 for d in datasets if d.get('has_fill'))
                overrides = sum(1 for d in datasets if d.get('has_type_override'))
                flags = []
                if styled:
                    flags.append(f"styled:{styled}")
                if filled:
                    flags.append(f"fill:{filled}")
                if overrides:
                    flags.append(f"type_override:{overrides}")
                flag_str = f" [{','.join(flags)}]" if flags else ""
                lines.append(f"  dataset/{dt}({len(datasets)}){flag_str}")

        # Data points by format
        if hasattr(matrix, 'chartjs_data_points') and matrix.chartjs_data_points:
            by_format = {}
            for dp in matrix.chartjs_data_points:
                fmt = dp.get('data_format', 'unknown')
                by_format.setdefault(fmt, 0)
                by_format[fmt] += 1
            summary = [f"{fmt}:{cnt}" for fmt, cnt in sorted(by_format.items(), key=lambda x: -x[1])]
            lines.append(f"  data_formats({len(matrix.chartjs_data_points)}): [{','.join(summary)}]")

        return lines

