    def _compress_leaflet_maps(self, matrix) -> List[str]:
        """Compress Leaflet/Mapbox map instances and tile layers."""
        lines = []

        # Map instances by type
        if hasattr(matrix, 'leaflet_maps') and matrix.leaflet_maps:
            by_type = {}
            for m in matrix.leaflet_maps:
                mt = m.get('map_type', 'unknown')
                by_type.setdefault(mt, []).append(m)
            for mt, maps in sorted(by_type.items()):
                center = sum(1 for m in maps if m.get('has_center'))
                zoom = sum(1 for m in maps if m.get('has_zoom'))
                bounds = sum(1 for m in maps if m.get('has_bounds'))
                flags = []
                if center:
                    flags.append(f"center:{center}")
                if zoom:
                    flags.append(f"zoom:{zoom}")
                if bounds:
                    flags.append(f"bounds:{bounds}")
                flag_str = f" [{','.join(flags)}]" if flags else ""
                lines.append(f"  map/{mt}({len(maps)}){flag_str}")

        # Tile layers by provider
        if hasattr(matrix, 'leaflet_tile_layers') and matrix.leaflet_tile_layers:
            by_provider = {}
            for tl in matrix.leaflet_tile_layers:
                prov = tl.get('provider', 'unknown')
                by_provider.setdefault(prov, []).append(tl)
            for prov, layers in sorted(by_provider.items()):
                token = sum(1 for l in layers if l.get('has_access_token'))
                flags = []
                if token:
                    flags.append("token")
                flag_str = f" [{','.join(flags)}]" if flags else ""
                lines.append(f"  tiles/{prov}({len(layers)}){flag_str}")

        return lines

    def _compress_leaflet_layers(self, matrix) -> List[str]:
        """Compress Leaflet markers, shapes, GeoJSON, layer groups, Mapbox sources."""
        lines = []

        # Markers by type
        if hasattr(matrix, 'leaflet_markers') and matrix.leaflet_markers:
            by_type = {}
            for mk in matrix.leaflet_markers:
                mt = mk.get('marker_type', 'default')
                by_type.setdefault(mt, []).append(mk)
            for mt, markers in sorted(by_type.items()):
                popup = sum(1 for m in markers if m.get('has_popup'))
                icon = sum(1 for m in markers if m.get('has_icon'))
                clustered = sum(1 for m in markers if m.get('is_clustered'))
                flags = []
                if popup:
                    flags.append(f"popup:{popup}")
                if icon:
                    flags.append(f"icon:{icon}")
                if clustered:
                    flags.append(f"clustered:{clustered}")
                flag_str = f" [{','.join(flags)}]" if flags else ""
                lines.append(f"  marker/{mt}({len(markers)}){flag_str}")

        # Shapes by type
        if hasattr(matrix, 'leaflet_shapes') and matrix.leaflet_shapes:
            by_type = {}
            for sh in matrix.leaflet_shapes:
                st = sh.get('shape_type', 'unknown')
                by_type.setdefault(st, 0)
                by_type[st] += 1
            summary = [f"{st}:{cnt}" for st, cnt in sorted(by_type.items(), key=lambda x: -x[1])]
            lines.append(f"  shapes({len(matrix.leaflet_shapes)}): [{','.join(summary)}]")

        # GeoJSON
        if hasattr(matrix, 'leaflet_geojson') and matrix.leaflet_geojson:
            styled = sum(1 for g in matrix.leaflet_geojson if g.get('has_style'))
            interactive = sum(1 for g in matrix.leaflet_geojson if g.get('has_onEachFeature'))
            flags = []
            if styled:
                flags.append(f"styled:{styled}")
            if interactive:
                flags.append(f"interactive:{interactive}")
            flag_str = f" [{','.join(flags)}]" if flags else ""
            lines.append(f"  geojson({len(matrix.leaflet_geojson)}){flag_str}")

        # Layer groups
        if hasattr(matrix, 'leaflet_layer_groups') and matrix.leaflet_layer_groups:
            by_type = {}
            for lg in matrix.leaflet_layer_groups:
                gt = lg.get('group_type', 'unknown')
                by_type.setdefault(gt, 0)
                by_type[gt] += 1
            summary = [f"{gt}:{cnt}" for gt, cnt in sorted(by_type.items(), key=lambda x: -x[1])]
