    def _compress_gsap_api(self, matrix) -> List[str]:
        """Compress GSAP API: imports, integrations, types, context, matchMedia, version, features."""
        lines = []

        # Imports by type
        if hasattr(matrix, 'gsap_imports') and matrix.gsap_imports:
            by_type = {}
            for imp in matrix.gsap_imports:
                it = imp.get('import_type', 'esm')
                by_type.setdefault(it, 0)
                by_type[it] += 1
            summary = [f"{it}:{c}" for it, c in sorted(by_type.items(), key=lambda x: -x[1])]
            lines.append(f"  imports({len(matrix.gsap_imports)}): [{','.join(summary)}]")

        # Integrations
        if hasattr(matrix, 'gsap_integrations') and matrix.gsap_integrations:
            by_type = {}
            for integ in matrix.gsap_integrations:
                it = integ.get('integration_type', 'other')
                by_type.setdefault(it, []).append(integ)
            for it, integs in sorted(by_type.items()):
                names = list(dict.fromkeys(i.get('name', '?') for i in integs))
                lines.append(f"  integrations/{it}: [{','.join(names)}]")

        # TypeScript types
        if hasattr(matrix, 'gsap_types') and matrix.gsap_types:
            type_names = list(dict.fromkeys(t['name'] for t in matrix.gsap_types))[:20]
            lines.append(f"  types({len(matrix.gsap_types)}): [{','.join(type_names)}]")

        # Contexts (v3.11+)
        if hasattr(matrix, 'gsap_contexts') and matrix.gsap_contexts:
            with_scope = sum(1 for c in matrix.gsap_contexts if c.get('has_scope'))
            with_cleanup = sum(1 for c in matrix.gsap_contexts if c.get('has_cleanup'))
            flags = []
            if with_scope:
                flags.append(f"scope:{with_scope}")
            if with_cleanup:
                flags.append(f"cleanup:{with_cleanup}")
            flag_str = f" [{','.join(flags)}]" if flags else ""
            lines.append(f"  gsap.context({len(matrix.gsap_contexts)}){flag_str}")

        # matchMedia (v3.11+)
        if hasattr(matrix, 'gsap_match_medias') and matrix.gsap_match_medias:
            all_bps = []
            for mm in matrix.gsap_match_medias:
                all_bps.extend(mm.get('breakpoints', []))
            unique_bps = list(dict.fromkeys(all_bps))[:5]
            bp_str = f": [{','.join(unique_bps)}]" if unique_bps else ""
            lines.append(f"  gsap.matchMedia({len(matrix.gsap_match_medias)}){bp_str}")

        # Detected frameworks
        if hasattr(matrix, 'gsap_detected_frameworks') and matrix.gsap_detected_frameworks:
            fws = matrix.gsap_detected_frameworks[:30]
            lines.append(f"  ecosystem:[{','.join(fws)}]")

        # Detected features
        if hasattr(matrix, 'gsap_detected_features') and matrix.gsap_detected_features:
            feats = matrix.gsap_detected_features[:20]
            lines.append(f"  features:[{','.join(feats)}]")

        # Version
        if hasattr(matrix, 'gsap_version') and matrix.gsap_version:
            lines.append(f"  GSAP version: {matrix.gsap_version}")

        # Feature flags
        if hasattr(matrix, 'gsap_has_typescript') and matrix.gsap_has_typescript:
            lines.append("  feature: TypeScript")
        if hasattr(matrix, 'gsap_has_tweens') and matrix.gsap_has_tweens:
            lines.append("  feature: tweens")
        if hasattr(matrix, 'gsap_has_timelines') and matrix.gsap_has_timelines:
            lines.append("  feature: timelines")
        if hasattr(matrix, 'gsap_has_scroll_trigger') and matrix.gsap_has_scroll_trigger:
            lines.append("  feature: ScrollTrigger")
        if hasattr(matrix, 'gsap_has_scroll_smoother') and matrix.gsap_has_scroll_smoother:
            lines.append("  feature: ScrollSmoother")
        if hasattr(matrix, 'gsap_has_plugins') and matrix.gsap_has_plugins:
            lines.append("  feature: plugins")
        if hasattr(matrix, 'gsap_has_staggers') and matrix.gsap_has_staggers:
            lines.append("  feature: staggers")
        if hasattr(matrix, 'gsap_has_context') and matrix.gsap_has_context:
            lines.append("  feature: context")
        if hasattr(matrix, 'gsap_has_match_media') and matrix.gsap_has_match_media:
            lines.append("  feature: matchMedia")
        if hasattr(matrix, 'gsap_has_club_plugins') and matrix.gsap_has_club_plugins:
            lines.append("  feature: Club GreenSock")

        return lines

