    def _compress_rxjs_operators(self, matrix) -> List[str]:
        """Compress RxJS operator constructs: operators by category, custom operators, pipes."""
        lines = []

        # Operators by category
        if hasattr(matrix, 'rxjs_operators') and matrix.rxjs_operators:
            by_cat = {}
            for op in matrix.rxjs_operators:
                cat = op.get('category', 'other')
                by_cat.setdefault(cat, [])
                by_cat[cat].append(op)
            for cat, ops in sorted(by_cat.items(), key=lambda x: -len(x[1])):
                names = list(dict.fromkeys(o.get('name', '?') for o in ops))[:15]
                legacy = sum(1 for o in ops if o.get('is_legacy'))
                flags = []
                if legacy:
                    flags.append(f"legacy:{legacy}")
                flag_str = f" [{','.join(flags)}]" if flags else ""
                lines.append(f"  {cat}({len(ops)}): [{','.join(names)}]{flag_str}")

        # Custom operators
        if hasattr(matrix, 'rxjs_custom_operators') and matrix.rxjs_custom_operators:
            names = list(dict.fromkeys(co.get('name', '?') for co in matrix.rxjs_custom_operators))[:10]
            lines.append(f"  custom({len(matrix.rxjs_custom_operators)}): [{','.join(names)}]")

        # Pipes
        if hasattr(matrix, 'rxjs_pipes') and matrix.rxjs_pipes:
            avg_len = sum(p.get('operator_count', 0) for p in matrix.rxjs_pipes) / max(len(matrix.rxjs_pipes), 1)
            lines.append(f"  pipes({len(matrix.rxjs_pipes)}): avg_operators={avg_len:.1f}")

        return lines

