            with_error = sum(1 for s in matrix.rxjs_subscriptions if s.get('has_error'))
            with_complete = sum(1 for s in matrix.rxjs_subscriptions if s.get('has_complete'))
            unsubscribed = sum(1 for s in matrix.rxjs_subscriptions if s.get('is_unsubscribed'))
