                ver = f"|v{cdn['version']}" if cdn.get('version') else ""
                pkg = f"|{cdn['package_name']}" if cdn.get('package_name') else ""
                js = "|JS" if cdn.get('includes_js') else ""
                css = "|CSS" if cdn.get('includes_css') else ""
                bundle = "|bundle" if cdn.get('is_bundle') else ""
