    def _compress_radix_components(self, matrix) -> List[str]:
        """Compress Radix UI components (primitives + themes)."""
        lines = []

        # Primitives components
        if hasattr(matrix, 'radix_components') and matrix.radix_components:
            by_cat = {}
            for comp in matrix.radix_components:
                cat = comp.get('category', 'other')
                if cat not in by_cat:
                    by_cat[cat] = []
                by_cat[cat].append(comp)

            lines.append(f"# Primitives ({len(matrix.radix_components)})")
            for cat, comps in sorted(by_cat.items()):
                lines.append(f"# {cat} ({len(comps)})")
                for comp in comps[:20]:
                    file_short = comp.get('file', '').split('/')[-1]
                    src = f"|{comp['import_source']}" if comp.get('import_source') else ""
                    aschild = "|asChild" if comp.get('has_as_child') else ""
                    portal = "|portal" if comp.get('is_portal') else ""
                    ctrl = "|controlled" if comp.get('is_controlled') else ""
                    subs = f"|subs:[{','.join(comp.get('sub_components', [])[:5])}]" if comp.get('sub_components') else ""
                    attrs = f"|data:[{','.join(comp.get('data_attributes', [])[:5])}]" if comp.get('data_attributes') else ""
                    lines.append(f"  {comp['name']}{src}{aschild}{portal}{ctrl}{subs}{attrs}|{file_short}")
                if len(comps) > 20:
                    lines.append(f"  # ... and {len(comps) - 20} more {cat}")

        # Themes components
        if hasattr(matrix, 'radix_themes_components') and matrix.radix_themes_components:
            by_cat = {}
            for tc in matrix.radix_themes_components:
                cat = tc.get('category', 'other')
                if cat not in by_cat:
                    by_cat[cat] = []
                by_cat[cat].append(tc)

            lines.append(f"# Themes Components ({len(matrix.radix_themes_components)})")
            for cat, comps in sorted(by_cat.items()):
                lines.append(f"# {cat} ({len(comps)})")
                for tc in comps[:20]:
                    file_short = tc.get('file', '').split('/')[-1]
                    variant = f"|{tc['variant']}" if tc.get('variant') else ""
                    size = f"|sz:{tc['size']}" if tc.get('size') else ""
                    color = f"|clr:{tc['color']}" if tc.get('color') else ""
                    hc = "|highContrast" if tc.get('high_contrast') else ""
                    radius = f"|r:{tc['radius']}" if tc.get('radius') else ""
                    resp = "|responsive" if tc.get('has_responsive') else ""
                    lines.append(f"  {tc['name']}{variant}{size}{color}{hc}{radius}{resp}|{file_short}")

        # Detected frameworks
        if hasattr(matrix, 'radix_detected_frameworks') and matrix.radix_detected_frameworks:
            lines.append(f"# Ecosystem: {', '.join(matrix.radix_detected_frameworks[:30])}")

        # Version
        if hasattr(matrix, 'radix_version') and matrix.radix_version:
            lines.append(f"# Radix version: {matrix.radix_version}")

        return lines

