    def _compress_radix_styles(self, matrix) -> List[str]:
        """Compress Radix UI styling patterns and data attributes."""
        lines = []

        # Style patterns
        if hasattr(matrix, 'radix_style_patterns') and matrix.radix_style_patterns:
            # Group by approach
            by_approach = {}
            for sp in matrix.radix_style_patterns:
                approach = sp.get('approach', 'other')
                if approach not in by_approach:
                    by_approach[approach] = []
                by_approach[approach].append(sp)

            lines.append(f"# Styling Approaches ({len(matrix.radix_style_patterns)})")
            for approach, patterns in sorted(by_approach.items()):
                dark_count = sum(1 for p in patterns if p.get('has_dark_mode'))
                anim_count = sum(1 for p in patterns if p.get('has_animation'))
                resp_count = sum(1 for p in patterns if p.get('has_responsive'))
                extras = ""
                if dark_count:
                    extras += f"|dark:{dark_count}"
                if anim_count:
                    extras += f"|anim:{anim_count}"
                if resp_count:
                    extras += f"|resp:{resp_count}"
                lines.append(f"  {approach}|count:{len(patterns)}{extras}")

        # Data attributes
        if hasattr(matrix, 'radix_data_attributes') and matrix.radix_data_attributes:
            # Group by attribute
            by_attr = {}
            for da in matrix.radix_data_attributes:
                attr = da.get('attribute', 'unknown')
                if attr not in by_attr:
                    by_attr[attr] = []
                by_attr[attr].append(da)

            lines.append(f"# Data Attributes ({len(matrix.radix_data_attributes)})")
            for attr, das in sorted(by_attr.items()):
                all_values = set()
                for da in das:
                    all_values.update(da.get('values', []))
                vals = f"|vals:[{','.join(sorted(all_values)[:8])}]" if all_values else ""
                lines.append(f"  {attr}|uses:{len(das)}{vals}")

        return lines

    def _compress_radix_api(self, matrix) -> List[str]:
        """Compress Radix UI API composition patterns."""
        lines = []

        # Compositions (compound components)
        if hasattr(matrix, 'radix_compositions') and matrix.radix_compositions:
            lines.append(f"# Compositions ({len(matrix.radix_compositions)})")
            for comp in matrix.radix_compositions[:20]:
                file_short = comp.get('file', '').split('/')[-1]
                ptype = f"|{comp['pattern_type']}" if comp.get('pattern_type') else ""
                subs = f"|subs:[{','.join(comp.get('sub_components', [])[:5])}]" if comp.get('sub_components') else ""
                aschild = "|asChild" if comp.get('has_as_child') else ""
                fref = "|forwardRef" if comp.get('has_forward_ref') else ""
                lines.append(f"  {comp['name']}{ptype}{subs}{aschild}{fref}|{file_short}")

        # Controlled patterns
        if hasattr(matrix, 'radix_controlled_patterns') and matrix.radix_controlled_patterns:
            controlled = [cp for cp in matrix.radix_controlled_patterns if cp.get('is_controlled')]
            uncontrolled = [cp for cp in matrix.radix_controlled_patterns if not cp.get('is_controlled')]

            if controlled:
                lines.append(f"# Controlled ({len(controlled)})")
                for cp in controlled[:15]:
                    file_short = cp.get('file', '').split('/')[-1]
                    state = f"|{cp['state_prop']}" if cp.get('state_prop') else ""
                    handler = f"|on:{cp['handler_prop']}" if cp.get('handler_prop') else ""
                    lines.append(f"  {cp['component']}{state}{handler}|{file_short}")

            if uncontrolled:
                lines.append(f"# Uncontrolled ({len(uncontrolled)})")
                for cp in uncontrolled[:15]:
                    file_short = cp.get('file', '').split('/')[-1]
                    default = f"|{cp['default_prop']}" if cp.get('default_prop') else ""
                    lines.append(f"  {cp['component']}{default}|{file_short}")

        # Portal patterns
        if hasattr(matrix, 'radix_portal_patterns') and matrix.radix_portal_patterns:
            lines.append(f"# Portals ({len(matrix.radix_portal_patterns)})")
            for pp in matrix.radix_portal_patterns[:15]:
                file_short = pp.get('file', '').split('/')[-1]
                container = "|container" if pp.get('has_container') else ""
                mount = "|forceMount" if pp.get('has_force_mount') else ""
                anim = f"|anim:{pp['animation_library']}" if pp.get('animation_library') else ""
                lines.append(f"  {pp['component']}{container}{mount}{anim}|{file_short}")

        # Detected features
        if hasattr(matrix, 'radix_detected_features') and matrix.radix_detected_features:
            lines.append(f"# Features: {', '.join(matrix.radix_detected_features[:30])}")

        return lines

    # ============================================
    # v4.42: Styled Components compression methods
    # ============================================

    def _compress_sc_components(self, matrix) -> List[str]:
        """Compress styled-components component definitions."""
        lines = []

        # Styled components
        if hasattr(matrix, 'sc_components') and matrix.sc_components:
            by_method = {}
            for comp in matrix.sc_components:
                method = comp.get('method', 'tagged-template')
                if method not in by_method:
                    by_method[method] = []
                by_method[method].append(comp)

            lines.append(f"# Styled Components ({len(matrix.sc_components)})")
            for method, comps in sorted(by_method.items()):
                if len(by_method) > 1:
                    lines.append(f"# {method} ({len(comps)})")
                for comp in comps[:30]:
                    file_short = comp.get('file', '').split('/')[-1]
                    base = f"|{comp['base_element']}" if comp.get('base_element') else ""
                    base_comp = f"|extends:{comp['base_component']}" if comp.get('base_component') else ""
                    src = f"|{comp['import_source']}" if comp.get('import_source') else ""
                    attrs = "|attrs" if comp.get('has_attrs') else ""
                    cfg = "|withConfig" if comp.get('has_with_config') else ""
                    trans = "|$props" if comp.get('has_transient_props') else ""
                    dyn = "|dynamic" if comp.get('has_dynamic_props') else ""
                    theme = "|theme" if comp.get('has_theme_usage') else ""
                    mq = "|media" if comp.get('has_media_query') else ""
                    syntax = f"|{comp['style_syntax']}" if comp.get('style_syntax') and comp['style_syntax'] != 'tagged-template' else ""
                    css_count = f"|css:{comp['css_properties_count']}" if comp.get('css_properties_count', 0) > 0 else ""
                    lines.append(f"  {comp['name']}{base}{base_comp}{src}{attrs}{cfg}{trans}{dyn}{theme}{mq}{syntax}{css_count}|{file_short}")
                if len(comps) > 30:
                    lines.append(f"  # ... and {len(comps) - 30} more {method}")

        # Extended components
        if hasattr(matrix, 'sc_extended_components') and matrix.sc_extended_components:
            lines.append(f"# Extended Components ({len(matrix.sc_extended_components)})")
            for ext in matrix.sc_extended_components[:20]:
                file_short = ext.get('file', '').split('/')[-1]
                parent = f"|from:{ext['parent_component']}" if ext.get('parent_component') else ""
                overrides = "|overrides" if ext.get('has_overrides') else ""
                dyn = "|dynamic" if ext.get('has_dynamic_props') else ""
                lines.append(f"  {ext['name']}{parent}{overrides}{dyn}|{file_short}")

        # Detected frameworks and version
        if hasattr(matrix, 'sc_detected_frameworks') and matrix.sc_detected_frameworks:
            lines.append(f"# Ecosystem: {', '.join(matrix.sc_detected_frameworks[:30])}")

        if hasattr(matrix, 'sc_version') and matrix.sc_version:
            lines.append(f"# Version: {matrix.sc_version}")

        if hasattr(matrix, 'sc_css_in_js_library') and matrix.sc_css_in_js_library:
            lines.append(f"# Library: {matrix.sc_css_in_js_library}")

        return lines

    def _compress_sc_theme(self, matrix) -> List[str]:
        """Compress styled-components theme system."""
        lines = []

        # Theme providers
        if hasattr(matrix, 'sc_providers') and matrix.sc_providers:
            lines.append(f"# ThemeProviders ({len(matrix.sc_providers)})")
            for prov in matrix.sc_providers[:10]:
                file_short = prov.get('file', '').split('/')[-1]
                var = f"|{prov['theme_variable']}" if prov.get('theme_variable') else ""
                inline = "|inline" if prov.get('has_inline_theme') else ""
                nested = "|nested" if prov.get('is_nested') else ""
                cats = f"|tokens:[{','.join(prov.get('token_categories', [])[:5])}]" if prov.get('token_categories') else ""
                lines.append(f"  {prov['name']}{var}{inline}{nested}{cats}|{file_short}")

        # Global styles
        if hasattr(matrix, 'sc_global_styles') and matrix.sc_global_styles:
            lines.append(f"# Global Styles ({len(matrix.sc_global_styles)})")
            for gs in matrix.sc_global_styles[:10]:
                file_short = gs.get('file', '').split('/')[-1]
                method = f"|{gs['method']}" if gs.get('method') else ""
                theme = "|theme" if gs.get('has_theme_usage') else ""
                reset = "|cssReset" if gs.get('has_css_reset') else ""
                font = "|fontFace" if gs.get('has_font_face') else ""
                cssvar = "|cssVars" if gs.get('has_css_variables') else ""
                lines.append(f"  {gs['name']}{method}{theme}{reset}{font}{cssvar}|{file_short}")

        # Theme usages
        if hasattr(matrix, 'sc_theme_usages') and matrix.sc_theme_usages:
            by_method = {}
            for tu in matrix.sc_theme_usages:
                m = tu.get('method', 'interpolation')
                if m not in by_method:
                    by_method[m] = 0
                by_method[m] += 1

            lines.append(f"# Theme Usage ({len(matrix.sc_theme_usages)})")
            for m, count in sorted(by_method.items(), key=lambda x: -x[1]):
                lines.append(f"  {m}|count:{count}")

        return lines

