    def _compress_emotion_components(self, matrix) -> List[str]:
        """Compress Emotion styled component definitions (@emotion/styled)."""
        lines = []

        # Styled components
        if hasattr(matrix, 'em_components') and matrix.em_components:
            by_method = {}
            for comp in matrix.em_components:
                method = comp.get('method', 'tagged-template')
                if method not in by_method:
                    by_method[method] = []
                by_method[method].append(comp)

            lines.append(f"# Styled Components ({len(matrix.em_components)})")
            for method, comps in sorted(by_method.items()):
                if len(by_method) > 1:
                    lines.append(f"# {method} ({len(comps)})")
                for comp in comps[:30]:
                    file_short = comp.get('file', '').split('/')[-1]
                    base = f"|{comp['base_element']}" if comp.get('base_element') else ""
                    base_comp = f"|extends:{comp['base_component']}" if comp.get('base_component') else ""
                    src = f"|{comp['import_source']}" if comp.get('import_source') else ""
                    fwd = "|shouldForwardProp" if comp.get('has_should_forward_prop') else ""
                    dyn = "|dynamic" if comp.get('has_dynamic_props') else ""
                    theme = "|theme" if comp.get('has_theme_usage') else ""
                    mq = "|media" if comp.get('has_media_query') else ""
                    nest = "|nesting" if comp.get('has_nesting') else ""
                    label = "|label" if comp.get('has_label') else ""
                    syntax = f"|{comp['style_syntax']}" if comp.get('style_syntax') and comp['style_syntax'] != 'tagged-template' else ""
                    css_count = f"|css:{comp['css_properties_count']}" if comp.get('css_properties_count', 0) > 0 else ""
                    lines.append(f"  {comp['name']}{base}{base_comp}{src}{fwd}{dyn}{theme}{mq}{nest}{label}{syntax}{css_count}|{file_short}")
                if len(comps) > 30:
                    lines.append(f"  # ... and {len(comps) - 30} more {method}")

        # Extended components
        if hasattr(matrix, 'em_extended_components') and matrix.em_extended_components:
            lines.append(f"# Extended Components ({len(matrix.em_extended_components)})")
            for ext in matrix.em_extended_components[:20]:
                file_short = ext.get('file', '').split('/')[-1]
                parent = f"|from:{ext['parent_component']}" if ext.get('parent_component') else ""
                overrides = "|overrides" if ext.get('has_overrides') else ""
                dyn = "|dynamic" if ext.get('has_dynamic_props') else ""
                lines.append(f"  {ext['name']}{parent}{overrides}{dyn}|{file_short}")

        # Detected frameworks, packages, and version
        if hasattr(matrix, 'em_detected_frameworks') and matrix.em_detected_frameworks:
            lines.append(f"# Ecosystem: {', '.join(matrix.em_detected_frameworks[:30])}")

        if hasattr(matrix, 'em_version') and matrix.em_version:
            lines.append(f"# Version: {matrix.em_version}")

        if hasattr(matrix, 'em_packages') and matrix.em_packages:
            lines.append(f"# Packages: {', '.join(matrix.em_packages[:20])}")

        return lines

