    def _compress_svelte_runes(self, matrix) -> List[str]:
        """Compress Svelte 5 runes and lifecycle data."""
        lines = []

        # Runes
        if hasattr(matrix, 'svelte_runes') and matrix.svelte_runes:
            # Group by rune type
            by_type = {}
            for rune in matrix.svelte_runes:
                rt = rune.get('name', 'unknown')
                if rt not in by_type:
                    by_type[rt] = []
                by_type[rt].append(rune)

            for rune_type, runes in by_type.items():
                lines.append(f"# ${rune_type} ({len(runes)})")
                for r in runes[:15]:
                    file_short = r.get('file', '').split('/')[-1]
                    name = r.get('name', '')
                    lines.append(f"  {name}|{file_short}|L{r.get('line', 0)}")
                if len(runes) > 15:
                    lines.append(f"  # ... and {len(runes) - 15} more")

        # Lifecycle hooks
        if hasattr(matrix, 'svelte_lifecycle_hooks') and matrix.svelte_lifecycle_hooks:
            lines.append(f"# Lifecycle Hooks ({len(matrix.svelte_lifecycle_hooks)})")
            for hook in matrix.svelte_lifecycle_hooks[:20]:
                file_short = hook.get('file', '').split('/')[-1]
                hook_name = hook.get('name', '')
                flags = []
                if hook.get('has_cleanup'):
                    flags.append("cleanup")
                if hook.get('is_async'):
                    flags.append("async")
                flag_str = f" [{','.join(flags)}]" if flags else ""
                lines.append(f"  {hook_name}|{file_short}|L{hook.get('line', 0)}{flag_str}")
            if len(matrix.svelte_lifecycle_hooks) > 20:
                lines.append(f"  # ... and {len(matrix.svelte_lifecycle_hooks) - 20} more lifecycle hooks")

        # Contexts
        if hasattr(matrix, 'svelte_contexts') and matrix.svelte_contexts:
            lines.append(f"# Contexts ({len(matrix.svelte_contexts)})")
            for ctx in matrix.svelte_contexts[:15]:
                file_short = ctx.get('file', '').split('/')[-1]
                ctx_type = ctx.get('kind', 'set')
                lines.append(f"  {ctx.get('key', '')}|{ctx_type}|{file_short}|L{ctx.get('line', 0)}")
            if len(matrix.svelte_contexts) > 15:
                lines.append(f"  # ... and {len(matrix.svelte_contexts) - 15} more contexts")

        return lines

