    def _compress_semantic_routes(self, matrix) -> List[str]:
        """Compress semantically detected routes."""
        lines = []
        if not hasattr(matrix, 'semantic_routes') or not matrix.semantic_routes:
            return lines

        # Deduplicate against go_routes if they exist
        existing = set()
        if hasattr(matrix, 'go_routes'):
            for r in matrix.go_routes:
                existing.add(f"{r.get('method', '')}:{r.get('path', '')}")

        # Group by file
        by_file = {}
        for route in matrix.semantic_routes:
            key = f"{route.get('method', '')}:{route.get('path', '')}"
            if key in existing:
                continue  # Skip duplicates
            file_short = route.get('file', '').split('/')[-1]
            if file_short not in by_file:
                by_file[file_short] = []
            by_file[file_short].append(route)

        for filename, routes in list(by_file.items())[:15]:
            lines.append(f"  # {filename}")
            for r in routes[:10]:
                lines.append(f"    {r['method']} {r['path']} -> {r.get('handler', '?')}")
            if len(routes) > 10:
                lines.append(f"    # ... and {len(routes) - 10} more")

        return lines

    def _compress_semantic_lifecycle(self, matrix) -> List[str]:
        """Compress lifecycle method data."""
        lines = []
        if not hasattr(matrix, 'semantic_lifecycle') or not matrix.semantic_lifecycle:
            return lines

        # Group by phase
        by_phase = {}
        for lc in matrix.semantic_lifecycle:
            phase = lc.get('phase', 'init')
            if phase not in by_phase:
                by_phase[phase] = []
            by_phase[phase].append(lc)

        phase_order = ['init', 'start', 'run', 'stop', 'cleanup']
        for phase in phase_order:
            if phase not in by_phase:
                continue
            items = by_phase[phase]
            lines.append(f"  # {phase} ({len(items)})")
            for item in items[:10]:
                owner = f"{item['owner']}." if item.get('owner') else ""
                file_short = item.get('file', '').split('/')[-1]
                lines.append(f"    {owner}{item['name']}|{file_short}")
            if len(items) > 10:
                lines.append(f"    # ... and {len(items) - 10} more")

        return lines

