    def _compress_hapi(self, matrix) -> List[str]:
        """
        v4.86: Compress Hapi routes, plugins, auth strategies/schemes, server
        config, caching, server methods, extension points.
        """
        lines = []

        routes = getattr(matrix, 'hapi_routes', [])
        plugins = getattr(matrix, 'hapi_plugins', [])
        auth_strategies = getattr(matrix, 'hapi_auth_strategies', [])
        auth_schemes = getattr(matrix, 'hapi_auth_schemes', [])
        server_configs = getattr(matrix, 'hapi_server_configs', [])
        caches = getattr(matrix, 'hapi_caches', [])
        server_methods = getattr(matrix, 'hapi_server_methods', [])
        ext_points = getattr(matrix, 'hapi_ext_points', [])
        imports = getattr(matrix, 'hapi_imports', [])

        if not routes and not plugins and not auth_strategies:
            return lines

        # Summary
        frameworks = getattr(matrix, 'hapi_detected_frameworks', [])
        if frameworks:
            lines.append(f"# Ecosystem: {', '.join(frameworks[:20])}")
        version = getattr(matrix, 'hapi_version', '')
        if version:
            lines.append(f"# Min Hapi version: {version}")
        if getattr(matrix, 'hapi_is_typescript', False):
            lines.append("# TypeScript: yes")
        if getattr(matrix, 'hapi_is_legacy', False):
            lines.append("# Legacy (pre-v17): yes")
        default_auth = getattr(matrix, 'hapi_default_auth', '')
        if default_auth:
            lines.append(f"# Default auth: {default_auth}")

        # Routes
        if routes:
            lines.append(f"## Routes ({len(routes)})")
            for r in routes[:40]:
                file_short = r.get('file', '').split('/')[-1]
                handler = f"|handler:{r['handler']}" if r.get('handler') else ""
                async_flag = "|async" if r.get('is_async') else ""
                params = f"|params:{','.join(r.get('path_params', [])[:3])}" if r.get('path_params') else ""
                auth = f"|auth:{r['auth']}" if r.get('auth') else ""
                tags = f"|tags:{','.join(r.get('tags', [])[:3])}" if r.get('tags') else ""
                lines.append(f"  {r['method']} {r['path']}{handler}{async_flag}{params}{auth}{tags}|{file_short}")
            if len(routes) > 40:
                lines.append(f"  # ... and {len(routes) - 40} more routes")

        # Plugins
        if plugins:
            lines.append(f"## Plugins ({len(plugins)})")
            for p in plugins[:20]:
                file_short = p.get('file', '').split('/')[-1]
                pkg = f"|pkg:{p['package_name']}" if p.get('package_name') else ""
                builtin = "|builtin" if p.get('is_builtin') else ""
                custom = "|custom" if p.get('is_custom') else ""
                prefix = f"|prefix:{p['routes_prefix']}" if p.get('routes_prefix') else ""
                lines.append(f"  {p['name']}{pkg}{builtin}{custom}{prefix}|{file_short}")

        # Auth Strategies
        if auth_strategies:
            lines.append(f"## Auth Strategies ({len(auth_strategies)})")
            for s in auth_strategies[:10]:
                file_short = s.get('file', '').split('/')[-1]
                scheme = f"|scheme:{s['scheme']}" if s.get('scheme') else ""
                pkg = f"|pkg:{s['package']}" if s.get('package') else ""
                mode = f"|mode:{s['mode']}" if s.get('mode') else ""
                default = "|default" if s.get('is_default') else ""
                lines.append(f"  {s['name']}{scheme}{pkg}{mode}{default}|{file_short}")

        # Auth Schemes
        if auth_schemes:
            lines.append(f"## Auth Schemes ({len(auth_schemes)})")
            for sc in auth_schemes[:10]:
                file_short = sc.get('file', '').split('/')[-1]
                auth_fn = "|authenticate" if sc.get('has_authenticate') else ""
                payload = "|payload" if sc.get('has_payload') else ""
                lines.append(f"  {sc['name']}{auth_fn}{payload}|{file_short}")

        # Server Config
        if server_configs:
            for sc in server_configs[:3]:
                file_short = sc.get('file', '').split('/')[-1]
                port = f"|port:{sc['port']}" if sc.get('port') else ""
                host = f"|host:{sc['host']}" if sc.get('host') else ""
                tls = "|tls" if sc.get('has_tls') else ""
                cors = "|cors" if sc.get('cors_enabled') else ""
                decos = f"|decorations:{len(sc.get('decorations', []))}" if sc.get('decorations') else ""
                lines.append(f"  server{port}{host}{tls}{cors}{decos}|{file_short}")

        # Caches
        if caches:
            cache_providers = [c.get('provider', 'default') for c in caches]
            lines.append(f"## Caches: {', '.join(sorted(set(cache_providers)))}")

        # Server Methods
        if server_methods:
            lines.append(f"## Server Methods ({len(server_methods)})")
            for m in server_methods[:15]:
                file_short = m.get('file', '').split('/')[-1]
                cached = "|cached" if m.get('has_cache') else ""
                lines.append(f"  {m['name']}{cached}|{file_short}")

        # Extension Points
        if ext_points:
            ext_events = [e.get('event', '') for e in ext_points]
            event_counts = {}
            for ev in ext_events:
                event_counts[ev] = event_counts.get(ev, 0) + 1
            ext_summary = ', '.join(f"{e}:{c}" for e, c in sorted(event_counts.items()))
            lines.append(f"## Ext Points: {ext_summary}")

        return lines

