    def _compress_masstransit(self, matrix) -> List[str]:
        """Compress MassTransit consumers, sagas, messages, bus config."""
        lines = []

        consumers = getattr(matrix, 'masstransit_consumers', [])
        sagas = getattr(matrix, 'masstransit_sagas', [])
        messages = getattr(matrix, 'masstransit_messages', [])
        bus_configs = getattr(matrix, 'masstransit_bus_configs', [])
        middleware = getattr(matrix, 'masstransit_middleware', [])

        if not consumers and not sagas and not messages:
            return lines

        frameworks = getattr(matrix, 'masstransit_detected_frameworks', [])
        if frameworks:
            lines.append(f"# Ecosystem: {', '.join(frameworks[:15])}")
        version = getattr(matrix, 'masstransit_version', '')
        if version:
            lines.append(f"# MassTransit version: {version}")

        if consumers:
            lines.append(f"## Consumers ({len(consumers)})")
            for c in consumers[:30]:
                name = c.get('name', '?')
                msg = c.get('message_type', '')
                ctype = c.get('consumer_type', '')
                lines.append(f"  [{ctype}] {name}|msg:{msg}")
            if len(consumers) > 30:
                lines.append(f"  # ... and {len(consumers) - 30} more")

